import React, { useEffect, useRef, useState, useCallback } from 'react';
import { COLORS } from '../constants';
import { GameConfig, CarModel, MapConfig, GameMode, LevelConfig } from '../types';
import { createEngine, createCar, generateTerrainChunk, generateClouds, createWall, TerrainChunk, Cloud, Decoration } from '../utils/physics';
import { SoundManager } from '../utils/audio';
import DebugMenu from './DebugMenu';

const Matter = (window as any).Matter;

interface GameProps {
  mode: GameMode;
  levelConfig?: LevelConfig;
  onGameOver: (distance: number, coins: number) => void;
  onLevelComplete: (coins: number) => void;
  selectedCar: CarModel;
  selectedMap: MapConfig;
  config: GameConfig;
  onUpdateConfig: (key: keyof GameConfig, value: any) => void;
  onResetConfig: () => void;
  onExit: () => void;
  isMenuBackground?: boolean;
  onReady?: () => void;
}

interface Particle {
    x: number; y: number; vx: number; vy: number;
    life: number; maxLife: number; active: boolean;
    type: 'dust' | 'spark' | 'explosion' | 'smoke';
}

const Game: React.FC<GameProps> = ({ mode, levelConfig, onGameOver, onLevelComplete, selectedCar, selectedMap, config, onUpdateConfig, onResetConfig, onExit, isMenuBackground = false, onReady }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const requestRef = useRef<number | null>(null);
  const engineRef = useRef<any>(null);
  const carRef = useRef<any>(null);
  const soundManagerRef = useRef<SoundManager | null>(null);

  // Game Logic Refs
  const chunksRef = useRef<TerrainChunk[]>([]);
  const cloudsRef = useRef<Cloud[]>([]);
  const collectedCoinIdsRef = useRef<Set<number>>(new Set());
  const collectedFuelIdsRef = useRef<Set<number>>(new Set());
  const particlesRef = useRef<Particle[]>([]);
  const lastChunkDataRef = useRef({ endX: 0, endY: 200, globalIndex: 0, segmentsSinceFuel: 0 });

  const fuelRef = useRef(config.MAX_FUEL);
  const wheelGroundContacts = useRef(0);
  const isOutOfFuelRef = useRef(false);
  const gameStateRef = useRef({ distance: 0, coins: 0, isGameOver: false, keys: { left: false, right: false } });

  // Visual state
  const cameraZoomRef = useRef(1.0);
  const cameraPosRef = useRef({ x: 0, y: 0 });
  const [isPaused, setIsPaused] = useState(false);
  const pausedRef = useRef(false);
  const [notification, setNotification] = useState<{text: string, subText?: string, id: number} | null>(null);
  const patternsRef = useRef<{[key: string]: CanvasPattern | null}>({});
  const starsRef = useRef<{x: number, y: number, r: number, opacity: number}[]>([]);

  // FPS Logic
  const lastFpsTimeRef = useRef(0);
  const frameCountRef = useRef(0);
  const hudFpsRef = useRef<HTMLDivElement>(null);

  // HUD Refs
  const hudDistanceRef = useRef<HTMLDivElement>(null);
  const hudCoinsRef = useRef<HTMLDivElement>(null);
  const hudFuelBarRef = useRef<HTMLDivElement>(null);

  // Setup Stars for Moon
  useEffect(() => {
    if (selectedMap.backgroundType === 'moon') {
        const s = [];
        for(let i=0; i<150; i++) {
            s.push({ x: Math.random() * 2000, y: Math.random() * 1000 - 500, r: Math.random() * 2, opacity: Math.random() });
        }
        starsRef.current = s;
    } else {
        starsRef.current = [];
    }
  }, [selectedMap]);

  const addChunk = useCallback((startX: number) => {
    const { endY, globalIndex, segmentsSinceFuel } = lastChunkDataRef.current;
    const length = config.CHUNK_SIZE;
    const chunkId = Math.floor(startX / length);

    const newChunk = generateTerrainChunk(
        chunkId, startX, endY, globalIndex, length, false, config, selectedMap.backgroundType, segmentsSinceFuel,
        mode === 'LEVELS' && levelConfig ? levelConfig.distance : null
    );

    if (engineRef.current) Matter.World.add(engineRef.current.world, newChunk.composite);

    if (selectedMap.backgroundType === 'earth' || selectedMap.backgroundType === 'highway') {
        const newClouds = generateClouds(startX, length);
        cloudsRef.current = [...cloudsRef.current, ...newClouds];
    }

    lastChunkDataRef.current = {
        endX: startX + length,
        endY: newChunk.endY,
        globalIndex: newChunk.endGlobalIndex,
        segmentsSinceFuel: newChunk.nextSegmentsSinceFuel
    };

    chunksRef.current.push(newChunk);

    // Cleanup old chunks and clouds to prevent memory leak
    if (chunksRef.current.length > 5) {
        const oldChunk = chunksRef.current.shift();
        if (oldChunk && engineRef.current) {
             Matter.Composite.remove(engineRef.current.world, oldChunk.composite);
        }
    }
    if (cloudsRef.current.length > 50) {
        cloudsRef.current = cloudsRef.current.slice(cloudsRef.current.length - 40);
    }
  }, [config, selectedMap.backgroundType, mode, levelConfig]);

  const handleResize = useCallback(() => {
    if (canvasRef.current && containerRef.current) {
        const rw = containerRef.current.clientWidth * config.RESOLUTION;
        const rh = containerRef.current.clientHeight * config.RESOLUTION;
        canvasRef.current.width = rw;
        canvasRef.current.height = rh;
        patternsRef.current = {}; 
    }
  }, [config.RESOLUTION]);

  useEffect(() => {
    window.addEventListener('resize', handleResize);
    handleResize();
    return () => window.removeEventListener('resize', handleResize);
  }, [handleResize]);

  // Initialization Sequence
  useEffect(() => {
    if (!isMenuBackground) soundManagerRef.current = new SoundManager();
    const engine = createEngine(config);
    engineRef.current = engine;
    const car = createCar(200, -100, selectedCar, config); 
    carRef.current = car;
    Matter.World.add(engine.world, [car, createWall(-1000)]);

    // Reset loop state
    lastChunkDataRef.current = { endX: 0, endY: 200, globalIndex: 0, segmentsSinceFuel: 0 };
    chunksRef.current = [];
    cloudsRef.current = [];
    collectedCoinIdsRef.current = new Set();
    collectedFuelIdsRef.current = new Set();
    fuelRef.current = config.MAX_FUEL;
    isOutOfFuelRef.current = false;
    gameStateRef.current.isGameOver = false;
    gameStateRef.current.distance = 0;
    gameStateRef.current.coins = 0;
    pausedRef.current = false;
    setIsPaused(false);

    let currentGenX = 0;
    const buffer = isMenuBackground ? 4000 : config.INITIAL_BUFFER_DISTANCE;
    while (currentGenX < buffer) {
        addChunk(currentGenX);
        currentGenX += config.CHUNK_SIZE;
    }

    particlesRef.current = Array.from({ length: config.PARTICLE_POOL_SIZE }).map(() => ({
        x: 0, y: 0, vx: 0, vy: 0, life: 0, maxLife: 0, active: false, type: 'dust'
    }));

    Matter.Events.on(engine, 'collisionStart', (event: any) => {
        event.pairs.forEach((pair: any) => {
            const { bodyA, bodyB } = pair;
            const isWheel = (b: any) => b.label === 'wheelBack' || b.label === 'wheelFront';
            const isGround = (b: any) => b.label === 'ground' || b.label === 'obstacle';

            if ((isWheel(bodyA) && isGround(bodyB)) || (isWheel(bodyB) && isGround(bodyA))) {
                wheelGroundContacts.current++;
                const w = isWheel(bodyA) ? bodyA : bodyB;
                const speed = Matter.Vector.magnitude(w.velocity);
                if (speed > 5) spawnParticles(w.position.x, w.position.y + 15, 2, speed > 10 ? 'spark' : 'dust');
            }

            if ((bodyA.label === 'chassis' && bodyB.label === 'ground') || (bodyB.label === 'chassis' && bodyA.label === 'ground')) {
                if (isMenuBackground) return;
                const chassis = bodyA.label === 'chassis' ? bodyA : bodyB;
                if (Math.abs(chassis.angle) > Math.PI / 1.5) {
                    gameStateRef.current.isGameOver = true;
                    soundManagerRef.current?.stopContinuous();
                    onGameOver(gameStateRef.current.distance, gameStateRef.current.coins);
                }
            }

            let item = null;
            if (['chassis', 'wheelBack', 'wheelFront'].includes(bodyA.label) && ['coin', 'fuel', 'finishLine'].includes(bodyB.label)) item = bodyB;
            if (['chassis', 'wheelBack', 'wheelFront'].includes(bodyB.label) && ['coin', 'fuel', 'finishLine'].includes(bodyA.label)) item = bodyA;

            if (item && !isMenuBackground) {
                if (item.label === 'finishLine') {
                    gameStateRef.current.isGameOver = true;
                    onLevelComplete(gameStateRef.current.coins);
                } else if (!collectedCoinIdsRef.current.has(item.id) && !collectedFuelIdsRef.current.has(item.id)) {
                    if (item.label === 'coin') {
                        collectedCoinIdsRef.current.add(item.id);
                        gameStateRef.current.coins += config.COIN_VALUE;
                        soundManagerRef.current?.playCoinSound();
                        Matter.World.remove(engine.world, item);
                    } else if (item.label === 'fuel') {
                        collectedFuelIdsRef.current.add(item.id);
                        fuelRef.current = Math.min(config.MAX_FUEL, fuelRef.current + config.FUEL_CAN_VALUE);
                        isOutOfFuelRef.current = false;
                        setNotification({ text: "FUEL!", id: Date.now() });
                        setTimeout(() => setNotification(null), 1500);
                        Matter.World.remove(engine.world, item);
                    }
                }
            }
        });
    });

    Matter.Events.on(engine, 'collisionEnd', (event: any) => {
        event.pairs.forEach((pair: any) => {
            const isWheel = (b: any) => b.label === 'wheelBack' || b.label === 'wheelFront';
            const isGround = (b: any) => b.label === 'ground' || b.label === 'obstacle';
            if ((isWheel(pair.bodyA) && isGround(pair.bodyB)) || (isWheel(pair.bodyB) && isGround(pair.bodyA))) {
                wheelGroundContacts.current = Math.max(0, wheelGroundContacts.current - 1);
            }
        });
    });

    // Notify parent that we are ready to start playing
    if (onReady) onReady();

    requestRef.current = requestAnimationFrame(animate);
    return () => {
        if (requestRef.current) cancelAnimationFrame(requestRef.current);
        Matter.Engine.clear(engine);
        if (soundManagerRef.current) soundManagerRef.current.stopContinuous();
    };
  }, [addChunk, selectedCar, onGameOver, onLevelComplete, config, isMenuBackground, onReady]);

  const spawnParticles = (x: number, y: number, count: number, type: 'dust' | 'spark' | 'explosion' | 'smoke') => {
      let spawned = 0;
      for (let p of particlesRef.current) {
          if (spawned >= count) break;
          if (!p.active) {
              p.active = true; p.x = x; p.y = y; p.type = type;
              p.maxLife = config.PARTICLE_LIFETIME; p.life = p.maxLife;
              if (type === 'smoke') {
                  p.vx = (Math.random() - 0.5) * 2 - 2; // Smoke blows back
                  p.vy = (Math.random() - 0.5) * 2;
                  p.maxLife = 60;
                  p.life = 60;
              } else {
                  p.vx = (Math.random() - 0.5) * 5; 
                  p.vy = (Math.random() - 0.5) * 5;
              }
              spawned++;
          }
      }
  };

  const getPattern = (ctx: CanvasRenderingContext2D, type: string, color1: string, color2: string) => {
      const key = `${type}-${color1}-${color2}`;
      if (patternsRef.current[key]) return patternsRef.current[key];
      const pCanvas = document.createElement('canvas');
      const pCtx = pCanvas.getContext('2d')!;
      pCanvas.width = 40; pCanvas.height = 40;
      if (type === 'ground') {
          // Noise texture
          pCtx.fillStyle = color1; pCtx.fillRect(0,0,40,40);
          pCtx.fillStyle = color2; 
          for(let i=0; i<30; i++) {
              pCtx.globalAlpha = 0.1 + Math.random() * 0.2;
              pCtx.beginPath(); 
              pCtx.arc(Math.random()*40, Math.random()*40, 1 + Math.random()*2, 0, Math.PI*2);
              pCtx.fill();
          }
      } else if (type === 'striped') {
          pCanvas.width = 20; pCtx.fillStyle = color1; pCtx.fillRect(0,0,20,40);
          pCtx.fillStyle = color2; pCtx.fillRect(0,0,10,40);
      } else if (type === 'checker') {
          pCanvas.width = 20; pCanvas.height = 20;
          pCtx.fillStyle = color1; pCtx.fillRect(0,0,20,20);
          pCtx.fillStyle = color2; pCtx.fillRect(0,0,10,10); pCtx.fillRect(10,10,10,10);
      } else if (type === 'dots') {
          pCanvas.width = 10; pCanvas.height = 10;
          pCtx.fillStyle = color1; pCtx.fillRect(0,0,10,10);
          pCtx.fillStyle = color2; pCtx.beginPath(); pCtx.arc(5,5,2,0,Math.PI*2); pCtx.fill();
      } else if (type === 'gradient') {
          const g = pCtx.createLinearGradient(0,0,0,40);
          g.addColorStop(0, color2);
          g.addColorStop(1, color1);
          pCtx.fillStyle = g;
          pCtx.fillRect(0,0,40,40);
      }
      const pattern = ctx.createPattern(pCanvas, 'repeat');
      patternsRef.current[key] = pattern;
      return pattern;
  };

  const drawChassisPath = (ctx: CanvasRenderingContext2D, car: CarModel, cw: number, ch: number) => {
      ctx.beginPath();
      const halfW = cw / 2;
      const halfH = ch / 2;

      // Better shapes with more complex curves
      if (car.shape === 'coupe' || !car.shape) {
          ctx.moveTo(-halfW, halfH * 0.5); 
          ctx.lineTo(-halfW, -halfH * 0.2);
          ctx.quadraticCurveTo(-halfW, -halfH * 0.9, -halfW * 0.4, -halfH * 0.9); // Roof rear
          ctx.lineTo(halfW * 0.1, -halfH * 0.9); // Roof top
          ctx.quadraticCurveTo(halfW * 0.8, -halfH * 0.7, halfW * 1.1, 0); // Windshield slope
          ctx.lineTo(halfW * 1.2, halfH * 0.5); // Nose
          ctx.lineTo(-halfW, halfH * 0.5); // Bottom
      } else if (car.shape === 'jeep') {
          ctx.moveTo(-halfW * 0.9, halfH * 0.5);
          ctx.lineTo(-halfW * 0.9, -halfH * 0.5); // Rear bumper
          ctx.lineTo(-halfW * 0.5, -halfH * 0.5); // Bed
          ctx.lineTo(-halfW * 0.5, -halfH * 1.6); // Cab rear
          ctx.lineTo(halfW * 0.6, -halfH * 1.6); // Cab roof
          ctx.lineTo(halfW * 0.6, -halfH * 0.2); // Windshield vertical
          ctx.lineTo(halfW * 1.1, -halfH * 0.2); // Hood
          ctx.lineTo(halfW * 1.1, halfH * 0.5);
          ctx.lineTo(-halfW * 0.9, halfH * 0.5);
      } else if (car.shape === 'racer') {
          ctx.moveTo(-halfW * 1.2, halfH * 0.2);
          ctx.lineTo(-halfW * 1.2, -halfH * 0.3); // Rear Wing support
          ctx.lineTo(-halfW * 0.5, -halfH * 0.5); // Engine cover
          ctx.lineTo(halfW * 0.3, -halfH * 0.5); 
          ctx.quadraticCurveTo(halfW * 1.0, -halfH * 0.3, halfW * 1.5, 0); // Nose slope
          ctx.lineTo(halfW * 1.5, halfH * 0.3); 
          ctx.lineTo(-halfW * 1.2, halfH * 0.2);
      } else if (car.shape === 'buggy') {
          ctx.moveTo(-halfW * 0.7, 0);
          ctx.lineTo(-halfW * 0.5, -halfH * 1.4); // Roll bar back
          ctx.lineTo(halfW * 0.4, -halfH * 1.4); // Roll bar top
          ctx.lineTo(halfW * 0.9, 0); // Roll bar front
          ctx.lineTo(halfW * 1.1, 0); // Hood
          ctx.lineTo(halfW * 0.9, halfH * 0.5);
          ctx.lineTo(-halfW * 0.9, halfH * 0.5);
          ctx.lineTo(-halfW * 0.7, 0);
      } else if (car.shape === 'van') {
          ctx.moveTo(-halfW * 0.9, halfH * 0.5);
          ctx.lineTo(-halfW * 0.9, -halfH * 1.3);
          ctx.lineTo(halfW * 0.7, -halfH * 1.3); // Roof
          ctx.quadraticCurveTo(halfW * 1.1, -halfH * 1.2, halfW * 1.1, -halfH * 0.2); // Front curve
          ctx.lineTo(halfW * 1.1, halfH * 0.5);
          ctx.lineTo(-halfW * 0.9, halfH * 0.5);
      } else if (car.shape === 'supercar') {
          ctx.moveTo(-halfW * 1.1, halfH * 0.5);
          ctx.lineTo(-halfW * 1.1, 0);
          ctx.lineTo(-halfW * 0.5, -halfH * 0.6); // Rear deck
          ctx.lineTo(halfW * 0.1, -halfH * 0.6); // Roof start
          ctx.quadraticCurveTo(halfW * 1.0, -halfH * 0.4, halfW * 1.4, 0); // Sleek nose
          ctx.lineTo(halfW * 1.45, halfH * 0.5);
          ctx.lineTo(-halfW * 1.1, halfH * 0.5);
      } else if (car.shape === 'bike') {
           ctx.moveTo(-halfW * 0.5, 0);
           ctx.lineTo(0, -halfH * 0.7); // Seat position
           ctx.lineTo(halfW * 0.4, -halfH * 0.4); // Tank
           ctx.lineTo(halfW * 0.3, 0);
           ctx.lineTo(-halfW * 0.5, 0);
      }
      ctx.closePath();
  };

  const drawCarDetails = (ctx: CanvasRenderingContext2D, car: CarModel, cw: number, ch: number) => {
      const halfW = cw / 2;
      const halfH = ch / 2;

      // 1. Headlights (with glow)
      ctx.save();
      ctx.translate(halfW, 0);

      const grad = ctx.createLinearGradient(0, 0, 150, 0);
      grad.addColorStop(0, 'rgba(255, 255, 200, 0.4)');
      grad.addColorStop(1, 'rgba(255, 255, 200, 0)');
      ctx.fillStyle = grad;
      ctx.beginPath(); ctx.moveTo(0, -5); ctx.lineTo(150, -40); ctx.lineTo(150, 40); ctx.lineTo(0, 5); ctx.fill();

      ctx.fillStyle = '#fef08a';
      ctx.shadowColor = '#fef08a'; ctx.shadowBlur = 10;
      if (car.shape === 'jeep' || car.shape === 'van') {
           ctx.fillRect(halfW * 0.05, -15, 5, 20);
      } else if (car.shape === 'bike') {
           ctx.beginPath(); ctx.arc(halfW * 0.3, -10, 8, 0, Math.PI*2); ctx.fill();
      } else {
           ctx.beginPath(); ctx.ellipse(halfW * 0.15, 0, 4, 12, 0, 0, Math.PI*2); ctx.fill();
      }
      ctx.restore();

      // 2. Windows - Gradient glass
      const glassGrad = ctx.createLinearGradient(0, -ch, 0, 0);
      glassGrad.addColorStop(0, '#38bdf8');
      glassGrad.addColorStop(1, '#1e293b');
      ctx.fillStyle = glassGrad;
      ctx.strokeStyle = '#334155'; ctx.lineWidth = 1;

      if (car.shape === 'coupe') {
          ctx.beginPath();
          ctx.moveTo(-halfW * 0.3, -halfH * 0.75);
          ctx.lineTo(halfW * 0.1, -halfH * 0.75);
          ctx.lineTo(halfW * 0.5, -halfH * 0.1);
          ctx.lineTo(-halfW * 0.3, -halfH * 0.1);
          ctx.fill(); ctx.stroke();
      } else if (car.shape === 'supercar') {
          ctx.beginPath();
          ctx.moveTo(-halfW * 0.2, -halfH * 0.5);
          ctx.lineTo(halfW * 0.2, -halfH * 0.5);
          ctx.lineTo(halfW * 0.6, -halfH * 0.1);
          ctx.lineTo(-halfW * 0.4, -halfH * 0.1);
          ctx.fill(); ctx.stroke();
      } else if (car.shape === 'jeep') {
          ctx.fillRect(-halfW * 0.4, -halfH * 1.3, cw * 0.35, ch * 0.5); // Side
          ctx.fillRect(halfW * 0.1, -halfH * 1.3, cw * 0.35, ch * 0.5); // Front
      } else if (car.shape === 'van') {
          ctx.fillRect(-halfW * 0.8, -halfH * 1.1, cw * 0.35, ch * 0.5);
          ctx.fillRect(-halfW * 0.3, -halfH * 1.1, cw * 0.45, ch * 0.5);
      }

      // 3. Extra Details
      ctx.fillStyle = '#111';
      if (car.shape === 'racer' || car.shape === 'supercar') {
          // Spoiler
          ctx.fillStyle = car.bodyColor;
          ctx.beginPath();
          ctx.moveTo(-halfW * 1.1, -halfH * 0.2);
          ctx.lineTo(-halfW * 1.25, -halfH * 1.4);
          ctx.lineTo(-halfW * 0.7, -halfH * 1.4);
          ctx.lineTo(-halfW * 0.6, -halfH * 0.2);
          ctx.fill(); 
          ctx.stroke();
          // Wing
          ctx.fillStyle = '#111';
          ctx.fillRect(-halfW * 1.3, -halfH * 1.5, cw * 0.6, 6);
      } else if (car.shape === 'buggy') {
          ctx.strokeStyle = '#64748b';
          ctx.lineWidth = 3;
          ctx.beginPath();
          ctx.moveTo(-halfW * 0.7, 0); ctx.lineTo(halfW * 0.9, 0); 
          ctx.moveTo(-halfW * 0.5, -halfH * 1.4); ctx.lineTo(halfW * 0.4, -halfH * 1.4);
          ctx.lineTo(halfW * 0.9, 0);
          ctx.stroke();
      }

      // 4. Exhaust
      const exhaustX = -halfW * 1.0;
      const exhaustY = halfH * 0.3;
      ctx.fillStyle = '#444';
      if (car.shape !== 'bike') {
          ctx.fillRect(exhaustX - 8, exhaustY, 15, 8);
          ctx.fillStyle = '#000';
          ctx.beginPath(); ctx.arc(exhaustX - 8, exhaustY + 4, 3, 0, Math.PI*2); ctx.fill();
      }

      if (Math.random() > 0.7 && !isMenuBackground && Math.abs(carRef.current.bodies[0].velocity.x) > 1) {
          spawnParticles(
              carRef.current.bodies[0].position.x + exhaustX, 
              carRef.current.bodies[0].position.y + exhaustY + 4, 
              1, 'smoke'
          );
      }
  };

  const drawWheel = (ctx: CanvasRenderingContext2D, x: number, y: number, r: number, angle: number, color: string) => {
      ctx.save();
      ctx.translate(x, y);
      ctx.rotate(angle);

      // Tire
      ctx.beginPath(); ctx.arc(0, 0, r, 0, Math.PI * 2); 
      ctx.fillStyle = '#1c1917'; ctx.fill(); // Dark rubber

      // Detailed Tread
      ctx.strokeStyle = '#292524'; ctx.lineWidth = 4;
      ctx.setLineDash([5, 8]);
      ctx.beginPath(); ctx.arc(0,0, r-2, 0, Math.PI*2); ctx.stroke();
      ctx.setLineDash([]);

      // Rim
      const rimR = r * 0.65;
      ctx.beginPath(); ctx.arc(0, 0, rimR, 0, Math.PI * 2);
      ctx.fillStyle = color; ctx.fill();
      ctx.strokeStyle = '#444'; ctx.lineWidth = 2; ctx.stroke();

      // Spokes
      ctx.strokeStyle = '#000'; ctx.lineWidth = 3; ctx.lineCap = 'round';
      const spokes = 5;
      for (let i = 0; i < spokes; i++) {
          ctx.rotate((Math.PI * 2) / spokes);
          ctx.beginPath(); ctx.moveTo(0, 0); ctx.lineTo(0, rimR - 3); ctx.stroke();
      }

      // Center Hub
      ctx.beginPath(); ctx.arc(0, 0, r * 0.15, 0, Math.PI * 2);
      ctx.fillStyle = '#555'; ctx.fill();
      ctx.beginPath(); ctx.arc(0, 0, r * 0.08, 0, Math.PI * 2);
      ctx.fillStyle = '#222'; ctx.fill();

      ctx.restore();
  };

  const drawSuspension = (ctx: CanvasRenderingContext2D, chassisBody: any, wheelBody: any, offsetX: number, offsetY: number) => {
      const cAngle = chassisBody.angle;
      const worldOffsetX = offsetX * Math.cos(cAngle) - offsetY * Math.sin(cAngle);
      const worldOffsetY = offsetX * Math.sin(cAngle) + offsetY * Math.cos(cAngle);

      const p1 = { x: chassisBody.position.x + worldOffsetX, y: chassisBody.position.y + worldOffsetY };
      const p2 = { x: wheelBody.position.x, y: wheelBody.position.y };

      const dist = Math.hypot(p2.x - p1.x, p2.y - p1.y);
      const angle = Math.atan2(p2.y - p1.y, p2.x - p1.x);

      ctx.save();
      ctx.translate(p1.x, p1.y);
      ctx.rotate(angle);

      // Upper strut
      ctx.strokeStyle = '#444'; ctx.lineWidth = 6;
      ctx.beginPath(); ctx.moveTo(0, 0); ctx.lineTo(dist/2, 0); ctx.stroke();

      // Lower strut
      ctx.strokeStyle = '#999'; ctx.lineWidth = 4;
      ctx.beginPath(); ctx.moveTo(dist/2, 0); ctx.lineTo(dist, 0); ctx.stroke();

      // Coil
      ctx.strokeStyle = '#dc2626'; ctx.lineWidth = 2.5;
      ctx.beginPath();
      ctx.moveTo(0, 0);
      const zigs = 8;
      for(let i=0; i<=zigs; i++) {
          ctx.lineTo((dist / zigs) * i, i % 2 === 0 ? -5 : 5);
      }
      ctx.stroke();
      ctx.restore();
  };

  const drawCloud = (ctx: CanvasRenderingContext2D, cloud: Cloud) => {
      ctx.save();
      ctx.translate(cloud.x, cloud.y);
      ctx.scale(cloud.scale, cloud.scale);

      ctx.fillStyle = 'rgba(255,255,255,0.7)';

      ctx.beginPath();
      ctx.arc(0, 0, 30, 0, Math.PI * 2);
      ctx.arc(35, 5, 40, 0, Math.PI * 2);
      ctx.arc(-35, 5, 35, 0, Math.PI * 2);
      ctx.arc(15, -25, 30, 0, Math.PI * 2);
      ctx.arc(-15, -25, 30, 0, Math.PI * 2);

      ctx.fill();
      ctx.restore();
  };

  const drawTree = (ctx: CanvasRenderingContext2D, type: number, seed: number) => {
    // Trunk
    ctx.fillStyle = COLORS.treeTrunk;
    const trunkW = 12 + seed * 4;
    const trunkH = 40 + seed * 20;
    ctx.fillRect(-trunkW/2, -trunkH, trunkW, trunkH);

    // Leaves
    if (type === 6) { // Pine
        ctx.fillStyle = COLORS.treeLeafDark;
        ctx.beginPath();
        ctx.moveTo(-40, -trunkH + 10);
        ctx.lineTo(0, -trunkH - 100 - seed * 50);
        ctx.lineTo(40, -trunkH + 10);
        ctx.fill();

        ctx.fillStyle = COLORS.treeLeafLight;
        ctx.beginPath();
        ctx.moveTo(-30, -trunkH - 20);
        ctx.lineTo(0, -trunkH - 100 - seed * 50);
        ctx.lineTo(30, -trunkH - 20);
        ctx.fill();
    } else { // Round
        ctx.fillStyle = COLORS.treeLeafDark;
        ctx.beginPath();
        ctx.arc(0, -trunkH - 20, 40 + seed * 10, 0, Math.PI * 2);
        ctx.fill();

        ctx.fillStyle = COLORS.treeLeafLight;
        ctx.beginPath();
        ctx.arc(-10, -trunkH - 30, 30 + seed * 10, 0, Math.PI * 2);
        ctx.fill();
    }
  };

  const drawRock = (ctx: CanvasRenderingContext2D, seed: number) => {
      ctx.fillStyle = COLORS.boulder;
      ctx.beginPath();
      ctx.moveTo(-20 - seed * 10, 0);
      ctx.lineTo(-15 - seed * 5, -20 - seed * 15);
      ctx.lineTo(10 + seed * 5, -25 - seed * 10);
      ctx.lineTo(25 + seed * 10, 0);
      ctx.fill();

      // Detail
      ctx.fillStyle = COLORS.boulderDark;
      ctx.beginPath();
      ctx.moveTo(-10, -5);
      ctx.lineTo(0, -15);
      ctx.lineTo(10, -5);
      ctx.fill();
  };

  const drawBush = (ctx: CanvasRenderingContext2D, seed: number) => {
     ctx.fillStyle = COLORS.bushDark;
     ctx.beginPath();
     ctx.arc(-15, -10, 15 + seed * 5, 0, Math.PI * 2);
     ctx.arc(15, -10, 12 + seed * 5, 0, Math.PI * 2);
     ctx.arc(0, -20, 18 + seed * 5, 0, Math.PI * 2);
     ctx.fill();

     ctx.fillStyle = COLORS.bushLight;
     ctx.beginPath();
     ctx.arc(0, -20, 10 + seed * 3, 0, Math.PI * 2);
     ctx.fill();
  };

  const animate = useCallback(() => {
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d', { alpha: false });
    if (!canvas || !ctx || gameStateRef.current.isGameOver) {
        requestRef.current = requestAnimationFrame(animate);
        return;
    }

    if (!pausedRef.current) {
        Matter.Engine.update(engineRef.current, 1000 / 60);
        const chassis = carRef.current.bodies.find((b: any) => b.label === 'chassis');
        const wheelB = carRef.current.bodies.find((b: any) => b.label === 'wheelBack');
        const wheelF = carRef.current.bodies.find((b: any) => b.label === 'wheelFront');

        const { keys } = gameStateRef.current;
        const speedRatio = Matter.Vector.magnitude(chassis.velocity) / 25;
        const isGrounded = wheelGroundContacts.current > 0;

        if (!isMenuBackground) {
            soundManagerRef.current?.updateContinuous(speedRatio, isGrounded, keys.right && !isOutOfFuelRef.current);
            if (keys.right && !isOutOfFuelRef.current) {
                fuelRef.current -= config.FUEL_CONSUMPTION;
                if (fuelRef.current <= 0) {
                    fuelRef.current = 0; isOutOfFuelRef.current = true;
                    setNotification({ text: "OUT OF FUEL", id: Date.now() });
                    setTimeout(() => { if (!gameStateRef.current.isGameOver) onGameOver(gameStateRef.current.distance, gameStateRef.current.coins); }, 3000);
                }
                const power = selectedCar.acceleration;
                if (selectedCar.driveTrain !== 'FWD') Matter.Body.setAngularVelocity(wheelB, Math.min(wheelB.angularVelocity + power, selectedCar.speed));
                if (selectedCar.driveTrain !== 'RWD') Matter.Body.setAngularVelocity(wheelF, Math.min(wheelF.angularVelocity + power, selectedCar.speed));
                if (chassis.angularVelocity > -config.MAX_ROTATION_SPEED) Matter.Body.setAngularVelocity(chassis, chassis.angularVelocity - (isGrounded ? config.GROUND_ROTATION_SPEED : config.AIR_ROTATION_SPEED));
            } else if (keys.left) {
                 if (selectedCar.driveTrain !== 'FWD') Matter.Body.setAngularVelocity(wheelB, Math.max(wheelB.angularVelocity - 0.1, -selectedCar.speed/2));
                 if (selectedCar.driveTrain !== 'RWD') Matter.Body.setAngularVelocity(wheelF, Math.max(wheelF.angularVelocity - 0.1, -selectedCar.speed/2));
                 if (chassis.angularVelocity < config.MAX_ROTATION_SPEED) Matter.Body.setAngularVelocity(chassis, chassis.angularVelocity + (isGrounded ? config.GROUND_ROTATION_SPEED : config.AIR_ROTATION_SPEED));
            }
        } else {
            Matter.Body.setAngularVelocity(wheelB, 0.4); Matter.Body.setAngularVelocity(wheelF, 0.4);
            if (chassis.position.y > 500) Matter.Body.setPosition(chassis, { x: 200, y: -100 });
        }

        cameraPosRef.current = { x: chassis.position.x, y: chassis.position.y };
        if (chassis.position.x > lastChunkDataRef.current.endX - config.RENDER_DISTANCE) addChunk(lastChunkDataRef.current.endX);
        gameStateRef.current.distance = Math.max(0, Math.floor((chassis.position.x - 200) / 10));

        if (hudDistanceRef.current) hudDistanceRef.current.innerText = `${gameStateRef.current.distance}`;
        if (hudCoinsRef.current) hudCoinsRef.current.innerText = `${gameStateRef.current.coins}`;
        if (hudFuelBarRef.current) hudFuelBarRef.current.style.width = `${(fuelRef.current / config.MAX_FUEL) * 100}%`;
    }

    // --- RENDERING ---
    const zoom = cameraZoomRef.current;
    const vH = config.BASE_VIEWPORT_HEIGHT * zoom;
    const vW = (canvas.width / canvas.height) * vH; 
    const scale = canvas.height / vH;

    const camX = cameraPosRef.current.x - vW * 0.3;
    const camY = cameraPosRef.current.y - vH * 0.6;

    ctx.setTransform(scale, 0, 0, scale, -camX * scale, -camY * scale);

    // Sky
    const skyGrad = ctx.createLinearGradient(camX, camY, camX, camY + vH);
    skyGrad.addColorStop(0, selectedMap.skyColorStart); skyGrad.addColorStop(1, selectedMap.skyColorEnd);
    ctx.fillStyle = skyGrad; ctx.fillRect(camX, camY, vW, vH);

    // Sun/Moon Glow
    if (selectedMap.backgroundType !== 'moon') {
        const sunGrad = ctx.createRadialGradient(camX + vW - 100, camY + 100, 20, camX + vW - 100, camY + 100, 200);
        sunGrad.addColorStop(0, 'rgba(255, 255, 200, 0.6)');
        sunGrad.addColorStop(1, 'rgba(255, 255, 200, 0)');
        ctx.fillStyle = sunGrad; ctx.fillRect(camX, camY, vW, vH/2);
    }

    if (starsRef.current.length > 0) {
        ctx.fillStyle = 'white';
        starsRef.current.forEach(s => {
            const px = s.x + camX * 0.85; 
            if (px > camX && px < camX + vW) {
                ctx.globalAlpha = s.opacity; ctx.beginPath(); ctx.arc(px, s.y, s.r, 0, Math.PI*2); ctx.fill();
            }
        });
        ctx.globalAlpha = 1;
    }

    cloudsRef.current.forEach(c => {
        if (c.x > camX - 400 && c.x < camX + vW + 400) {
            drawCloud(ctx, c);
        }
    });

    const groundPat = getPattern(ctx, 'ground', selectedMap.groundColor, selectedMap.groundDarkColor);
    ctx.fillStyle = groundPat || selectedMap.groundColor;

    chunksRef.current.forEach(chunk => {
        if (chunk.endX < camX || chunk.pathData[0].x > camX + vW) return;

        ctx.beginPath(); ctx.moveTo(chunk.pathData[0].x, chunk.pathData[0].y);
        chunk.pathData.forEach(p => ctx.lineTo(p.x, p.y));
        ctx.lineTo(chunk.endX, chunk.endY + 1000); ctx.lineTo(chunk.pathData[0].x, chunk.pathData[0].y + 1000);
        ctx.fill(); 

        if (selectedMap.backgroundType === 'earth') {
             ctx.strokeStyle = COLORS.grassDetail; ctx.lineWidth = 10;
        } else if (selectedMap.backgroundType === 'moon') {
             ctx.strokeStyle = '#94a3b8'; ctx.lineWidth = 6;
        } else {
             ctx.strokeStyle = '#475569'; ctx.lineWidth = 8;
        }
        ctx.beginPath();
        chunk.pathData.forEach((p, i) => {
            if (i===0) ctx.moveTo(p.x, p.y);
            else ctx.lineTo(p.x, p.y);
        });
        ctx.stroke();

        chunk.decorations.forEach(d => {
            if (d.x < camX - 100 || d.x > camX + vW + 100) return;
            ctx.save(); ctx.translate(d.x, d.y); ctx.rotate(d.angle); ctx.scale(d.scale, d.scale);

            if (d.type === 5) { 
                ctx.fillStyle = 'white'; ctx.fillRect(0,-200,6,200); 
                ctx.fillStyle = '#ef4444'; ctx.beginPath(); ctx.moveTo(6,-200); ctx.lineTo(70,-175); ctx.lineTo(6,-150); ctx.fill();
            } else if (d.type === 3) { 
                ctx.fillStyle = COLORS.lampPost; ctx.fillRect(-2,-80,4,80); 
                ctx.fillStyle = COLORS.lampLight; ctx.beginPath(); ctx.arc(10,-80,6,0,Math.PI*2); ctx.fill();
                ctx.fillStyle = COLORS.lampGlow; ctx.beginPath(); ctx.arc(10,-80,20,0,Math.PI*2); ctx.fill();
            } else if (d.type === 4) { 
                ctx.fillStyle = '#78350f'; ctx.fillRect(-2,-20,4,20);
                ctx.fillRect(-20,-15,40,4);
            } else if (d.type === 6 || d.type === 7) { 
                drawTree(ctx, d.type, d.seed);
            } else if (d.type === 8) { 
                drawRock(ctx, d.seed);
            } else if (d.type === 9) { 
                drawBush(ctx, d.seed);
            } else if (selectedMap.backgroundType === 'earth') {
                 ctx.strokeStyle = COLORS.grassDetail; ctx.lineWidth = 2; 
                 ctx.beginPath(); 
                 ctx.moveTo(0,0); ctx.lineTo(-3, -8 - d.seed * 5);
                 ctx.moveTo(0,0); ctx.lineTo(3, -6 - d.seed * 5);
                 ctx.stroke();
            }
            ctx.restore();
        });

        chunk.coinBodies.forEach(b => {
            if (!collectedCoinIdsRef.current.has(b.id) && b.position.x > camX - 50 && b.position.x < camX + vW + 50) {
                ctx.save(); ctx.translate(b.position.x, b.position.y);
                const pulse = Math.sin(Date.now() / 200) * 0.1 + 1;
                ctx.scale(pulse, pulse);
                ctx.fillStyle = COLORS.coinOuter; ctx.beginPath(); ctx.arc(0,0,config.COIN_SIZE,0,Math.PI*2); ctx.fill();
                ctx.fillStyle = COLORS.coinInner; ctx.beginPath(); ctx.arc(0,0,config.COIN_SIZE*0.7,0,Math.PI*2); ctx.fill();
                ctx.fillStyle = '#fff'; ctx.font = 'bold 12px monospace'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle'; ctx.fillText('$', 0, 1);
                ctx.restore();
            }
        });

        chunk.fuelBodies.forEach(b => {
            if (!collectedFuelIdsRef.current.has(b.id) && b.position.x > camX - 50 && b.position.x < camX + vW + 50) {
                ctx.save(); ctx.translate(b.position.x, b.position.y);
                const pulse = Math.sin(Date.now() / 300) * 0.1 + 1;
                ctx.scale(pulse, pulse);
                ctx.fillStyle = COLORS.fuelCan; 
                ctx.fillRect(-10, -15, 20, 30);
                ctx.fillStyle = COLORS.fuelCanCap;
                ctx.fillRect(-6, -18, 12, 3);
                ctx.font = 'bold 10px sans-serif'; ctx.fillStyle = 'white'; ctx.fillText('FUEL', -10, 5);
                ctx.restore();
            }
        });
    });

    // --- CAR RENDER ---
    const chassis = carRef.current.bodies.find((b: any) => b.label === 'chassis');
    const wheelB = carRef.current.bodies.find((b: any) => b.label === 'wheelBack');
    const wheelF = carRef.current.bodies.find((b: any) => b.label === 'wheelFront');
    const cw = selectedCar.width || config.CAR_WIDTH; 
    const ch = selectedCar.height || config.CAR_HEIGHT;
    const wr = selectedCar.wheelSize || config.WHEEL_SIZE;

    // Draw Suspension
    const wheelOffsetX = -cw / 2 + wr;
    const wheelOffsetY = ch / 2;
    drawSuspension(ctx, chassis, wheelB, wheelOffsetX, wheelOffsetY);
    drawSuspension(ctx, chassis, wheelF, -wheelOffsetX, wheelOffsetY);

    // Draw Chassis
    ctx.save(); ctx.translate(chassis.position.x, chassis.position.y); ctx.rotate(chassis.angle);

    ctx.shadowColor = 'rgba(0,0,0,0.5)'; ctx.shadowBlur = 10;
    let bodyFill: string | CanvasPattern = selectedCar.bodyColor;
    if (selectedCar.texture !== 'plain') bodyFill = getPattern(ctx, selectedCar.texture, selectedCar.bodyColor, selectedCar.textureColor2) || bodyFill;

    if (selectedCar.imageUrl) {
        // ... (image logic from previous turn)
    }

    ctx.fillStyle = bodyFill;
    ctx.strokeStyle = 'rgba(0,0,0,0.6)'; ctx.lineWidth = 2;

    drawChassisPath(ctx, selectedCar, cw, ch);
    ctx.fill(); 
    ctx.shadowBlur = 0; 
    ctx.stroke();

    drawCarDetails(ctx, selectedCar, cw, ch);

    ctx.restore();

    // Draw Wheels (AFTER CHASSIS) - Ensures Z-Index correctness
    [wheelB, wheelF].forEach(w => {
        drawWheel(ctx, w.position.x, w.position.y, wr, w.angle, selectedCar.wheelColor);
    });

    particlesRef.current.forEach(p => {
        if (p.active) {
            ctx.fillStyle = p.type === 'spark' ? COLORS.particleSpark : 
                            p.type === 'smoke' ? COLORS.particleSmoke : COLORS.particleDust; 
            ctx.globalAlpha = p.life / p.maxLife;
            ctx.beginPath(); 
            if (p.type === 'smoke') {
                const r = 4 + (1 - p.life/p.maxLife) * 8;
                ctx.arc(p.x, p.y, r, 0, Math.PI*2);
            } else {
                ctx.arc(p.x, p.y, 2.5, 0, Math.PI*2); 
            }
            ctx.fill();
            p.x += p.vx; p.y += p.vy; 
            if (p.type !== 'smoke') p.vy += 0.2; 
            else { p.vx *= 0.95; p.vy -= 0.05; } 
            p.life--; if (p.life <= 0) p.active = false;
        }
    });
    ctx.globalAlpha = 1;

    const now = performance.now(); frameCountRef.current++;
    if (now - lastFpsTimeRef.current >= 500) {
        const fps = Math.round((frameCountRef.current * 1000) / (now - lastFpsTimeRef.current));
        if (hudFpsRef.current) hudFpsRef.current.innerText = `${fps} FPS`;
        lastFpsTimeRef.current = now; frameCountRef.current = 0;
    }

    requestRef.current = requestAnimationFrame(animate);
  }, [config, selectedCar, selectedMap, onGameOver, onLevelComplete, isMenuBackground]);

  return (
    <div ref={containerRef} className={`relative w-full h-full bg-slate-900 overflow-hidden select-none ${isMenuBackground ? 'opacity-40 pointer-events-none' : ''}`}>
      {!isMenuBackground && (
          <>
            <div className="absolute top-4 right-4 z-30 flex gap-2">
                <div ref={hudFpsRef} className="font-mono text-xs text-emerald-500 bg-black/60 px-2 py-1 rounded">60 FPS</div>
                <button onClick={() => { pausedRef.current = !pausedRef.current; setIsPaused(!isPaused); }} className="w-10 h-10 bg-black/60 text-white rounded flex items-center justify-center border border-white/20 hover:bg-white/10 active:scale-95 transition-all">
                    {isPaused ? "▶" : "⏸"}
                </button>
            </div>

            {isPaused && (
                <div className="absolute inset-0 z-40 flex items-center justify-center bg-black/40 backdrop-blur-sm">
                    <div className="text-5xl font-black italic text-white tracking-widest border-4 border-white p-6 uppercase animate-pulse shadow-2xl">
                        Paused
                    </div>
                </div>
            )}

            <div className="absolute top-6 left-6 z-10 pointer-events-none flex flex-col gap-2">
                <div className="bg-black/60 px-4 py-2 rounded-xl border border-white/10 flex flex-col">
                    <span className="text-[10px] text-neutral-400 uppercase font-bold">Distance</span>
                    <span ref={hudDistanceRef} className="text-2xl font-mono font-bold text-white">0</span>
                </div>
                <div className="bg-black/60 px-4 py-2 rounded-xl border border-amber-500/20 flex gap-3 items-center">
                    <div className="w-6 h-6 rounded-full bg-amber-500 text-black flex items-center justify-center text-xs font-bold">$</div>
                    <span ref={hudCoinsRef} className="text-xl font-mono font-bold text-white">0</span>
                </div>
                <div className="w-48 h-1.5 bg-neutral-800 rounded-full mt-2 overflow-hidden border border-white/5">
                    <div ref={hudFuelBarRef} className="h-full bg-red-500 transition-all duration-200" style={{ width: '100%' }} />
                </div>
            </div>
            {notification && (
                <div className="absolute top-1/3 left-1/2 -translate-x-1/2 z-40 text-4xl font-black italic text-white animate-bounce drop-shadow-lg">{notification.text}</div>
            )}
            <div className="absolute bottom-10 left-10 right-10 z-30 flex justify-between">
                 <button 
                    className="w-24 h-24 rounded-full bg-black/40 border-2 border-white/10 active:bg-white/10 active:border-red-500/50 transition-all text-white font-black italic text-xl" 
                    onMouseDown={() => gameStateRef.current.keys.left = true} 
                    onMouseUp={() => gameStateRef.current.keys.left = false} 
                    onMouseLeave={() => gameStateRef.current.keys.left = false}
                    onTouchStart={(e) => { e.preventDefault(); gameStateRef.current.keys.left = true; }} 
                    onTouchEnd={(e) => { e.preventDefault(); gameStateRef.current.keys.left = false; }}
                >
                    BRAKE
                </button>
                 <button 
                    className="w-24 h-24 rounded-full bg-black/40 border-2 border-white/10 active:bg-white/10 active:border-emerald-500/50 transition-all text-white font-black italic text-xl" 
                    onMouseDown={() => gameStateRef.current.keys.right = true} 
                    onMouseUp={() => gameStateRef.current.keys.right = false} 
                    onMouseLeave={() => gameStateRef.current.keys.right = false}
                    onTouchStart={(e) => { e.preventDefault(); gameStateRef.current.keys.right = true; }} 
                    onTouchEnd={(e) => { e.preventDefault(); gameStateRef.current.keys.right = false; }}
                >
                    GAS
                </button>
            </div>
          </>
      )}
      <canvas ref={canvasRef} className="w-full h-full" style={{ imageRendering: config.PIXELATED ? 'pixelated' : 'auto' }} />
    </div>
  );
};

export default Game;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { COLORS } from '../constants';
import { GameConfig, CarModel, MapConfig, GameMode, LevelConfig } from '../types';
import { createEngine, createCar, generateTerrainChunk, generateClouds, createWall, TerrainChunk, Cloud, Decoration } from '../utils/physics';
import { SoundManager } from '../utils/audio';
import DebugMenu from './DebugMenu';

const Matter = (window as any).Matter;

interface GameProps {
  mode: GameMode;
  levelConfig?: LevelConfig;
  onGameOver: (distance: number, coins: number) => void;
  onLevelComplete: (coins: number) => void;
  selectedCar: CarModel;
  selectedMap: MapConfig;
  config: GameConfig;
  onUpdateConfig: (key: keyof GameConfig, value: any) => void;
  onResetConfig: () => void;
  onExit: () => void;
  onRestart: () => void;
  isMenuBackground?: boolean;
  onReady?: () => void;
}

interface Particle {
    x: number; y: number; vx: number; vy: number;
    life: number; maxLife: number; active: boolean;
    type: 'dust' | 'spark' | 'explosion' | 'smoke';
}

const Game: React.FC<GameProps> = ({ mode, levelConfig, onGameOver, onLevelComplete, selectedCar, selectedMap, config, onUpdateConfig, onResetConfig, onExit, onRestart, isMenuBackground = false, onReady }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const requestRef = useRef<number | null>(null);
  const engineRef = useRef<any>(null);
  const carRef = useRef<any>(null);
  const soundManagerRef = useRef<SoundManager | null>(null);

  // Game Logic Refs
  const chunksRef = useRef<TerrainChunk[]>([]);
  const cloudsRef = useRef<Cloud[]>([]);
  const collectedCoinIdsRef = useRef<Set<number>>(new Set());
  const collectedFuelIdsRef = useRef<Set<number>>(new Set());
  const particlesRef = useRef<Particle[]>([]);
  const lastChunkDataRef = useRef({ endX: 0, endY: 200, globalIndex: 0, segmentsSinceFuel: 0 });

  const fuelRef = useRef(config.MAX_FUEL);
  const wheelGroundContacts = useRef(0);
  const isOutOfFuelRef = useRef(false);
  const gameStateRef = useRef({ distance: 0, coins: 0, isGameOver: false, keys: { left: false, right: false } });

  // Visual state
  const cameraZoomRef = useRef(1.0);
  const cameraPosRef = useRef({ x: 0, y: 0 });
  const [isPaused, setIsPaused] = useState(false);
  const pausedRef = useRef(false);
  const [notification, setNotification] = useState<{text: string, subText?: string, id: number} | null>(null);
  const patternsRef = useRef<{[key: string]: CanvasPattern | null}>({});
  const starsRef = useRef<{x: number, y: number, r: number, opacity: number}[]>([]);

  // FPS Logic
  const lastFpsTimeRef = useRef(0);
  const frameCountRef = useRef(0);
  const hudFpsRef = useRef<HTMLDivElement>(null);

  // HUD Refs
  const hudDistanceRef = useRef<HTMLDivElement>(null);
  const hudCoinsRef = useRef<HTMLDivElement>(null);
  const hudFuelBarRef = useRef<HTMLDivElement>(null);

  // Setup Stars for Moon
  useEffect(() => {
    if (selectedMap.backgroundType === 'moon') {
        const s = [];
        for(let i=0; i<150; i++) {
            s.push({ x: Math.random() * 2000, y: Math.random() * 1000 - 500, r: Math.random() * 2, opacity: Math.random() });
        }
        starsRef.current = s;
    } else {
        starsRef.current = [];
    }
  }, [selectedMap]);

  const addChunk = useCallback((startX: number) => {
    const { endY, globalIndex, segmentsSinceFuel } = lastChunkDataRef.current;
    const length = config.CHUNK_SIZE;
    const chunkId = Math.floor(startX / length);

    const newChunk = generateTerrainChunk(
        chunkId, startX, endY, globalIndex, length, false, config, selectedMap.backgroundType, segmentsSinceFuel,
        mode === 'LEVELS' && levelConfig ? levelConfig.distance : null
    );

    if (engineRef.current) Matter.World.add(engineRef.current.world, newChunk.composite);

    if (selectedMap.backgroundType === 'earth' || selectedMap.backgroundType === 'highway') {
        const newClouds = generateClouds(startX, length);
        cloudsRef.current = [...cloudsRef.current, ...newClouds];
    }

    lastChunkDataRef.current = {
        endX: startX + length,
        endY: newChunk.endY,
        globalIndex: newChunk.endGlobalIndex,
        segmentsSinceFuel: newChunk.nextSegmentsSinceFuel
    };

    chunksRef.current.push(newChunk);

    // Cleanup old chunks and clouds to prevent memory leak
    if (chunksRef.current.length > 5) {
        const oldChunk = chunksRef.current.shift();
        if (oldChunk && engineRef.current) {
             Matter.Composite.remove(engineRef.current.world, oldChunk.composite);
        }
    }
    if (cloudsRef.current.length > 50) {
        cloudsRef.current = cloudsRef.current.slice(cloudsRef.current.length - 40);
    }
  }, [config, selectedMap.backgroundType, mode, levelConfig]);

  const handleResize = useCallback(() => {
    if (canvasRef.current && containerRef.current) {
        const rw = containerRef.current.clientWidth * config.RESOLUTION;
        const rh = containerRef.current.clientHeight * config.RESOLUTION;
        canvasRef.current.width = rw;
        canvasRef.current.height = rh;
        patternsRef.current = {}; 
    }
  }, [config.RESOLUTION]);

  useEffect(() => {
    window.addEventListener('resize', handleResize);
    handleResize();
    return () => window.removeEventListener('resize', handleResize);
  }, [handleResize]);

  // Initialization Sequence
  useEffect(() => {
    if (!isMenuBackground) soundManagerRef.current = new SoundManager();
    const engine = createEngine(config);
    engineRef.current = engine;
    const car = createCar(200, -100, selectedCar, config); 
    carRef.current = car;
    Matter.World.add(engine.world, [car, createWall(-1000)]);

    // Reset loop state
    lastChunkDataRef.current = { endX: 0, endY: 200, globalIndex: 0, segmentsSinceFuel: 0 };
    chunksRef.current = [];
    cloudsRef.current = [];
    collectedCoinIdsRef.current = new Set();
    collectedFuelIdsRef.current = new Set();
    fuelRef.current = config.MAX_FUEL;
    isOutOfFuelRef.current = false;
    gameStateRef.current.isGameOver = false;
    gameStateRef.current.distance = 0;
    gameStateRef.current.coins = 0;
    pausedRef.current = false;
    setIsPaused(false);

    let currentGenX = 0;
    const buffer = isMenuBackground ? 4000 : config.INITIAL_BUFFER_DISTANCE;
    while (currentGenX < buffer) {
        addChunk(currentGenX);
        currentGenX += config.CHUNK_SIZE;
    }

    particlesRef.current = Array.from({ length: config.PARTICLE_POOL_SIZE }).map(() => ({
        x: 0, y: 0, vx: 0, vy: 0, life: 0, maxLife: 0, active: false, type: 'dust'
    }));

    Matter.Events.on(engine, 'collisionStart', (event: any) => {
        event.pairs.forEach((pair: any) => {
            const { bodyA, bodyB } = pair;
            const isWheel = (b: any) => b.label === 'wheelBack' || b.label === 'wheelFront';
            const isGround = (b: any) => b.label === 'ground' || b.label === 'obstacle';

            if ((isWheel(bodyA) && isGround(bodyB)) || (isWheel(bodyB) && isGround(bodyA))) {
                wheelGroundContacts.current++;
                const w = isWheel(bodyA) ? bodyA : bodyB;
                const speed = Matter.Vector.magnitude(w.velocity);
                if (speed > 5) spawnParticles(w.position.x, w.position.y + 15, 2, speed > 10 ? 'spark' : 'dust');
            }

            if ((bodyA.label === 'chassis' && bodyB.label === 'ground') || (bodyB.label === 'chassis' && bodyA.label === 'ground')) {
                if (isMenuBackground) return;
                const chassis = bodyA.label === 'chassis' ? bodyA : bodyB;
                if (Math.abs(chassis.angle) > Math.PI / 1.5) {
                    gameStateRef.current.isGameOver = true;
                    soundManagerRef.current?.stopContinuous();
                    onGameOver(gameStateRef.current.distance, gameStateRef.current.coins);
                }
            }

            let item = null;
            if (['chassis', 'wheelBack', 'wheelFront'].includes(bodyA.label) && ['coin', 'fuel', 'finishLine'].includes(bodyB.label)) item = bodyB;
            if (['chassis', 'wheelBack', 'wheelFront'].includes(bodyB.label) && ['coin', 'fuel', 'finishLine'].includes(bodyA.label)) item = bodyA;

            if (item && !isMenuBackground) {
                if (item.label === 'finishLine') {
                    gameStateRef.current.isGameOver = true;
                    onLevelComplete(gameStateRef.current.coins);
                } else if (!collectedCoinIdsRef.current.has(item.id) && !collectedFuelIdsRef.current.has(item.id)) {
                    if (item.label === 'coin') {
                        collectedCoinIdsRef.current.add(item.id);
                        gameStateRef.current.coins += config.COIN_VALUE;
                        soundManagerRef.current?.playCoinSound();
                        Matter.World.remove(engine.world, item);
                    } else if (item.label === 'fuel') {
                        collectedFuelIdsRef.current.add(item.id);
                        fuelRef.current = Math.min(config.MAX_FUEL, fuelRef.current + config.FUEL_CAN_VALUE);
                        isOutOfFuelRef.current = false;
                        setNotification({ text: "FUEL!", id: Date.now() });
                        setTimeout(() => setNotification(null), 1500);
                        Matter.World.remove(engine.world, item);
                    }
                }
            }
        });
    });

    Matter.Events.on(engine, 'collisionEnd', (event: any) => {
        event.pairs.forEach((pair: any) => {
            const isWheel = (b: any) => b.label === 'wheelBack' || b.label === 'wheelFront';
            const isGround = (b: any) => b.label === 'ground' || b.label === 'obstacle';
            if ((isWheel(pair.bodyA) && isGround(pair.bodyB)) || (isWheel(pair.bodyB) && isGround(pair.bodyA))) {
                wheelGroundContacts.current = Math.max(0, wheelGroundContacts.current - 1);
            }
        });
    });

    // Notify parent that we are ready to start playing
    if (onReady) onReady();

    requestRef.current = requestAnimationFrame(animate);
    return () => {
        if (requestRef.current) cancelAnimationFrame(requestRef.current);
        Matter.Engine.clear(engine);
        if (soundManagerRef.current) soundManagerRef.current.stopContinuous();
    };
  }, [addChunk, selectedCar, onGameOver, onLevelComplete, config, isMenuBackground, onReady]);

  const handleResume = useCallback(() => {
    pausedRef.current = false;
    setIsPaused(false);
  }, []);

  const spawnParticles = (x: number, y: number, count: number, type: 'dust' | 'spark' | 'explosion' | 'smoke') => {
      let spawned = 0;
      for (let p of particlesRef.current) {
          if (spawned >= count) break;
          if (!p.active) {
              p.active = true; p.x = x; p.y = y; p.type = type;
              p.maxLife = config.PARTICLE_LIFETIME; p.life = p.maxLife;
              if (type === 'smoke') {
                  p.vx = (Math.random() - 0.5) * 2 - 2; // Smoke blows back
                  p.vy = (Math.random() - 0.5) * 2;
                  p.maxLife = 60;
                  p.life = 60;
              } else {
                  p.vx = (Math.random() - 0.5) * 5; 
                  p.vy = (Math.random() - 0.5) * 5;
              }
              spawned++;
          }
      }
  };

  const getPattern = (ctx: CanvasRenderingContext2D, type: string, color1: string, color2: string) => {
      const key = `${type}-${color1}-${color2}`;
      if (patternsRef.current[key]) return patternsRef.current[key];
      const pCanvas = document.createElement('canvas');
      const pCtx = pCanvas.getContext('2d')!;
      pCanvas.width = 40; pCanvas.height = 40;
      if (type === 'ground') {
          // Noise texture
          pCtx.fillStyle = color1; pCtx.fillRect(0,0,40,40);
          pCtx.fillStyle = color2; 
          for(let i=0; i<30; i++) {
              pCtx.globalAlpha = 0.1 + Math.random() * 0.2;
              pCtx.beginPath(); 
              pCtx.arc(Math.random()*40, Math.random()*40, 1 + Math.random()*2, 0, Math.PI*2);
              pCtx.fill();
          }
      } else if (type === 'striped') {
          pCanvas.width = 20; pCtx.fillStyle = color1; pCtx.fillRect(0,0,20,40);
          pCtx.fillStyle = color2; pCtx.fillRect(0,0,10,40);
      } else if (type === 'checker') {
          pCanvas.width = 20; pCanvas.height = 20;
          pCtx.fillStyle = color1; pCtx.fillRect(0,0,20,20);
          pCtx.fillStyle = color2; pCtx.fillRect(0,0,10,10); pCtx.fillRect(10,10,10,10);
      } else if (type === 'dots') {
          pCanvas.width = 10; pCanvas.height = 10;
          pCtx.fillStyle = color1; pCtx.fillRect(0,0,10,10);
          pCtx.fillStyle = color2; pCtx.beginPath(); pCtx.arc(5,5,2,0,Math.PI*2); pCtx.fill();
      } else if (type === 'gradient') {
          const g = pCtx.createLinearGradient(0,0,0,40);
          g.addColorStop(0, color2);
          g.addColorStop(1, color1);
          pCtx.fillStyle = g;
          pCtx.fillRect(0,0,40,40);
      }
      const pattern = ctx.createPattern(pCanvas, 'repeat');
      patternsRef.current[key] = pattern;
      return pattern;
  };

  const drawChassisPath = (ctx: CanvasRenderingContext2D, car: CarModel, cw: number, ch: number) => {
      ctx.beginPath();
      const halfW = cw / 2;
      const halfH = ch / 2;

      // Better shapes with more complex curves
      if (car.shape === 'coupe' || !car.shape) {
          ctx.moveTo(-halfW, halfH * 0.5); 
          ctx.lineTo(-halfW, -halfH * 0.2);
          ctx.quadraticCurveTo(-halfW, -halfH * 0.9, -halfW * 0.4, -halfH * 0.9); // Roof rear
          ctx.lineTo(halfW * 0.1, -halfH * 0.9); // Roof top
          ctx.quadraticCurveTo(halfW * 0.8, -halfH * 0.7, halfW * 1.1, 0); // Windshield slope
          ctx.lineTo(halfW * 1.2, halfH * 0.5); // Nose
          ctx.lineTo(-halfW, halfH * 0.5); // Bottom
      } else if (car.shape === 'jeep') {
          ctx.moveTo(-halfW * 0.9, halfH * 0.5);
          ctx.lineTo(-halfW * 0.9, -halfH * 0.5); // Rear bumper
          ctx.lineTo(-halfW * 0.5, -halfH * 0.5); // Bed
          ctx.lineTo(-halfW * 0.5, -halfH * 1.6); // Cab rear
          ctx.lineTo(halfW * 0.6, -halfH * 1.6); // Cab roof
          ctx.lineTo(halfW * 0.6, -halfH * 0.2); // Windshield vertical
          ctx.lineTo(halfW * 1.1, -halfH * 0.2); // Hood
          ctx.lineTo(halfW * 1.1, halfH * 0.5);
          ctx.lineTo(-halfW * 0.9, halfH * 0.5);
      } else if (car.shape === 'racer') {
          ctx.moveTo(-halfW * 1.2, halfH * 0.2);
          ctx.lineTo(-halfW * 1.2, -halfH * 0.3); // Rear Wing support
          ctx.lineTo(-halfW * 0.5, -halfH * 0.5); // Engine cover
          ctx.lineTo(halfW * 0.3, -halfH * 0.5); 
          ctx.quadraticCurveTo(halfW * 1.0, -halfH * 0.3, halfW * 1.5, 0); // Nose slope
          ctx.lineTo(halfW * 1.5, halfH * 0.3); 
          ctx.lineTo(-halfW * 1.2, halfH * 0.2);
      } else if (car.shape === 'buggy') {
          ctx.moveTo(-halfW * 0.7, 0);
          ctx.lineTo(-halfW * 0.5, -halfH * 1.4); // Roll bar back
          ctx.lineTo(halfW * 0.4, -halfH * 1.4); // Roll bar top
          ctx.lineTo(halfW * 0.9, 0); // Roll bar front
          ctx.lineTo(halfW * 1.1, 0); // Hood
          ctx.lineTo(halfW * 0.9, halfH * 0.5);
          ctx.lineTo(-halfW * 0.9, halfH * 0.5);
          ctx.lineTo(-halfW * 0.7, 0);
      } else if (car.shape === 'van') {
          ctx.moveTo(-halfW * 0.9, halfH * 0.5);
          ctx.lineTo(-halfW * 0.9, -halfH * 1.3);
          ctx.lineTo(halfW * 0.7, -halfH * 1.3); // Roof
          ctx.quadraticCurveTo(halfW * 1.1, -halfH * 1.2, halfW * 1.1, -halfH * 0.2); // Front curve
          ctx.lineTo(halfW * 1.1, halfH * 0.5);
          ctx.lineTo(-halfW * 0.9, halfH * 0.5);
      } else if (car.shape === 'supercar') {
          ctx.moveTo(-halfW * 1.1, halfH * 0.5);
          ctx.lineTo(-halfW * 1.1, 0);
          ctx.lineTo(-halfW * 0.5, -halfH * 0.6); // Rear deck
          ctx.lineTo(halfW * 0.1, -halfH * 0.6); // Roof start
          ctx.quadraticCurveTo(halfW * 1.0, -halfH * 0.4, halfW * 1.4, 0); // Sleek nose
          ctx.lineTo(halfW * 1.45, halfH * 0.5);
          ctx.lineTo(-halfW * 1.1, halfH * 0.5);
      } else if (car.shape === 'bike') {
           ctx.moveTo(-halfW * 0.5, 0);
           ctx.lineTo(0, -halfH * 0.7); // Seat position
           ctx.lineTo(halfW * 0.4, -halfH * 0.4); // Tank
           ctx.lineTo(halfW * 0.3, 0);
           ctx.lineTo(-halfW * 0.5, 0);
      }
      ctx.closePath();
  };

  const drawCarDetails = (ctx: CanvasRenderingContext2D, car: CarModel, cw: number, ch: number) => {
      const halfW = cw / 2;
      const halfH = ch / 2;

      // 1. Headlights (with glow)
      ctx.save();
      ctx.translate(halfW, 0);

      const grad = ctx.createLinearGradient(0, 0, 150, 0);
      grad.addColorStop(0, 'rgba(255, 255, 200, 0.4)');
      grad.addColorStop(1, 'rgba(255, 255, 200, 0)');
      ctx.fillStyle = grad;
      ctx.beginPath(); ctx.moveTo(0, -5); ctx.lineTo(150, -40); ctx.lineTo(150, 40); ctx.lineTo(0, 5); ctx.fill();

      ctx.fillStyle = '#fef08a';
      ctx.shadowColor = '#fef08a'; ctx.shadowBlur = 10;
      if (car.shape === 'jeep' || car.shape === 'van') {
           ctx.fillRect(halfW * 0.05, -15, 5, 20);
      } else if (car.shape === 'bike') {
           ctx.beginPath(); ctx.arc(halfW * 0.3, -10, 8, 0, Math.PI*2); ctx.fill();
      } else {
           ctx.beginPath(); ctx.ellipse(halfW * 0.15, 0, 4, 12, 0, 0, Math.PI*2); ctx.fill();
      }
      ctx.restore();

      // 2. Windows - Gradient glass
      const glassGrad = ctx.createLinearGradient(0, -ch, 0, 0);
      glassGrad.addColorStop(0, '#38bdf8');
      glassGrad.addColorStop(1, '#1e293b');
      ctx.fillStyle = glassGrad;
      ctx.strokeStyle = '#334155'; ctx.lineWidth = 1;

      if (car.shape === 'coupe') {
          ctx.beginPath();
          ctx.moveTo(-halfW * 0.3, -halfH * 0.75);
          ctx.lineTo(halfW * 0.1, -halfH * 0.75);
          ctx.lineTo(halfW * 0.5, -halfH * 0.1);
          ctx.lineTo(-halfW * 0.3, -halfH * 0.1);
          ctx.fill(); ctx.stroke();
      } else if (car.shape === 'supercar') {
          ctx.beginPath();
          ctx.moveTo(-halfW * 0.2, -halfH * 0.5);
          ctx.lineTo(halfW * 0.2, -halfH * 0.5);
          ctx.lineTo(halfW * 0.6, -halfH * 0.1);
          ctx.lineTo(-halfW * 0.4, -halfH * 0.1);
          ctx.fill(); ctx.stroke();
      } else if (car.shape === 'jeep') {
          ctx.fillRect(-halfW * 0.4, -halfH * 1.3, cw * 0.35, ch * 0.5); // Side
          ctx.fillRect(halfW * 0.1, -halfH * 1.3, cw * 0.35, ch * 0.5); // Front
      } else if (car.shape === 'van') {
          ctx.fillRect(-halfW * 0.8, -halfH * 1.1, cw * 0.35, ch * 0.5);
          ctx.fillRect(-halfW * 0.3, -halfH * 1.1, cw * 0.45, ch * 0.5);
      }

      // 3. Extra Details
      ctx.fillStyle = '#111';
      if (car.shape === 'racer' || car.shape === 'supercar') {
          // Spoiler
          ctx.fillStyle = car.bodyColor;
          ctx.beginPath();
          ctx.moveTo(-halfW * 1.1, -halfH * 0.2);
          ctx.lineTo(-halfW * 1.25, -halfH * 1.4);
          ctx.lineTo(-halfW * 0.7, -halfH * 1.4);
          ctx.lineTo(-halfW * 0.6, -halfH * 0.2);
          ctx.fill(); 
          ctx.stroke();
          // Wing
          ctx.fillStyle = '#111';
          ctx.fillRect(-halfW * 1.3, -halfH * 1.5, cw * 0.6, 6);
      } else if (car.shape === 'buggy') {
          ctx.strokeStyle = '#64748b';
          ctx.lineWidth = 3;
          ctx.beginPath();
          ctx.moveTo(-halfW * 0.7, 0); ctx.lineTo(halfW * 0.9, 0); 
          ctx.moveTo(-halfW * 0.5, -halfH * 1.4); ctx.lineTo(halfW * 0.4, -halfH * 1.4);
          ctx.lineTo(halfW * 0.9, 0);
          ctx.stroke();
      }

      // 4. Exhaust
      const exhaustX = -halfW * 1.0;
      const exhaustY = halfH * 0.3;
      ctx.fillStyle = '#444';
      if (car.shape !== 'bike') {
          ctx.fillRect(exhaustX - 8, exhaustY, 15, 8);
          ctx.fillStyle = '#000';
          ctx.beginPath(); ctx.arc(exhaustX - 8, exhaustY + 4, 3, 0, Math.PI*2); ctx.fill();
      }

      if (Math.random() > 0.7 && !isMenuBackground && Math.abs(carRef.current.bodies[0].velocity.x) > 1) {
          spawnParticles(
              carRef.current.bodies[0].position.x + exhaustX, 
              carRef.current.bodies[0].position.y + exhaustY + 4, 
              1, 'smoke'
          );
      }
  };

  const drawWheel = (ctx: CanvasRenderingContext2D, x: number, y: number, r: number, angle: number, color: string) => {
      ctx.save();
      ctx.translate(x, y);
      ctx.rotate(angle);

      // Tire
      ctx.beginPath(); ctx.arc(0, 0, r, 0, Math.PI * 2); 
      ctx.fillStyle = '#1c1917'; ctx.fill(); // Dark rubber

      // Detailed Tread
      ctx.strokeStyle = '#292524'; ctx.lineWidth = 4;
      ctx.setLineDash([5, 8]);
      ctx.beginPath(); ctx.arc(0,0, r-2, 0, Math.PI*2); ctx.stroke();
      ctx.setLineDash([]);

      // Rim
      const rimR = r * 0.65;
      ctx.beginPath(); ctx.arc(0, 0, rimR, 0, Math.PI * 2);
      ctx.fillStyle = color; ctx.fill();
      ctx.strokeStyle = '#444'; ctx.lineWidth = 2; ctx.stroke();

      // Spokes
      ctx.strokeStyle = '#000'; ctx.lineWidth = 3; ctx.lineCap = 'round';
      const spokes = 5;
      for (let i = 0; i < spokes; i++) {
          ctx.rotate((Math.PI * 2) / spokes);
          ctx.beginPath(); ctx.moveTo(0, 0); ctx.lineTo(0, rimR - 3); ctx.stroke();
      }

      // Center Hub
      ctx.beginPath(); ctx.arc(0, 0, r * 0.15, 0, Math.PI * 2);
      ctx.fillStyle = '#555'; ctx.fill();
      ctx.beginPath(); ctx.arc(0, 0, r * 0.08, 0, Math.PI * 2);
      ctx.fillStyle = '#222'; ctx.fill();

      ctx.restore();
  };

  const drawSuspension = (ctx: CanvasRenderingContext2D, chassisBody: any, wheelBody: any, offsetX: number, offsetY: number) => {
      const cAngle = chassisBody.angle;
      const worldOffsetX = offsetX * Math.cos(cAngle) - offsetY * Math.sin(cAngle);
      const worldOffsetY = offsetX * Math.sin(cAngle) + offsetY * Math.cos(cAngle);

      const p1 = { x: chassisBody.position.x + worldOffsetX, y: chassisBody.position.y + worldOffsetY };
      const p2 = { x: wheelBody.position.x, y: wheelBody.position.y };

      const dist = Math.hypot(p2.x - p1.x, p2.y - p1.y);
      const angle = Math.atan2(p2.y - p1.y, p2.x - p1.x);

      ctx.save();
      ctx.translate(p1.x, p1.y);
      ctx.rotate(angle);

      // Upper strut
      ctx.strokeStyle = '#444'; ctx.lineWidth = 6;
      ctx.beginPath(); ctx.moveTo(0, 0); ctx.lineTo(dist/2, 0); ctx.stroke();

      // Lower strut
      ctx.strokeStyle = '#999'; ctx.lineWidth = 4;
      ctx.beginPath(); ctx.moveTo(dist/2, 0); ctx.lineTo(dist, 0); ctx.stroke();

      // Coil
      ctx.strokeStyle = '#dc2626'; ctx.lineWidth = 2.5;
      ctx.beginPath();
      ctx.moveTo(0, 0);
      const zigs = 8;
      for(let i=0; i<=zigs; i++) {
          ctx.lineTo((dist / zigs) * i, i % 2 === 0 ? -5 : 5);
      }
      ctx.stroke();
      ctx.restore();
  };

  const drawCloud = (ctx: CanvasRenderingContext2D, cloud: Cloud) => {
      ctx.save();
      ctx.translate(cloud.x, cloud.y);
      ctx.scale(cloud.scale, cloud.scale);

      ctx.fillStyle = 'rgba(255,255,255,0.7)';

      ctx.beginPath();
      ctx.arc(0, 0, 30, 0, Math.PI * 2);
      ctx.arc(35, 5, 40, 0, Math.PI * 2);
      ctx.arc(-35, 5, 35, 0, Math.PI * 2);
      ctx.arc(15, -25, 30, 0, Math.PI * 2);
      ctx.arc(-15, -25, 30, 0, Math.PI * 2);

      ctx.fill();
      ctx.restore();
  };

  const drawTree = (ctx: CanvasRenderingContext2D, type: number, seed: number) => {
    // Trunk
    ctx.fillStyle = COLORS.treeTrunk;
    const trunkW = 12 + seed * 4;
    const trunkH = 40 + seed * 20;
    ctx.fillRect(-trunkW/2, -trunkH, trunkW, trunkH);

    // Leaves
    if (type === 6) { // Pine
        ctx.fillStyle = COLORS.treeLeafDark;
        ctx.beginPath();
        ctx.moveTo(-40, -trunkH + 10);
        ctx.lineTo(0, -trunkH - 100 - seed * 50);
        ctx.lineTo(40, -trunkH + 10);
        ctx.fill();

        ctx.fillStyle = COLORS.treeLeafLight;
        ctx.beginPath();
        ctx.moveTo(-30, -trunkH - 20);
        ctx.lineTo(0, -trunkH - 100 - seed * 50);
        ctx.lineTo(30, -trunkH - 20);
        ctx.fill();
    } else { // Round
        ctx.fillStyle = COLORS.treeLeafDark;
        ctx.beginPath();
        ctx.arc(0, -trunkH - 20, 40 + seed * 10, 0, Math.PI * 2);
        ctx.fill();

        ctx.fillStyle = COLORS.treeLeafLight;
        ctx.beginPath();
        ctx.arc(-10, -trunkH - 30, 30 + seed * 10, 0, Math.PI * 2);
        ctx.fill();
    }
  };

  const drawRock = (ctx: CanvasRenderingContext2D, seed: number) => {
      ctx.fillStyle = COLORS.boulder;
      ctx.beginPath();
      ctx.moveTo(-20 - seed * 10, 0);
      ctx.lineTo(-15 - seed * 5, -20 - seed * 15);
      ctx.lineTo(10 + seed * 5, -25 - seed * 10);
      ctx.lineTo(25 + seed * 10, 0);
      ctx.fill();

      // Detail
      ctx.fillStyle = COLORS.boulderDark;
      ctx.beginPath();
      ctx.moveTo(-10, -5);
      ctx.lineTo(0, -15);
      ctx.lineTo(10, -5);
      ctx.fill();
  };

  const drawBush = (ctx: CanvasRenderingContext2D, seed: number) => {
     ctx.fillStyle = COLORS.bushDark;
     ctx.beginPath();
     ctx.arc(-15, -10, 15 + seed * 5, 0, Math.PI * 2);
     ctx.arc(15, -10, 12 + seed * 5, 0, Math.PI * 2);
     ctx.arc(0, -20, 18 + seed * 5, 0, Math.PI * 2);
     ctx.fill();

     ctx.fillStyle = COLORS.bushLight;
     ctx.beginPath();
     ctx.arc(0, -20, 10 + seed * 3, 0, Math.PI * 2);
     ctx.fill();
  };

  const animate = useCallback(() => {
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d', { alpha: false });
    if (!canvas || !ctx || gameStateRef.current.isGameOver) {
        requestRef.current = requestAnimationFrame(animate);
        return;
    }

    if (!pausedRef.current) {
        Matter.Engine.update(engineRef.current, 1000 / 60);
        const chassis = carRef.current.bodies.find((b: any) => b.label === 'chassis');
        const wheelB = carRef.current.bodies.find((b: any) => b.label === 'wheelBack');
        const wheelF = carRef.current.bodies.find((b: any) => b.label === 'wheelFront');

        const { keys } = gameStateRef.current;
        const speedRatio = Matter.Vector.magnitude(chassis.velocity) / 25;
        const isGrounded = wheelGroundContacts.current > 0;

        if (!isMenuBackground) {
            soundManagerRef.current?.updateContinuous(speedRatio, isGrounded, keys.right && !isOutOfFuelRef.current);
            if (keys.right && !isOutOfFuelRef.current) {
                fuelRef.current -= config.FUEL_CONSUMPTION;
                if (fuelRef.current <= 0) {
                    fuelRef.current = 0; isOutOfFuelRef.current = true;
                    setNotification({ text: "OUT OF FUEL", id: Date.now() });
                    setTimeout(() => { if (!gameStateRef.current.isGameOver) onGameOver(gameStateRef.current.distance, gameStateRef.current.coins); }, 3000);
                }
                const power = selectedCar.acceleration;
                if (selectedCar.driveTrain !== 'FWD') Matter.Body.setAngularVelocity(wheelB, Math.min(wheelB.angularVelocity + power, selectedCar.speed));
                if (selectedCar.driveTrain !== 'RWD') Matter.Body.setAngularVelocity(wheelF, Math.min(wheelF.angularVelocity + power, selectedCar.speed));
                if (chassis.angularVelocity > -config.MAX_ROTATION_SPEED) Matter.Body.setAngularVelocity(chassis, chassis.angularVelocity - (isGrounded ? config.GROUND_ROTATION_SPEED : config.AIR_ROTATION_SPEED));
            } else if (keys.left) {
                 if (selectedCar.driveTrain !== 'FWD') Matter.Body.setAngularVelocity(wheelB, Math.max(wheelB.angularVelocity - 0.1, -selectedCar.speed/2));
                 if (selectedCar.driveTrain !== 'RWD') Matter.Body.setAngularVelocity(wheelF, Math.max(wheelF.angularVelocity - 0.1, -selectedCar.speed/2));
                 if (chassis.angularVelocity < config.MAX_ROTATION_SPEED) Matter.Body.setAngularVelocity(chassis, chassis.angularVelocity + (isGrounded ? config.GROUND_ROTATION_SPEED : config.AIR_ROTATION_SPEED));
            }
        } else {
            Matter.Body.setAngularVelocity(wheelB, 0.4); Matter.Body.setAngularVelocity(wheelF, 0.4);
            if (chassis.position.y > 500) Matter.Body.setPosition(chassis, { x: 200, y: -100 });
        }

        cameraPosRef.current = { x: chassis.position.x, y: chassis.position.y };
        if (chassis.position.x > lastChunkDataRef.current.endX - config.RENDER_DISTANCE) addChunk(lastChunkDataRef.current.endX);
        gameStateRef.current.distance = Math.max(0, Math.floor((chassis.position.x - 200) / 10));

        if (hudDistanceRef.current) hudDistanceRef.current.innerText = `${gameStateRef.current.distance}`;
        if (hudCoinsRef.current) hudCoinsRef.current.innerText = `${gameStateRef.current.coins}`;
        if (hudFuelBarRef.current) hudFuelBarRef.current.style.width = `${(fuelRef.current / config.MAX_FUEL) * 100}%`;
    }

    // --- RENDERING ---
    const zoom = cameraZoomRef.current;
    const vH = config.BASE_VIEWPORT_HEIGHT * zoom;
    const vW = (canvas.width / canvas.height) * vH; 
    const scale = canvas.height / vH;

    const camX = cameraPosRef.current.x - vW * 0.3;
    const camY = cameraPosRef.current.y - vH * 0.6;

    ctx.setTransform(scale, 0, 0, scale, -camX * scale, -camY * scale);

    // Sky
    const skyGrad = ctx.createLinearGradient(camX, camY, camX, camY + vH);
    skyGrad.addColorStop(0, selectedMap.skyColorStart); skyGrad.addColorStop(1, selectedMap.skyColorEnd);
    ctx.fillStyle = skyGrad; ctx.fillRect(camX, camY, vW, vH);

    // Sun/Moon Glow
    if (selectedMap.backgroundType !== 'moon') {
        const sunGrad = ctx.createRadialGradient(camX + vW - 100, camY + 100, 20, camX + vW - 100, camY + 100, 200);
        sunGrad.addColorStop(0, 'rgba(255, 255, 200, 0.6)');
        sunGrad.addColorStop(1, 'rgba(255, 255, 200, 0)');
        ctx.fillStyle = sunGrad; ctx.fillRect(camX, camY, vW, vH/2);
    }

    if (starsRef.current.length > 0) {
        ctx.fillStyle = 'white';
        starsRef.current.forEach(s => {
            const px = s.x + camX * 0.85; 
            if (px > camX && px < camX + vW) {
                ctx.globalAlpha = s.opacity; ctx.beginPath(); ctx.arc(px, s.y, s.r, 0, Math.PI*2); ctx.fill();
            }
        });
        ctx.globalAlpha = 1;
    }

    cloudsRef.current.forEach(c => {
        if (c.x > camX - 400 && c.x < camX + vW + 400) {
            drawCloud(ctx, c);
        }
    });

    const groundPat = getPattern(ctx, 'ground', selectedMap.groundColor, selectedMap.groundDarkColor);
    ctx.fillStyle = groundPat || selectedMap.groundColor;

    chunksRef.current.forEach(chunk => {
        if (chunk.endX < camX || chunk.pathData[0].x > camX + vW) return;

        ctx.beginPath(); ctx.moveTo(chunk.pathData[0].x, chunk.pathData[0].y);
        chunk.pathData.forEach(p => ctx.lineTo(p.x, p.y));
        ctx.lineTo(chunk.endX, chunk.endY + 1000); ctx.lineTo(chunk.pathData[0].x, chunk.pathData[0].y + 1000);
        ctx.fill(); 

        if (selectedMap.backgroundType === 'earth') {
             ctx.strokeStyle = COLORS.grassDetail; ctx.lineWidth = 10;
        } else if (selectedMap.backgroundType === 'moon') {
             ctx.strokeStyle = '#94a3b8'; ctx.lineWidth = 6;
        } else {
             ctx.strokeStyle = '#475569'; ctx.lineWidth = 8;
        }
        ctx.beginPath();
        chunk.pathData.forEach((p, i) => {
            if (i===0) ctx.moveTo(p.x, p.y);
            else ctx.lineTo(p.x, p.y);
        });
        ctx.stroke();

        chunk.decorations.forEach(d => {
            if (d.x < camX - 100 || d.x > camX + vW + 100) return;
            ctx.save(); ctx.translate(d.x, d.y); ctx.rotate(d.angle); ctx.scale(d.scale, d.scale);

            if (d.type === 5) { 
                ctx.fillStyle = 'white'; ctx.fillRect(0,-200,6,200); 
                ctx.fillStyle = '#ef4444'; ctx.beginPath(); ctx.moveTo(6,-200); ctx.lineTo(70,-175); ctx.lineTo(6,-150); ctx.fill();
            } else if (d.type === 3) { 
                ctx.fillStyle = COLORS.lampPost; ctx.fillRect(-2,-80,4,80); 
                ctx.fillStyle = COLORS.lampLight; ctx.beginPath(); ctx.arc(10,-80,6,0,Math.PI*2); ctx.fill();
                ctx.fillStyle = COLORS.lampGlow; ctx.beginPath(); ctx.arc(10,-80,20,0,Math.PI*2); ctx.fill();
            } else if (d.type === 4) { 
                ctx.fillStyle = '#78350f'; ctx.fillRect(-2,-20,4,20);
                ctx.fillRect(-20,-15,40,4);
            } else if (d.type === 6 || d.type === 7) { 
                drawTree(ctx, d.type, d.seed);
            } else if (d.type === 8) { 
                drawRock(ctx, d.seed);
            } else if (d.type === 9) { 
                drawBush(ctx, d.seed);
            } else if (selectedMap.backgroundType === 'earth') {
                 ctx.strokeStyle = COLORS.grassDetail; ctx.lineWidth = 2; 
                 ctx.beginPath(); 
                 ctx.moveTo(0,0); ctx.lineTo(-3, -8 - d.seed * 5);
                 ctx.moveTo(0,0); ctx.lineTo(3, -6 - d.seed * 5);
                 ctx.stroke();
            }
            ctx.restore();
        });

        chunk.coinBodies.forEach(b => {
            if (!collectedCoinIdsRef.current.has(b.id) && b.position.x > camX - 50 && b.position.x < camX + vW + 50) {
                ctx.save(); ctx.translate(b.position.x, b.position.y);
                const pulse = Math.sin(Date.now() / 200) * 0.1 + 1;
                ctx.scale(pulse, pulse);
                ctx.fillStyle = COLORS.coinOuter; ctx.beginPath(); ctx.arc(0,0,config.COIN_SIZE,0,Math.PI*2); ctx.fill();
                ctx.fillStyle = COLORS.coinInner; ctx.beginPath(); ctx.arc(0,0,config.COIN_SIZE*0.7,0,Math.PI*2); ctx.fill();
                ctx.fillStyle = '#fff'; ctx.font = 'bold 12px monospace'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle'; ctx.fillText('$', 0, 1);
                ctx.restore();
            }
        });

        chunk.fuelBodies.forEach(b => {
            if (!collectedFuelIdsRef.current.has(b.id) && b.position.x > camX - 50 && b.position.x < camX + vW + 50) {
                ctx.save(); ctx.translate(b.position.x, b.position.y);
                const pulse = Math.sin(Date.now() / 300) * 0.1 + 1;
                ctx.scale(pulse, pulse);
                ctx.fillStyle = COLORS.fuelCan; 
                ctx.fillRect(-10, -15, 20, 30);
                ctx.fillStyle = COLORS.fuelCanCap;
                ctx.fillRect(-6, -18, 12, 3);
                ctx.font = 'bold 10px sans-serif'; ctx.fillStyle = 'white'; ctx.fillText('FUEL', -10, 5);
                ctx.restore();
            }
        });
    });

    // --- CAR RENDER ---
    const chassis = carRef.current.bodies.find((b: any) => b.label === 'chassis');
    const wheelB = carRef.current.bodies.find((b: any) => b.label === 'wheelBack');
    const wheelF = carRef.current.bodies.find((b: any) => b.label === 'wheelFront');
    const cw = selectedCar.width || config.CAR_WIDTH; 
    const ch = selectedCar.height || config.CAR_HEIGHT;
    const wr = selectedCar.wheelSize || config.WHEEL_SIZE;

    // Draw Suspension
    const wheelOffsetX = -cw / 2 + wr;
    const wheelOffsetY = ch / 2;
    drawSuspension(ctx, chassis, wheelB, wheelOffsetX, wheelOffsetY);
    drawSuspension(ctx, chassis, wheelF, -wheelOffsetX, wheelOffsetY);

    // Draw Chassis
    ctx.save(); ctx.translate(chassis.position.x, chassis.position.y); ctx.rotate(chassis.angle);

    ctx.shadowColor = 'rgba(0,0,0,0.5)'; ctx.shadowBlur = 10;
    let bodyFill: string | CanvasPattern = selectedCar.bodyColor;
    if (selectedCar.texture !== 'plain') bodyFill = getPattern(ctx, selectedCar.texture, selectedCar.bodyColor, selectedCar.textureColor2) || bodyFill;

    if (selectedCar.imageUrl) {
        // ... (image logic from previous turn)
    }

    ctx.fillStyle = bodyFill;
    ctx.strokeStyle = 'rgba(0,0,0,0.6)'; ctx.lineWidth = 2;

    drawChassisPath(ctx, selectedCar, cw, ch);
    ctx.fill(); 
    ctx.shadowBlur = 0; 
    ctx.stroke();

    drawCarDetails(ctx, selectedCar, cw, ch);

    ctx.restore();

    // Draw Wheels (AFTER CHASSIS) - Ensures Z-Index correctness
    [wheelB, wheelF].forEach(w => {
        drawWheel(ctx, w.position.x, w.position.y, wr, w.angle, selectedCar.wheelColor);
    });

    particlesRef.current.forEach(p => {
        if (p.active) {
            ctx.fillStyle = p.type === 'spark' ? COLORS.particleSpark : 
                            p.type === 'smoke' ? COLORS.particleSmoke : COLORS.particleDust; 
            ctx.globalAlpha = p.life / p.maxLife;
            ctx.beginPath(); 
            if (p.type === 'smoke') {
                const r = 4 + (1 - p.life/p.maxLife) * 8;
                ctx.arc(p.x, p.y, r, 0, Math.PI*2);
            } else {
                ctx.arc(p.x, p.y, 2.5, 0, Math.PI*2); 
            }
            ctx.fill();
            p.x += p.vx; p.y += p.vy; 
            if (p.type !== 'smoke') p.vy += 0.2; 
            else { p.vx *= 0.95; p.vy -= 0.05; } 
            p.life--; if (p.life <= 0) p.active = false;
        }
    });
    ctx.globalAlpha = 1;

    const now = performance.now(); frameCountRef.current++;
    if (now - lastFpsTimeRef.current >= 500) {
        const fps = Math.round((frameCountRef.current * 1000) / (now - lastFpsTimeRef.current));
        if (hudFpsRef.current) hudFpsRef.current.innerText = `${fps} FPS`;
        lastFpsTimeRef.current = now; frameCountRef.current = 0;
    }

    requestRef.current = requestAnimationFrame(animate);
  }, [config, selectedCar, selectedMap, onGameOver, onLevelComplete, isMenuBackground]);

  return (
    <div ref={containerRef} className={`relative w-full h-full bg-slate-900 overflow-hidden select-none ${isMenuBackground ? 'opacity-40 pointer-events-none' : ''}`}>
      {!isMenuBackground && (
          <>
            <div className="absolute top-4 right-4 z-30 flex gap-2">
                <div ref={hudFpsRef} className="font-mono text-xs text-emerald-500 bg-black/60 px-2 py-1 rounded">60 FPS</div>
                <button onClick={() => { pausedRef.current = !pausedRef.current; setIsPaused(!isPaused); }} className="w-10 h-10 bg-black/60 text-white rounded flex items-center justify-center border border-white/20 hover:bg-white/10 active:scale-95 transition-all">
                    {isPaused ? "▶" : "⏸"}
                </button>
            </div>

            {isPaused && (
                <div className="absolute inset-0 z-40 flex flex-col items-center justify-center bg-black/80 backdrop-blur-md animate-fade-in">
                    <div className="p-8 bg-neutral-900/90 border border-neutral-700 rounded-2xl shadow-2xl flex flex-col items-center gap-6 min-w-[300px]">
                        <h2 className="text-4xl font-black italic text-white tracking-widest uppercase border-b-4 border-amber-500 pb-2 mb-2">
                            Paused
                        </h2>

                        <div className="flex flex-col gap-3 w-full">
                            <button 
                                onClick={handleResume}
                                className="w-full py-4 bg-emerald-600 hover:bg-emerald-500 text-white font-black italic uppercase tracking-wider rounded-lg shadow-lg hover:scale-[1.02] active:scale-95 transition-all flex items-center justify-center gap-2"
                            >
                                <span>▶</span> Resume
                            </button>

                            <button 
                                onClick={onRestart}
                                className="w-full py-4 bg-neutral-700 hover:bg-neutral-600 text-white font-bold uppercase tracking-wider rounded-lg shadow-lg hover:scale-[1.02] active:scale-95 transition-all flex items-center justify-center gap-2"
                            >
                                <span>↺</span> Restart
                            </button>

                            <button 
                                onClick={onExit}
                                className="w-full py-4 bg-red-900/50 border-2 border-red-900/50 hover:bg-red-900 hover:border-red-800 text-red-100 font-bold uppercase tracking-wider rounded-lg shadow-lg hover:scale-[1.02] active:scale-95 transition-all flex items-center justify-center gap-2"
                            >
                                <span>✕</span> Main Menu
                            </button>
                        </div>
                    </div>
                </div>
            )}

            <div className="absolute top-6 left-6 z-10 pointer-events-none flex flex-col gap-2">
                <div className="bg-black/60 px-4 py-2 rounded-xl border border-white/10 flex flex-col">
                    <span className="text-[10px] text-neutral-400 uppercase font-bold">Distance</span>
                    <span ref={hudDistanceRef} className="text-2xl font-mono font-bold text-white">0</span>
                </div>
                <div className="bg-black/60 px-4 py-2 rounded-xl border border-amber-500/20 flex gap-3 items-center">
                    <div className="w-6 h-6 rounded-full bg-amber-500 text-black flex items-center justify-center text-xs font-bold">$</div>
                    <span ref={hudCoinsRef} className="text-xl font-mono font-bold text-white">0</span>
                </div>
                <div className="w-48 h-1.5 bg-neutral-800 rounded-full mt-2 overflow-hidden border border-white/5">
                    <div ref={hudFuelBarRef} className="h-full bg-red-500 transition-all duration-200" style={{ width: '100%' }} />
                </div>
            </div>
            {notification && (
                <div className="absolute top-1/3 left-1/2 -translate-x-1/2 z-40 text-4xl font-black italic text-white animate-bounce drop-shadow-lg">{notification.text}</div>
            )}
            <div className="absolute bottom-10 left-10 right-10 z-30 flex justify-between">
                 <button 
                    className="w-24 h-24 rounded-full bg-black/40 border-2 border-white/10 active:bg-white/10 active:border-red-500/50 transition-all text-white font-black italic text-xl" 
                    onMouseDown={() => gameStateRef.current.keys.left = true} 
                    onMouseUp={() => gameStateRef.current.keys.left = false} 
                    onMouseLeave={() => gameStateRef.current.keys.left = false}
                    onTouchStart={(e) => { e.preventDefault(); gameStateRef.current.keys.left = true; }} 
                    onTouchEnd={(e) => { e.preventDefault(); gameStateRef.current.keys.left = false; }}
                >
                    BRAKE
                </button>
                 <button 
                    className="w-24 h-24 rounded-full bg-black/40 border-2 border-white/10 active:bg-white/10 active:border-emerald-500/50 transition-all text-white font-black italic text-xl" 
                    onMouseDown={() => gameStateRef.current.keys.right = true} 
                    onMouseUp={() => gameStateRef.current.keys.right = false} 
                    onMouseLeave={() => gameStateRef.current.keys.right = false}
                    onTouchStart={(e) => { e.preventDefault(); gameStateRef.current.keys.right = true; }} 
                    onTouchEnd={(e) => { e.preventDefault(); gameStateRef.current.keys.right = false; }}
                >
                    GAS
                </button>
            </div>
          </>
      )}
      <canvas ref={canvasRef} className="w-full h-full" style={{ imageRendering: config.PIXELATED ? 'pixelated' : 'auto' }} />
    </div>
  );
};

export default Game;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import Game from './components/Game';
import MainMenu from './components/MainMenu';
import GameOver from './components/GameOver';
import CarSelection from './components/CarSelection';
import MapSelection from './components/MapSelection';
import MapMaker from './components/MapMaker';
import CarMaker from './components/CarMaker';
import LevelSelect from './components/LevelSelect';
import LoadingScreen from './components/LoadingScreen';
import { GameState, CarModel, GameConfig, MapConfig, GameMode, LevelConfig } from './types';
import { CAR_MODELS, GAME_CONFIG, MAPS, LEVELS } from './constants';
import { SoundManager } from './utils/audio';

const CONFIG_STORAGE_KEY = 'hill_climber_config_v1';

const App: React.FC = () => {
  // Start in SPLASH state to force user interaction and music load
  const [gameState, setGameState] = useState<GameState>(GameState.SPLASH);
  const [score, setScore] = useState(0); // Distance
  const [coins, setCoins] = useState(0);
  const [bestScore, setBestScore] = useState(0);
  const [isMusicReady, setIsMusicReady] = useState(false);
  const [isInitializing, setIsInitializing] = useState(false);

  // Game Configuration State (Persisted)
  const [gameConfig, setGameConfig] = useState<GameConfig>(GAME_CONFIG);

  // Selection State
  const [selectedCar, setSelectedCar] = useState<CarModel>(CAR_MODELS[0]);
  const [selectedMap, setSelectedMap] = useState<MapConfig>(MAPS[0]);

  // Mode State
  const [gameMode, setGameMode] = useState<GameMode>('INFINITE');
  const [currentLevel, setCurrentLevel] = useState<LevelConfig | undefined>(undefined);

  const [isGarageOpen, setIsGarageOpen] = useState(false);
  const [isMapSelectOpen, setIsMapSelectOpen] = useState(false);
  const [isLevelSelectOpen, setIsLevelSelectOpen] = useState(false);

  // Load Config on Mount
  useEffect(() => {
    const savedConfig = localStorage.getItem(CONFIG_STORAGE_KEY);
    if (savedConfig) {
        try {
            const parsed = JSON.parse(savedConfig);
            setGameConfig(prev => ({ ...prev, ...parsed }));
        } catch (e) {
            console.error("Failed to load config", e);
        }
    }
  }, []);

  // Preload Music on Mount
  useEffect(() => {
    SoundManager.preload();

    // Check if already ready (rare but possible)
    if (SoundManager.isMusicReady()) {
        setIsMusicReady(true);
    }

    const handleMusicReady = () => setIsMusicReady(true);
    window.addEventListener('music-ready', handleMusicReady);
    return () => window.removeEventListener('music-ready', handleMusicReady);
  }, []);

  // Save Config on Change
  useEffect(() => {
    localStorage.setItem(CONFIG_STORAGE_KEY, JSON.stringify(gameConfig));
  }, [gameConfig]);

  // Audio Volume Logic
  useEffect(() => {
    if (gameState === GameState.MENU) {
        SoundManager.setMusicVolume(0.8); 
    } else if (gameState === GameState.PLAYING) {
        SoundManager.setMusicVolume(0.5); 
    }
  }, [gameState]);

  const handleSplashStart = useCallback(() => {
      setIsInitializing(true);

      // Initialize Audio Context (requires user gesture)
      SoundManager.init();

      // If music is ready, proceed immediately
      if (SoundManager.isMusicReady()) {
          SoundManager.startMusic();
          setGameState(GameState.MENU);
          setIsInitializing(false);
      } else {
          // If not ready, we are now in "Initializing" state showing a spinner
          // The useEffect listening for 'music-ready' will eventually trigger a state update
          // But we need a separate effect to watch `isMusicReady` when `isInitializing` is true
      }
  }, []);

  // Watch for music readiness after user clicked start
  useEffect(() => {
      if (isInitializing && isMusicReady) {
          SoundManager.startMusic();
          setGameState(GameState.MENU);
          setIsInitializing(false);
      }
  }, [isInitializing, isMusicReady]);

  const updateConfig = useCallback((key: keyof GameConfig, value: any) => {
      setGameConfig(prev => ({ ...prev, [key]: value }));
  }, []);

  const resetConfig = useCallback(() => {
      setGameConfig(GAME_CONFIG);
  }, []);

  const startGame = useCallback((mode: GameMode) => {
      setGameMode(mode);
      if (mode === 'LEVELS') {
          setIsLevelSelectOpen(true);
      } else {
          setScore(0);
          setCoins(0);
          setGameState(GameState.LOADING);
      }
  }, []);

  const startLevel = useCallback((levelId: number) => {
      const level = LEVELS.find(l => l.id === levelId);
      if (level) {
          setCurrentLevel(level);
          setScore(0);
          setCoins(0);
          setIsLevelSelectOpen(false);
          setGameState(GameState.LOADING);
      }
  }, []);

  const handleGameReady = useCallback(() => {
      // Small delay to ensure smooth transition from loading screen
      setTimeout(() => {
          setGameState(GameState.PLAYING);
      }, 500);
  }, []);

  const handleGameOver = useCallback((distance: number, collectedCoins: number) => {
    setScore(distance);
    setCoins(collectedCoins);
    if (gameMode === 'INFINITE' && distance > bestScore) {
      setBestScore(distance);
    }
    setGameState(GameState.GAME_OVER);
  }, [gameMode, bestScore]); 

  const handleLevelComplete = useCallback((collectedCoins: number) => {
      setCoins(collectedCoins);
      setGameState(GameState.LEVEL_COMPLETE);
  }, []);

  const handleRestart = useCallback(() => {
      if (gameMode === 'LEVELS' && currentLevel) {
          startLevel(currentLevel.id);
      } else {
          startGame('INFINITE');
      }
  }, [gameMode, currentLevel, startLevel, startGame]);

  // Helpers for background game to ensure stable references
  const noOp = useCallback(() => {}, []);

  // Merge Base Config with Map Overrides for the active game session
  const activeConfig = useMemo(() => {
      return { ...gameConfig, ...selectedMap.configOverrides };
  }, [gameConfig, selectedMap]);

  return (
    <div className="w-screen h-screen overflow-hidden font-sans select-none">

      {/* SPLASH SCREEN */}
      {gameState === GameState.SPLASH && (
        <div className="absolute inset-0 z-[100] bg-black flex flex-col items-center justify-center cursor-pointer" onClick={!isInitializing ? handleSplashStart : undefined}>
            {/* Background elements */}
            <div className="absolute inset-0 bg-gradient-to-b from-slate-900 to-black opacity-90"></div>
            <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-amber-900/20 via-black to-black"></div>

            <div className="relative z-10 flex flex-col items-center p-8 animate-fade-in text-center">
                 <h1 className="text-7xl font-black italic tracking-tighter text-transparent bg-clip-text bg-gradient-to-r from-amber-200 via-yellow-500 to-amber-700 drop-shadow-[0_0_30px_rgba(245,158,11,0.5)] mb-2">
                    HILL CLIMBER
                 </h1>
                 <p className="text-neutral-500 font-mono tracking-[0.5em] text-sm uppercase mb-16">Extreme Physics Engine</p>

                 {!isInitializing ? (
                     <div className="group flex flex-col items-center gap-2 animate-pulse">
                         <span className="text-3xl font-bold text-white group-hover:text-amber-400 transition-colors tracking-widest uppercase">Click To Start</span>
                         <span className="text-[10px] text-neutral-600 uppercase">Enable Audio & Graphics</span>
                     </div>
                 ) : (
                    <div className="flex flex-col items-center gap-4">
                        <div className="w-12 h-12 border-4 border-neutral-800 border-t-amber-500 rounded-full animate-spin"></div>
                        <span className="text-sm font-mono text-amber-500 tracking-widest uppercase animate-pulse">
                            {isMusicReady ? 'Initializing Engine...' : 'Generating Soundtrack...'}
                        </span>
                    </div>
                 )}
            </div>

            <div className="absolute bottom-8 text-neutral-800 text-xs font-mono">v2.1 • React • MatterJS • WebAudio</div>
        </div>
      )}

      {/* Background Game Rendering for Menu (Hidden during Splash) */}
      {gameState !== GameState.SPLASH && gameState === GameState.MENU && (
        <div className="absolute inset-0 z-0">
          <Game 
              mode="INFINITE"
              selectedCar={selectedCar}
              selectedMap={selectedMap}
              config={activeConfig}
              onGameOver={noOp} 
              onLevelComplete={noOp}
              onUpdateConfig={noOp}
              onResetConfig={noOp}
              onExit={noOp}
              onRestart={noOp}
              isMenuBackground={true}
              onReady={noOp} 
          />
        </div>
      )}

      {gameState === GameState.MENU && (
        <MainMenu 
          onStart={startGame} 
          onOpenGarage={() => setIsGarageOpen(true)}
          onOpenMapSelect={() => setIsMapSelectOpen(true)}
          onOpenMapMaker={() => setGameState(GameState.MAP_MAKER)}
          onOpenCarMaker={() => setGameState(GameState.CAR_MAKER)}
          bestDistance={bestScore} 
        />
      )}

      {/* Loading Screen Overlay (Between Menu and Game) */}
      {gameState === GameState.LOADING && <LoadingScreen />}

      {/* Actual Game - Mounted during LOADING, PLAYING, GAME_OVER, and LEVEL_COMPLETE (frozen in background) */}
      {(gameState === GameState.LOADING || gameState === GameState.PLAYING || gameState === GameState.GAME_OVER || gameState === GameState.LEVEL_COMPLETE) && (
        <Game 
            mode={gameMode}
            levelConfig={currentLevel}
            onGameOver={handleGameOver} 
            onLevelComplete={handleLevelComplete}
            selectedCar={selectedCar} 
            selectedMap={selectedMap}
            config={activeConfig}
            onUpdateConfig={updateConfig}
            onResetConfig={resetConfig}
            onExit={() => setGameState(GameState.MENU)}
            onRestart={handleRestart}
            onReady={handleGameReady} // Trigger when terrain buffer is full
        />
      )}

      {gameState === GameState.GAME_OVER && (
        <GameOver 
          title="Wasted"
          message="You flipped the car!"
          distance={score} 
          bestDistance={bestScore} 
          isWin={false}
          onRestart={handleRestart} 
          onMenu={() => setGameState(GameState.MENU)}
        />
      )}

      {gameState === GameState.LEVEL_COMPLETE && (
         <GameOver 
            title="Victory!"
            message={`You beat ${currentLevel?.name}!`}
            distance={score}
            bestDistance={bestScore} 
            isWin={true}
            onRestart={() => setGameState(GameState.MENU)} 
            onMenu={() => setGameState(GameState.MENU)}
         />
      )}

      {gameState === GameState.MAP_MAKER && (
          <MapMaker 
             config={activeConfig} 
             onUpdateConfig={updateConfig} 
             onClose={() => setGameState(GameState.MENU)} 
          />
      )}

      {gameState === GameState.CAR_MAKER && (
          <CarMaker onClose={() => setGameState(GameState.MENU)} />
      )}

      {isGarageOpen && (
        <CarSelection 
          currentCarId={selectedCar.id} 
          onSelect={setSelectedCar} 
          onClose={() => setIsGarageOpen(false)} 
        />
      )}

      {isMapSelectOpen && (
        <MapSelection 
          currentMapId={selectedMap.id} 
          onSelect={setSelectedMap} 
          onClose={() => setIsMapSelectOpen(false)} 
        />
      )}

      {isLevelSelectOpen && (
          <LevelSelect 
            onSelectLevel={startLevel}
            onClose={() => setIsLevelSelectOpen(false)}
          />
      )}

      {(gameState === GameState.MAP_MAKER || gameState === GameState.CAR_MAKER) && (
        <div className="absolute inset-0 -z-10 bg-gradient-to-b" style={{ 
            backgroundImage: `linear-gradient(to bottom, ${selectedMap.skyColorStart}, ${selectedMap.skyColorEnd})` 
        }}>
           <div className="absolute bottom-0 w-full h-1/3 transform skew-y-3 origin-bottom-right" style={{ backgroundColor: selectedMap.groundDarkColor }}></div>
           <div className="absolute bottom-0 w-full h-1/4 transform -skew-y-2 origin-bottom-left" style={{ backgroundColor: selectedMap.groundColor }}></div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { COLORS } from '../constants';
import { GameConfig, CarModel, MapConfig, GameMode, LevelConfig } from '../types';
import { createEngine, createCar, generateTerrainChunk, generateClouds, createWall, TerrainChunk, Cloud, Decoration } from '../utils/physics';
import { SoundManager } from '../utils/audio';
import DebugMenu from './DebugMenu';

const Matter = (window as any).Matter;

interface GameProps {
  mode: GameMode;
  levelConfig?: LevelConfig;
  onGameOver: (distance: number, coins: number) => void;
  onLevelComplete: (coins: number) => void;
  selectedCar: CarModel;
  selectedMap: MapConfig;
  config: GameConfig;
  onUpdateConfig: (key: keyof GameConfig, value: any) => void;
  onResetConfig: () => void;
  onExit: () => void;
  onRestart: () => void;
  isMenuBackground?: boolean;
  onReady?: () => void;
}

interface Particle {
    x: number; y: number; vx: number; vy: number;
    life: number; maxLife: number; active: boolean;
    type: 'dust' | 'spark' | 'explosion' | 'smoke';
}

const Game: React.FC<GameProps> = ({ mode, levelConfig, onGameOver, onLevelComplete, selectedCar, selectedMap, config, onUpdateConfig, onResetConfig, onExit, onRestart, isMenuBackground = false, onReady }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const requestRef = useRef<number | null>(null);
  const engineRef = useRef<any>(null);
  const carRef = useRef<any>(null);
  const soundManagerRef = useRef<SoundManager | null>(null);

  // Game Logic Refs
  const chunksRef = useRef<TerrainChunk[]>([]);
  const cloudsRef = useRef<Cloud[]>([]);
  const collectedCoinIdsRef = useRef<Set<number>>(new Set());
  const collectedFuelIdsRef = useRef<Set<number>>(new Set());
  const particlesRef = useRef<Particle[]>([]);
  const lastChunkDataRef = useRef({ endX: 0, endY: 200, globalIndex: 0, segmentsSinceFuel: 0 });

  const fuelRef = useRef(config.MAX_FUEL);
  const wheelGroundContacts = useRef(0);
  const isOutOfFuelRef = useRef(false);
  const gameStateRef = useRef({ distance: 0, coins: 0, isGameOver: false, keys: { left: false, right: false } });

  // Visual state
  const cameraZoomRef = useRef(1.0);
  const cameraPosRef = useRef({ x: 0, y: 0 });
  const [isPaused, setIsPaused] = useState(false);
  const pausedRef = useRef(false);
  const [notification, setNotification] = useState<{text: string, subText?: string, id: number} | null>(null);
  const patternsRef = useRef<{[key: string]: CanvasPattern | null}>({});
  const starsRef = useRef<{x: number, y: number, r: number, opacity: number}[]>([]);

  // FPS Logic
  const lastFpsTimeRef = useRef(0);
  const frameCountRef = useRef(0);
  const hudFpsRef = useRef<HTMLDivElement>(null);

  // HUD Refs
  const hudDistanceRef = useRef<HTMLDivElement>(null);
  const hudCoinsRef = useRef<HTMLDivElement>(null);
  const hudFuelBarRef = useRef<HTMLDivElement>(null);

  // Setup Stars for Moon
  useEffect(() => {
    if (selectedMap.backgroundType === 'moon') {
        const s = [];
        for(let i=0; i<150; i++) {
            s.push({ x: Math.random() * 2000, y: Math.random() * 1000 - 500, r: Math.random() * 2, opacity: Math.random() });
        }
        starsRef.current = s;
    } else {
        starsRef.current = [];
    }
  }, [selectedMap]);

  const addChunk = useCallback((startX: number) => {
    const { endY, globalIndex, segmentsSinceFuel } = lastChunkDataRef.current;
    const length = config.CHUNK_SIZE;
    const chunkId = Math.floor(startX / length);

    const newChunk = generateTerrainChunk(
        chunkId, startX, endY, globalIndex, length, false, config, selectedMap.backgroundType, segmentsSinceFuel,
        mode === 'LEVELS' && levelConfig ? levelConfig.distance : null
    );

    if (engineRef.current) Matter.World.add(engineRef.current.world, newChunk.composite);

    if (selectedMap.backgroundType === 'earth' || selectedMap.backgroundType === 'highway') {
        const newClouds = generateClouds(startX, length);
        cloudsRef.current = [...cloudsRef.current, ...newClouds];
    }

    lastChunkDataRef.current = {
        endX: startX + length,
        endY: newChunk.endY,
        globalIndex: newChunk.endGlobalIndex,
        segmentsSinceFuel: newChunk.nextSegmentsSinceFuel
    };

    chunksRef.current.push(newChunk);

    // Cleanup old chunks and clouds to prevent memory leak
    if (chunksRef.current.length > 5) {
        const oldChunk = chunksRef.current.shift();
        if (oldChunk && engineRef.current) {
             Matter.Composite.remove(engineRef.current.world, oldChunk.composite);
        }
    }
    if (cloudsRef.current.length > 50) {
        cloudsRef.current = cloudsRef.current.slice(cloudsRef.current.length - 40);
    }
  }, [config, selectedMap.backgroundType, mode, levelConfig]);

  const handleResize = useCallback(() => {
    if (canvasRef.current && containerRef.current) {
        const rw = containerRef.current.clientWidth * config.RESOLUTION;
        const rh = containerRef.current.clientHeight * config.RESOLUTION;
        canvasRef.current.width = rw;
        canvasRef.current.height = rh;
        patternsRef.current = {}; 
    }
  }, [config.RESOLUTION]);

  useEffect(() => {
    window.addEventListener('resize', handleResize);
    handleResize();
    return () => window.removeEventListener('resize', handleResize);
  }, [handleResize]);

  // Initialization Sequence
  useEffect(() => {
    if (!isMenuBackground) soundManagerRef.current = new SoundManager();
    const engine = createEngine(config);
    engineRef.current = engine;
    const car = createCar(200, -100, selectedCar, config); 
    carRef.current = car;
    Matter.World.add(engine.world, [car, createWall(-1000)]);

    // Reset loop state
    lastChunkDataRef.current = { endX: 0, endY: 200, globalIndex: 0, segmentsSinceFuel: 0 };
    chunksRef.current = [];
    cloudsRef.current = [];
    collectedCoinIdsRef.current = new Set();
    collectedFuelIdsRef.current = new Set();
    fuelRef.current = config.MAX_FUEL;
    isOutOfFuelRef.current = false;
    gameStateRef.current.isGameOver = false;
    gameStateRef.current.distance = 0;
    gameStateRef.current.coins = 0;
    pausedRef.current = false;
    setIsPaused(false);

    let currentGenX = 0;
    const buffer = isMenuBackground ? 4000 : config.INITIAL_BUFFER_DISTANCE;
    while (currentGenX < buffer) {
        addChunk(currentGenX);
        currentGenX += config.CHUNK_SIZE;
    }

    particlesRef.current = Array.from({ length: config.PARTICLE_POOL_SIZE }).map(() => ({
        x: 0, y: 0, vx: 0, vy: 0, life: 0, maxLife: 0, active: false, type: 'dust'
    }));

    Matter.Events.on(engine, 'collisionStart', (event: any) => {
        event.pairs.forEach((pair: any) => {
            const { bodyA, bodyB } = pair;
            const isWheel = (b: any) => b.label === 'wheelBack' || b.label === 'wheelFront';
            const isGround = (b: any) => b.label === 'ground' || b.label === 'obstacle';

            if ((isWheel(bodyA) && isGround(bodyB)) || (isWheel(bodyB) && isGround(bodyA))) {
                wheelGroundContacts.current++;
                const w = isWheel(bodyA) ? bodyA : bodyB;
                const speed = Matter.Vector.magnitude(w.velocity);
                if (speed > 5) spawnParticles(w.position.x, w.position.y + 15, 2, speed > 10 ? 'spark' : 'dust');
            }

            if ((bodyA.label === 'chassis' && bodyB.label === 'ground') || (bodyB.label === 'chassis' && bodyA.label === 'ground')) {
                if (isMenuBackground) return;
                const chassis = bodyA.label === 'chassis' ? bodyA : bodyB;
                if (Math.abs(chassis.angle) > Math.PI / 1.5) {
                    gameStateRef.current.isGameOver = true;
                    soundManagerRef.current?.stopContinuous();
                    onGameOver(gameStateRef.current.distance, gameStateRef.current.coins);
                }
            }

            let item = null;
            if (['chassis', 'wheelBack', 'wheelFront'].includes(bodyA.label) && ['coin', 'fuel', 'finishLine'].includes(bodyB.label)) item = bodyB;
            if (['chassis', 'wheelBack', 'wheelFront'].includes(bodyB.label) && ['coin', 'fuel', 'finishLine'].includes(bodyA.label)) item = bodyA;

            if (item && !isMenuBackground) {
                if (item.label === 'finishLine') {
                    gameStateRef.current.isGameOver = true;
                    onLevelComplete(gameStateRef.current.coins);
                } else if (!collectedCoinIdsRef.current.has(item.id) && !collectedFuelIdsRef.current.has(item.id)) {
                    if (item.label === 'coin') {
                        collectedCoinIdsRef.current.add(item.id);
                        gameStateRef.current.coins += config.COIN_VALUE;
                        soundManagerRef.current?.playCoinSound();
                        Matter.World.remove(engine.world, item);
                    } else if (item.label === 'fuel') {
                        collectedFuelIdsRef.current.add(item.id);
                        fuelRef.current = Math.min(config.MAX_FUEL, fuelRef.current + config.FUEL_CAN_VALUE);
                        isOutOfFuelRef.current = false;
                        setNotification({ text: "FUEL!", id: Date.now() });
                        setTimeout(() => setNotification(null), 1500);
                        Matter.World.remove(engine.world, item);
                    }
                }
            }
        });
    });

    Matter.Events.on(engine, 'collisionEnd', (event: any) => {
        event.pairs.forEach((pair: any) => {
            const isWheel = (b: any) => b.label === 'wheelBack' || b.label === 'wheelFront';
            const isGround = (b: any) => b.label === 'ground' || b.label === 'obstacle';
            if ((isWheel(pair.bodyA) && isGround(pair.bodyB)) || (isWheel(pair.bodyB) && isGround(pair.bodyA))) {
                wheelGroundContacts.current = Math.max(0, wheelGroundContacts.current - 1);
            }
        });
    });

    // Notify parent that we are ready to start playing
    if (onReady) onReady();

    requestRef.current = requestAnimationFrame(animate);
    return () => {
        if (requestRef.current) cancelAnimationFrame(requestRef.current);
        Matter.Engine.clear(engine);
        if (soundManagerRef.current) soundManagerRef.current.stopContinuous();
    };
  }, [addChunk, selectedCar, onGameOver, onLevelComplete, config, isMenuBackground, onReady]);

  const handleResume = useCallback(() => {
    pausedRef.current = false;
    setIsPaused(false);
  }, []);

  const spawnParticles = (x: number, y: number, count: number, type: 'dust' | 'spark' | 'explosion' | 'smoke') => {
      let spawned = 0;
      for (let p of particlesRef.current) {
          if (spawned >= count) break;
          if (!p.active) {
              p.active = true; p.x = x; p.y = y; p.type = type;
              p.maxLife = config.PARTICLE_LIFETIME; p.life = p.maxLife;
              if (type === 'smoke') {
                  p.vx = (Math.random() - 0.5) * 2 - 2; // Smoke blows back
                  p.vy = (Math.random() - 0.5) * 2;
                  p.maxLife = 60;
                  p.life = 60;
              } else {
                  p.vx = (Math.random() - 0.5) * 5; 
                  p.vy = (Math.random() - 0.5) * 5;
              }
              spawned++;
          }
      }
  };

  const getPattern = (ctx: CanvasRenderingContext2D, type: string, color1: string, color2: string) => {
      const key = `${type}-${color1}-${color2}`;
      if (patternsRef.current[key]) return patternsRef.current[key];
      const pCanvas = document.createElement('canvas');
      const pCtx = pCanvas.getContext('2d')!;
      pCanvas.width = 40; pCanvas.height = 40;
      if (type === 'ground') {
          // Noise texture
          pCtx.fillStyle = color1; pCtx.fillRect(0,0,40,40);
          pCtx.fillStyle = color2; 
          for(let i=0; i<30; i++) {
              pCtx.globalAlpha = 0.1 + Math.random() * 0.2;
              pCtx.beginPath(); 
              pCtx.arc(Math.random()*40, Math.random()*40, 1 + Math.random()*2, 0, Math.PI*2);
              pCtx.fill();
          }
      } else if (type === 'striped') {
          pCanvas.width = 20; pCtx.fillStyle = color1; pCtx.fillRect(0,0,20,40);
          pCtx.fillStyle = color2; pCtx.fillRect(0,0,10,40);
      } else if (type === 'checker') {
          pCanvas.width = 20; pCanvas.height = 20;
          pCtx.fillStyle = color1; pCtx.fillRect(0,0,20,20);
          pCtx.fillStyle = color2; pCtx.fillRect(0,0,10,10); pCtx.fillRect(10,10,10,10);
      } else if (type === 'dots') {
          pCanvas.width = 10; pCanvas.height = 10;
          pCtx.fillStyle = color1; pCtx.fillRect(0,0,10,10);
          pCtx.fillStyle = color2; pCtx.beginPath(); pCtx.arc(5,5,2,0,Math.PI*2); pCtx.fill();
      } else if (type === 'gradient') {
          const g = pCtx.createLinearGradient(0,0,0,40);
          g.addColorStop(0, color2);
          g.addColorStop(1, color1);
          pCtx.fillStyle = g;
          pCtx.fillRect(0,0,40,40);
      }
      const pattern = ctx.createPattern(pCanvas, 'repeat');
      patternsRef.current[key] = pattern;
      return pattern;
  };

  const drawChassisPath = (ctx: CanvasRenderingContext2D, car: CarModel, cw: number, ch: number, wr: number) => {
      ctx.beginPath();
      const halfW = cw / 2;
      const halfH = ch / 2;

      // Calculate wheel positions relative to center
      // Based on createCar logic: offset = -cw/2 + wr
      const rearWheelX = -halfW + wr;
      const frontWheelX = halfW - wr;
      const wellR = wr + 4; // Slight clearance for wheel well

      // -- UNDERCARRIAGE with Wheel Wells --
      // Start at Bottom-Left (before rear well)
      ctx.moveTo(-halfW, halfH); 

      // Rear Well
      ctx.arc(rearWheelX, halfH, wellR, Math.PI, 0); 

      // Front Well
      ctx.arc(frontWheelX, halfH, wellR, Math.PI, 0);

      // To Front Bumper Bottom
      ctx.lineTo(halfW, halfH);

      // -- UPPER BODY SHAPES --
      if (car.shape === 'coupe' || !car.shape) {
          ctx.lineTo(halfW * 1.1, 0); // Nose slope
          ctx.quadraticCurveTo(halfW * 0.8, -halfH * 0.7, halfW * 0.1, -halfH * 0.9); // Windshield
          ctx.lineTo(-halfW * 0.4, -halfH * 0.9); // Roof
          ctx.quadraticCurveTo(-halfW, -halfH * 0.9, -halfW, -halfH * 0.2); // Rear Slope
      } else if (car.shape === 'jeep') {
          ctx.lineTo(halfW * 1.1, halfH); // Front bumper vertical
          ctx.lineTo(halfW * 1.1, -halfH * 0.2); // Hood front
          ctx.lineTo(halfW * 0.6, -halfH * 0.2); // Hood top
          ctx.lineTo(halfW * 0.6, -halfH * 1.6); // Windshield
          ctx.lineTo(-halfW * 0.5, -halfH * 1.6); // Roof
          ctx.lineTo(-halfW * 0.5, -halfH * 0.5); // Bed front
          ctx.lineTo(-halfW * 0.9, -halfH * 0.5); // Bed top
      } else if (car.shape === 'racer') {
          ctx.lineTo(halfW * 1.5, halfH * 0.3); // Nose tip
          ctx.quadraticCurveTo(halfW * 1.0, -halfH * 0.3, halfW * 0.3, -halfH * 0.5); // Body slope
          ctx.lineTo(-halfW * 0.5, -halfH * 0.5); // Engine cover
          ctx.lineTo(-halfW * 1.2, -halfH * 0.3); // Spoiler mount
          ctx.lineTo(-halfW * 1.2, halfH * 0.2); // Rear
      } else if (car.shape === 'buggy') {
          ctx.lineTo(halfW * 0.9, halfH * 0.5); // Nose
          ctx.lineTo(halfW * 1.1, 0);
          ctx.lineTo(halfW * 0.9, 0); 
          ctx.lineTo(halfW * 0.4, -halfH * 1.4); // Rollcage Front
          ctx.lineTo(-halfW * 0.5, -halfH * 1.4); // Rollcage Top
          ctx.lineTo(-halfW * 0.7, 0); // Rollcage Rear
      } else if (car.shape === 'van') {
          ctx.lineTo(halfW * 1.1, halfH * 0.5);
          ctx.quadraticCurveTo(halfW * 1.1, -halfH * 1.2, halfW * 0.7, -halfH * 1.3); // Front curve
          ctx.lineTo(-halfW * 0.9, -halfH * 1.3); // Roof
          ctx.lineTo(-halfW * 0.9, halfH * 0.5); // Rear
      } else if (car.shape === 'supercar') {
          ctx.lineTo(halfW * 1.45, halfH * 0.5); // Nose
          ctx.quadraticCurveTo(halfW * 1.0, -halfH * 0.4, halfW * 0.1, -halfH * 0.6); // Hood
          ctx.lineTo(-halfW * 0.5, -halfH * 0.6); // Rear Deck
          ctx.lineTo(-halfW * 1.1, 0); 
          ctx.lineTo(-halfW * 1.1, halfH * 0.5);
      } else if (car.shape === 'bike') {
           ctx.lineTo(halfW * 0.3, 0);
           ctx.lineTo(halfW * 0.4, -halfH * 0.4); 
           ctx.lineTo(0, -halfH * 0.7); 
           ctx.lineTo(-halfW * 0.5, 0);
      }

      ctx.closePath();
  };

  const drawCarDetails = (ctx: CanvasRenderingContext2D, car: CarModel, cw: number, ch: number) => {
      const halfW = cw / 2;
      const halfH = ch / 2;

      // 1. Headlights (with glow)
      ctx.save();
      ctx.translate(halfW, 0);

      const grad = ctx.createLinearGradient(0, 0, 150, 0);
      grad.addColorStop(0, 'rgba(255, 255, 200, 0.4)');
      grad.addColorStop(1, 'rgba(255, 255, 200, 0)');
      ctx.fillStyle = grad;
      ctx.beginPath(); ctx.moveTo(0, -5); ctx.lineTo(150, -40); ctx.lineTo(150, 40); ctx.lineTo(0, 5); ctx.fill();

      ctx.fillStyle = '#fef08a';
      ctx.shadowColor = '#fef08a'; ctx.shadowBlur = 10;
      if (car.shape === 'jeep' || car.shape === 'van') {
           ctx.fillRect(halfW * 0.05, -15, 5, 20);
      } else if (car.shape === 'bike') {
           ctx.beginPath(); ctx.arc(halfW * 0.3, -10, 8, 0, Math.PI*2); ctx.fill();
      } else {
           ctx.beginPath(); ctx.ellipse(halfW * 0.15, 0, 4, 12, 0, 0, Math.PI*2); ctx.fill();
      }
      ctx.restore();

      // 2. Windows - Gradient glass
      const glassGrad = ctx.createLinearGradient(0, -ch, 0, 0);
      glassGrad.addColorStop(0, '#38bdf8');
      glassGrad.addColorStop(1, '#1e293b');
      ctx.fillStyle = glassGrad;
      ctx.strokeStyle = '#334155'; ctx.lineWidth = 1;

      if (car.shape === 'coupe') {
          ctx.beginPath();
          ctx.moveTo(-halfW * 0.3, -halfH * 0.75);
          ctx.lineTo(halfW * 0.1, -halfH * 0.75);
          ctx.lineTo(halfW * 0.5, -halfH * 0.1);
          ctx.lineTo(-halfW * 0.3, -halfH * 0.1);
          ctx.fill(); ctx.stroke();
      } else if (car.shape === 'supercar') {
          ctx.beginPath();
          ctx.moveTo(-halfW * 0.2, -halfH * 0.5);
          ctx.lineTo(halfW * 0.2, -halfH * 0.5);
          ctx.lineTo(halfW * 0.6, -halfH * 0.1);
          ctx.lineTo(-halfW * 0.4, -halfH * 0.1);
          ctx.fill(); ctx.stroke();
      } else if (car.shape === 'jeep') {
          ctx.fillRect(-halfW * 0.4, -halfH * 1.3, cw * 0.35, ch * 0.5); // Side
          ctx.fillRect(halfW * 0.1, -halfH * 1.3, cw * 0.35, ch * 0.5); // Front
      } else if (car.shape === 'van') {
          ctx.fillRect(-halfW * 0.8, -halfH * 1.1, cw * 0.35, ch * 0.5);
          ctx.fillRect(-halfW * 0.3, -halfH * 1.1, cw * 0.45, ch * 0.5);
      }

      // 3. Extra Details
      ctx.fillStyle = '#111';
      if (car.shape === 'racer' || car.shape === 'supercar') {
          // Spoiler
          ctx.fillStyle = car.bodyColor;
          ctx.beginPath();
          ctx.moveTo(-halfW * 1.1, -halfH * 0.2);
          ctx.lineTo(-halfW * 1.25, -halfH * 1.4);
          ctx.lineTo(-halfW * 0.7, -halfH * 1.4);
          ctx.lineTo(-halfW * 0.6, -halfH * 0.2);
          ctx.fill(); 
          ctx.stroke();
          // Wing
          ctx.fillStyle = '#111';
          ctx.fillRect(-halfW * 1.3, -halfH * 1.5, cw * 0.6, 6);
      } else if (car.shape === 'buggy') {
          ctx.strokeStyle = '#64748b';
          ctx.lineWidth = 3;
          ctx.beginPath();
          ctx.moveTo(-halfW * 0.7, 0); ctx.lineTo(halfW * 0.9, 0); 
          ctx.moveTo(-halfW * 0.5, -halfH * 1.4); ctx.lineTo(halfW * 0.4, -halfH * 1.4);
          ctx.lineTo(halfW * 0.9, 0);
          ctx.stroke();
      }

      // 4. Exhaust
      const exhaustX = -halfW * 1.0;
      const exhaustY = halfH * 0.3;
      ctx.fillStyle = '#444';
      if (car.shape !== 'bike') {
          ctx.fillRect(exhaustX - 8, exhaustY, 15, 8);
          ctx.fillStyle = '#000';
          ctx.beginPath(); ctx.arc(exhaustX - 8, exhaustY + 4, 3, 0, Math.PI*2); ctx.fill();
      }

      if (Math.random() > 0.7 && !isMenuBackground && Math.abs(carRef.current.bodies[0].velocity.x) > 1) {
          spawnParticles(
              carRef.current.bodies[0].position.x + exhaustX, 
              carRef.current.bodies[0].position.y + exhaustY + 4, 
              1, 'smoke'
          );
      }
  };

  const drawWheel = (ctx: CanvasRenderingContext2D, x: number, y: number, r: number, angle: number, color: string) => {
      ctx.save();
      ctx.translate(x, y);
      ctx.rotate(angle);

      // Tire
      ctx.beginPath(); ctx.arc(0, 0, r, 0, Math.PI * 2); 
      ctx.fillStyle = '#1c1917'; ctx.fill(); // Dark rubber

      // Detailed Tread
      ctx.strokeStyle = '#292524'; ctx.lineWidth = 4;
      ctx.setLineDash([5, 8]);
      ctx.beginPath(); ctx.arc(0,0, r-2, 0, Math.PI*2); ctx.stroke();
      ctx.setLineDash([]);

      // Rim
      const rimR = r * 0.65;
      ctx.beginPath(); ctx.arc(0, 0, rimR, 0, Math.PI * 2);
      ctx.fillStyle = color; ctx.fill();
      ctx.strokeStyle = '#444'; ctx.lineWidth = 2; ctx.stroke();

      // Spokes
      ctx.strokeStyle = '#000'; ctx.lineWidth = 3; ctx.lineCap = 'round';
      const spokes = 5;
      for (let i = 0; i < spokes; i++) {
          ctx.rotate((Math.PI * 2) / spokes);
          ctx.beginPath(); ctx.moveTo(0, 0); ctx.lineTo(0, rimR - 3); ctx.stroke();
      }

      // Center Hub
      ctx.beginPath(); ctx.arc(0, 0, r * 0.15, 0, Math.PI * 2);
      ctx.fillStyle = '#555'; ctx.fill();
      ctx.beginPath(); ctx.arc(0, 0, r * 0.08, 0, Math.PI * 2);
      ctx.fillStyle = '#222'; ctx.fill();

      ctx.restore();
  };

  const drawSuspension = (ctx: CanvasRenderingContext2D, chassisBody: any, wheelBody: any, offsetX: number, offsetY: number) => {
      const cAngle = chassisBody.angle;
      const worldOffsetX = offsetX * Math.cos(cAngle) - offsetY * Math.sin(cAngle);
      const worldOffsetY = offsetX * Math.sin(cAngle) + offsetY * Math.cos(cAngle);

      const p1 = { x: chassisBody.position.x + worldOffsetX, y: chassisBody.position.y + worldOffsetY };
      const p2 = { x: wheelBody.position.x, y: wheelBody.position.y };

      const dist = Math.hypot(p2.x - p1.x, p2.y - p1.y);
      const angle = Math.atan2(p2.y - p1.y, p2.x - p1.x);

      ctx.save();
      ctx.translate(p1.x, p1.y);
      ctx.rotate(angle);

      // Upper strut
      ctx.strokeStyle = '#444'; ctx.lineWidth = 6;
      ctx.beginPath(); ctx.moveTo(0, 0); ctx.lineTo(dist/2, 0); ctx.stroke();

      // Lower strut
      ctx.strokeStyle = '#999'; ctx.lineWidth = 4;
      ctx.beginPath(); ctx.moveTo(dist/2, 0); ctx.lineTo(dist, 0); ctx.stroke();

      // Coil
      ctx.strokeStyle = '#dc2626'; ctx.lineWidth = 2.5;
      ctx.beginPath();
      ctx.moveTo(0, 0);
      const zigs = 8;
      for(let i=0; i<=zigs; i++) {
          ctx.lineTo((dist / zigs) * i, i % 2 === 0 ? -5 : 5);
      }
      ctx.stroke();
      ctx.restore();
  };

  const drawCloud = (ctx: CanvasRenderingContext2D, cloud: Cloud) => {
      ctx.save();
      ctx.translate(cloud.x, cloud.y);
      ctx.scale(cloud.scale, cloud.scale);

      ctx.fillStyle = 'rgba(255,255,255,0.7)';

      ctx.beginPath();
      ctx.arc(0, 0, 30, 0, Math.PI * 2);
      ctx.arc(35, 5, 40, 0, Math.PI * 2);
      ctx.arc(-35, 5, 35, 0, Math.PI * 2);
      ctx.arc(15, -25, 30, 0, Math.PI * 2);
      ctx.arc(-15, -25, 30, 0, Math.PI * 2);

      ctx.fill();
      ctx.restore();
  };

  const drawTree = (ctx: CanvasRenderingContext2D, type: number, seed: number) => {
    // Trunk
    ctx.fillStyle = COLORS.treeTrunk;
    const trunkW = 12 + seed * 4;
    const trunkH = 40 + seed * 20;
    ctx.fillRect(-trunkW/2, -trunkH, trunkW, trunkH);

    // Leaves
    if (type === 6) { // Pine
        ctx.fillStyle = COLORS.treeLeafDark;
        ctx.beginPath();
        ctx.moveTo(-40, -trunkH + 10);
        ctx.lineTo(0, -trunkH - 100 - seed * 50);
        ctx.lineTo(40, -trunkH + 10);
        ctx.fill();

        ctx.fillStyle = COLORS.treeLeafLight;
        ctx.beginPath();
        ctx.moveTo(-30, -trunkH - 20);
        ctx.lineTo(0, -trunkH - 100 - seed * 50);
        ctx.lineTo(30, -trunkH - 20);
        ctx.fill();
    } else { // Round
        ctx.fillStyle = COLORS.treeLeafDark;
        ctx.beginPath();
        ctx.arc(0, -trunkH - 20, 40 + seed * 10, 0, Math.PI * 2);
        ctx.fill();

        ctx.fillStyle = COLORS.treeLeafLight;
        ctx.beginPath();
        ctx.arc(-10, -trunkH - 30, 30 + seed * 10, 0, Math.PI * 2);
        ctx.fill();
    }
  };

  const drawRock = (ctx: CanvasRenderingContext2D, seed: number) => {
      ctx.fillStyle = COLORS.boulder;
      ctx.beginPath();
      ctx.moveTo(-20 - seed * 10, 0);
      ctx.lineTo(-15 - seed * 5, -20 - seed * 15);
      ctx.lineTo(10 + seed * 5, -25 - seed * 10);
      ctx.lineTo(25 + seed * 10, 0);
      ctx.fill();

      // Detail
      ctx.fillStyle = COLORS.boulderDark;
      ctx.beginPath();
      ctx.moveTo(-10, -5);
      ctx.lineTo(0, -15);
      ctx.lineTo(10, -5);
      ctx.fill();
  };

  const drawBush = (ctx: CanvasRenderingContext2D, seed: number) => {
     ctx.fillStyle = COLORS.bushDark;
     ctx.beginPath();
     ctx.arc(-15, -10, 15 + seed * 5, 0, Math.PI * 2);
     ctx.arc(15, -10, 12 + seed * 5, 0, Math.PI * 2);
     ctx.arc(0, -20, 18 + seed * 5, 0, Math.PI * 2);
     ctx.fill();

     ctx.fillStyle = COLORS.bushLight;
     ctx.beginPath();
     ctx.arc(0, -20, 10 + seed * 3, 0, Math.PI * 2);
     ctx.fill();
  };

  const animate = useCallback(() => {
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d', { alpha: false });
    if (!canvas || !ctx || gameStateRef.current.isGameOver) {
        requestRef.current = requestAnimationFrame(animate);
        return;
    }

    if (!pausedRef.current) {
        Matter.Engine.update(engineRef.current, 1000 / 60);
        const chassis = carRef.current.bodies.find((b: any) => b.label === 'chassis');
        const wheelB = carRef.current.bodies.find((b: any) => b.label === 'wheelBack');
        const wheelF = carRef.current.bodies.find((b: any) => b.label === 'wheelFront');

        const { keys } = gameStateRef.current;
        const speedRatio = Matter.Vector.magnitude(chassis.velocity) / 25;
        const isGrounded = wheelGroundContacts.current > 0;

        if (!isMenuBackground) {
            soundManagerRef.current?.updateContinuous(speedRatio, isGrounded, keys.right && !isOutOfFuelRef.current);
            if (keys.right && !isOutOfFuelRef.current) {
                fuelRef.current -= config.FUEL_CONSUMPTION;
                if (fuelRef.current <= 0) {
                    fuelRef.current = 0; isOutOfFuelRef.current = true;
                    setNotification({ text: "OUT OF FUEL", id: Date.now() });
                    setTimeout(() => { if (!gameStateRef.current.isGameOver) onGameOver(gameStateRef.current.distance, gameStateRef.current.coins); }, 3000);
                }
                const power = selectedCar.acceleration;
                if (selectedCar.driveTrain !== 'FWD') Matter.Body.setAngularVelocity(wheelB, Math.min(wheelB.angularVelocity + power, selectedCar.speed));
                if (selectedCar.driveTrain !== 'RWD') Matter.Body.setAngularVelocity(wheelF, Math.min(wheelF.angularVelocity + power, selectedCar.speed));
                if (chassis.angularVelocity > -config.MAX_ROTATION_SPEED) Matter.Body.setAngularVelocity(chassis, chassis.angularVelocity - (isGrounded ? config.GROUND_ROTATION_SPEED : config.AIR_ROTATION_SPEED));
            } else if (keys.left) {
                 if (selectedCar.driveTrain !== 'FWD') Matter.Body.setAngularVelocity(wheelB, Math.max(wheelB.angularVelocity - 0.1, -selectedCar.speed/2));
                 if (selectedCar.driveTrain !== 'RWD') Matter.Body.setAngularVelocity(wheelF, Math.max(wheelF.angularVelocity - 0.1, -selectedCar.speed/2));
                 if (chassis.angularVelocity < config.MAX_ROTATION_SPEED) Matter.Body.setAngularVelocity(chassis, chassis.angularVelocity + (isGrounded ? config.GROUND_ROTATION_SPEED : config.AIR_ROTATION_SPEED));
            }
        } else {
            Matter.Body.setAngularVelocity(wheelB, 0.4); Matter.Body.setAngularVelocity(wheelF, 0.4);
            if (chassis.position.y > 500) Matter.Body.setPosition(chassis, { x: 200, y: -100 });
        }

        cameraPosRef.current = { x: chassis.position.x, y: chassis.position.y };
        if (chassis.position.x > lastChunkDataRef.current.endX - config.RENDER_DISTANCE) addChunk(lastChunkDataRef.current.endX);
        gameStateRef.current.distance = Math.max(0, Math.floor((chassis.position.x - 200) / 10));

        if (hudDistanceRef.current) hudDistanceRef.current.innerText = `${gameStateRef.current.distance}`;
        if (hudCoinsRef.current) hudCoinsRef.current.innerText = `${gameStateRef.current.coins}`;
        if (hudFuelBarRef.current) hudFuelBarRef.current.style.width = `${(fuelRef.current / config.MAX_FUEL) * 100}%`;
    }

    // --- RENDERING ---
    const zoom = cameraZoomRef.current;
    const vH = config.BASE_VIEWPORT_HEIGHT * zoom;
    const vW = (canvas.width / canvas.height) * vH; 
    const scale = canvas.height / vH;

    const camX = cameraPosRef.current.x - vW * 0.3;
    const camY = cameraPosRef.current.y - vH * 0.6;

    ctx.setTransform(scale, 0, 0, scale, -camX * scale, -camY * scale);

    // Sky
    const skyGrad = ctx.createLinearGradient(camX, camY, camX, camY + vH);
    skyGrad.addColorStop(0, selectedMap.skyColorStart); skyGrad.addColorStop(1, selectedMap.skyColorEnd);
    ctx.fillStyle = skyGrad; ctx.fillRect(camX, camY, vW, vH);

    // Sun/Moon Glow
    if (selectedMap.backgroundType !== 'moon') {
        const sunGrad = ctx.createRadialGradient(camX + vW - 100, camY + 100, 20, camX + vW - 100, camY + 100, 200);
        sunGrad.addColorStop(0, 'rgba(255, 255, 200, 0.6)');
        sunGrad.addColorStop(1, 'rgba(255, 255, 200, 0)');
        ctx.fillStyle = sunGrad; ctx.fillRect(camX, camY, vW, vH/2);
    }

    if (starsRef.current.length > 0) {
        ctx.fillStyle = 'white';
        starsRef.current.forEach(s => {
            const px = s.x + camX * 0.85; 
            if (px > camX && px < camX + vW) {
                ctx.globalAlpha = s.opacity; ctx.beginPath(); ctx.arc(px, s.y, s.r, 0, Math.PI*2); ctx.fill();
            }
        });
        ctx.globalAlpha = 1;
    }

    cloudsRef.current.forEach(c => {
        if (c.x > camX - 400 && c.x < camX + vW + 400) {
            drawCloud(ctx, c);
        }
    });

    const groundPat = getPattern(ctx, 'ground', selectedMap.groundColor, selectedMap.groundDarkColor);
    ctx.fillStyle = groundPat || selectedMap.groundColor;

    chunksRef.current.forEach(chunk => {
        if (chunk.endX < camX || chunk.pathData[0].x > camX + vW) return;

        ctx.beginPath(); ctx.moveTo(chunk.pathData[0].x, chunk.pathData[0].y);
        chunk.pathData.forEach(p => ctx.lineTo(p.x, p.y));
        ctx.lineTo(chunk.endX, chunk.endY + 1000); ctx.lineTo(chunk.pathData[0].x, chunk.pathData[0].y + 1000);
        ctx.fill(); 

        if (selectedMap.backgroundType === 'earth') {
             ctx.strokeStyle = COLORS.grassDetail; ctx.lineWidth = 10;
        } else if (selectedMap.backgroundType === 'moon') {
             ctx.strokeStyle = '#94a3b8'; ctx.lineWidth = 6;
        } else {
             ctx.strokeStyle = '#475569'; ctx.lineWidth = 8;
        }
        ctx.beginPath();
        chunk.pathData.forEach((p, i) => {
            if (i===0) ctx.moveTo(p.x, p.y);
            else ctx.lineTo(p.x, p.y);
        });
        ctx.stroke();

        chunk.decorations.forEach(d => {
            if (d.x < camX - 100 || d.x > camX + vW + 100) return;
            ctx.save(); ctx.translate(d.x, d.y); ctx.rotate(d.angle); ctx.scale(d.scale, d.scale);

            if (d.type === 5) { 
                ctx.fillStyle = 'white'; ctx.fillRect(0,-200,6,200); 
                ctx.fillStyle = '#ef4444'; ctx.beginPath(); ctx.moveTo(6,-200); ctx.lineTo(70,-175); ctx.lineTo(6,-150); ctx.fill();
            } else if (d.type === 3) { 
                ctx.fillStyle = COLORS.lampPost; ctx.fillRect(-2,-80,4,80); 
                ctx.fillStyle = COLORS.lampLight; ctx.beginPath(); ctx.arc(10,-80,6,0,Math.PI*2); ctx.fill();
                ctx.fillStyle = COLORS.lampGlow; ctx.beginPath(); ctx.arc(10,-80,20,0,Math.PI*2); ctx.fill();
            } else if (d.type === 4) { 
                ctx.fillStyle = '#78350f'; ctx.fillRect(-2,-20,4,20);
                ctx.fillRect(-20,-15,40,4);
            } else if (d.type === 6 || d.type === 7) { 
                drawTree(ctx, d.type, d.seed);
            } else if (d.type === 8) { 
                drawRock(ctx, d.seed);
            } else if (d.type === 9) { 
                drawBush(ctx, d.seed);
            } else if (selectedMap.backgroundType === 'earth') {
                 ctx.strokeStyle = COLORS.grassDetail; ctx.lineWidth = 2; 
                 ctx.beginPath(); 
                 ctx.moveTo(0,0); ctx.lineTo(-3, -8 - d.seed * 5);
                 ctx.moveTo(0,0); ctx.lineTo(3, -6 - d.seed * 5);
                 ctx.stroke();
            }
            ctx.restore();
        });

        chunk.coinBodies.forEach(b => {
            if (!collectedCoinIdsRef.current.has(b.id) && b.position.x > camX - 50 && b.position.x < camX + vW + 50) {
                ctx.save(); ctx.translate(b.position.x, b.position.y);
                const pulse = Math.sin(Date.now() / 200) * 0.1 + 1;
                ctx.scale(pulse, pulse);
                ctx.fillStyle = COLORS.coinOuter; ctx.beginPath(); ctx.arc(0,0,config.COIN_SIZE,0,Math.PI*2); ctx.fill();
                ctx.fillStyle = COLORS.coinInner; ctx.beginPath(); ctx.arc(0,0,config.COIN_SIZE*0.7,0,Math.PI*2); ctx.fill();
                ctx.fillStyle = '#fff'; ctx.font = 'bold 12px monospace'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle'; ctx.fillText('$', 0, 1);
                ctx.restore();
            }
        });

        chunk.fuelBodies.forEach(b => {
            if (!collectedFuelIdsRef.current.has(b.id) && b.position.x > camX - 50 && b.position.x < camX + vW + 50) {
                ctx.save(); ctx.translate(b.position.x, b.position.y);
                const pulse = Math.sin(Date.now() / 300) * 0.1 + 1;
                ctx.scale(pulse, pulse);
                ctx.fillStyle = COLORS.fuelCan; 
                ctx.fillRect(-10, -15, 20, 30);
                ctx.fillStyle = COLORS.fuelCanCap;
                ctx.fillRect(-6, -18, 12, 3);
                ctx.font = 'bold 10px sans-serif'; ctx.fillStyle = 'white'; ctx.fillText('FUEL', -10, 5);
                ctx.restore();
            }
        });
    });

    // --- CAR RENDER ---
    const chassis = carRef.current.bodies.find((b: any) => b.label === 'chassis');
    const wheelB = carRef.current.bodies.find((b: any) => b.label === 'wheelBack');
    const wheelF = carRef.current.bodies.find((b: any) => b.label === 'wheelFront');
    const cw = selectedCar.width || config.CAR_WIDTH; 
    const ch = selectedCar.height || config.CAR_HEIGHT;
    const wr = selectedCar.wheelSize || config.WHEEL_SIZE;

    // Draw Suspension (BEHIND everything)
    const wheelOffsetX = -cw / 2 + wr;
    const wheelOffsetY = ch / 2;
    drawSuspension(ctx, chassis, wheelB, wheelOffsetX, wheelOffsetY);
    drawSuspension(ctx, chassis, wheelF, -wheelOffsetX, wheelOffsetY);

    // Draw Wheels (BEHIND Chassis)
    [wheelB, wheelF].forEach(w => {
        drawWheel(ctx, w.position.x, w.position.y, wr, w.angle, selectedCar.wheelColor);
    });

    // Draw Chassis (ON TOP)
    ctx.save(); ctx.translate(chassis.position.x, chassis.position.y); ctx.rotate(chassis.angle);

    ctx.shadowColor = 'rgba(0,0,0,0.5)'; ctx.shadowBlur = 10;
    let bodyFill: string | CanvasPattern = selectedCar.bodyColor;
    if (selectedCar.texture !== 'plain') bodyFill = getPattern(ctx, selectedCar.texture, selectedCar.bodyColor, selectedCar.textureColor2) || bodyFill;

    if (selectedCar.imageUrl) {
        // ... (image logic from previous turn)
    }

    ctx.fillStyle = bodyFill;
    ctx.strokeStyle = 'rgba(0,0,0,0.6)'; ctx.lineWidth = 2;

    // Pass wheel radius to calculate arches
    drawChassisPath(ctx, selectedCar, cw, ch, wr);
    ctx.fill(); 
    ctx.shadowBlur = 0; 
    ctx.stroke();

    drawCarDetails(ctx, selectedCar, cw, ch);

    ctx.restore();

    particlesRef.current.forEach(p => {
        if (p.active) {
            ctx.fillStyle = p.type === 'spark' ? COLORS.particleSpark : 
                            p.type === 'smoke' ? COLORS.particleSmoke : COLORS.particleDust; 
            ctx.globalAlpha = p.life / p.maxLife;
            ctx.beginPath(); 
            if (p.type === 'smoke') {
                const r = 4 + (1 - p.life/p.maxLife) * 8;
                ctx.arc(p.x, p.y, r, 0, Math.PI*2);
            } else {
                ctx.arc(p.x, p.y, 2.5, 0, Math.PI*2); 
            }
            ctx.fill();
            p.x += p.vx; p.y += p.vy; 
            if (p.type !== 'smoke') p.vy += 0.2; 
            else { p.vx *= 0.95; p.vy -= 0.05; } 
            p.life--; if (p.life <= 0) p.active = false;
        }
    });
    ctx.globalAlpha = 1;

    const now = performance.now(); frameCountRef.current++;
    if (now - lastFpsTimeRef.current >= 500) {
        const fps = Math.round((frameCountRef.current * 1000) / (now - lastFpsTimeRef.current));
        if (hudFpsRef.current) hudFpsRef.current.innerText = `${fps} FPS`;
        lastFpsTimeRef.current = now; frameCountRef.current = 0;
    }

    requestRef.current = requestAnimationFrame(animate);
  }, [config, selectedCar, selectedMap, onGameOver, onLevelComplete, isMenuBackground]);

  return (
    <div ref={containerRef} className={`relative w-full h-full bg-slate-900 overflow-hidden select-none ${isMenuBackground ? 'opacity-40 pointer-events-none' : ''}`}>
      {!isMenuBackground && (
          <>
            <div className="absolute top-4 right-4 z-30 flex gap-2">
                <div ref={hudFpsRef} className="font-mono text-xs text-emerald-500 bg-black/60 px-2 py-1 rounded">60 FPS</div>
                <button onClick={() => { pausedRef.current = !pausedRef.current; setIsPaused(!isPaused); }} className="w-10 h-10 bg-black/60 text-white rounded flex items-center justify-center border border-white/20 hover:bg-white/10 active:scale-95 transition-all">
                    {isPaused ? "▶" : "⏸"}
                </button>
            </div>

            {isPaused && (
                <div className="absolute inset-0 z-40 flex flex-col items-center justify-center bg-black/80 backdrop-blur-md animate-fade-in">
                    <div className="p-8 bg-neutral-900/90 border border-neutral-700 rounded-2xl shadow-2xl flex flex-col items-center gap-6 min-w-[300px]">
                        <h2 className="text-4xl font-black italic text-white tracking-widest uppercase border-b-4 border-amber-500 pb-2 mb-2">
                            Paused
                        </h2>

                        <div className="flex flex-col gap-3 w-full">
                            <button 
                                onClick={handleResume}
                                className="w-full py-4 bg-emerald-600 hover:bg-emerald-500 text-white font-black italic uppercase tracking-wider rounded-lg shadow-lg hover:scale-[1.02] active:scale-95 transition-all flex items-center justify-center gap-2"
                            >
                                <span>▶</span> Resume
                            </button>

                            <button 
                                onClick={onRestart}
                                className="w-full py-4 bg-neutral-700 hover:bg-neutral-600 text-white font-bold uppercase tracking-wider rounded-lg shadow-lg hover:scale-[1.02] active:scale-95 transition-all flex items-center justify-center gap-2"
                            >
                                <span>↺</span> Restart
                            </button>

                            <button 
                                onClick={onExit}
                                className="w-full py-4 bg-red-900/50 border-2 border-red-900/50 hover:bg-red-900 hover:border-red-800 text-red-100 font-bold uppercase tracking-wider rounded-lg shadow-lg hover:scale-[1.02] active:scale-95 transition-all flex items-center justify-center gap-2"
                            >
                                <span>✕</span> Main Menu
                            </button>
                        </div>
                    </div>
                </div>
            )}

            <div className="absolute top-6 left-6 z-10 pointer-events-none flex flex-col gap-2">
                <div className="bg-black/60 px-4 py-2 rounded-xl border border-white/10 flex flex-col">
                    <span className="text-[10px] text-neutral-400 uppercase font-bold">Distance</span>
                    <span ref={hudDistanceRef} className="text-2xl font-mono font-bold text-white">0</span>
                </div>
                <div className="bg-black/60 px-4 py-2 rounded-xl border border-amber-500/20 flex gap-3 items-center">
                    <div className="w-6 h-6 rounded-full bg-amber-500 text-black flex items-center justify-center text-xs font-bold">$</div>
                    <span ref={hudCoinsRef} className="text-xl font-mono font-bold text-white">0</span>
                </div>
                <div className="w-48 h-1.5 bg-neutral-800 rounded-full mt-2 overflow-hidden border border-white/5">
                    <div ref={hudFuelBarRef} className="h-full bg-red-500 transition-all duration-200" style={{ width: '100%' }} />
                </div>
            </div>
            {notification && (
                <div className="absolute top-1/3 left-1/2 -translate-x-1/2 z-40 text-4xl font-black italic text-white animate-bounce drop-shadow-lg">{notification.text}</div>
            )}
            <div className="absolute bottom-10 left-10 right-10 z-30 flex justify-between">
                 <button 
                    className="w-24 h-24 rounded-full bg-black/40 border-2 border-white/10 active:bg-white/10 active:border-red-500/50 transition-all text-white font-black italic text-xl" 
                    onMouseDown={() => gameStateRef.current.keys.left = true} 
                    onMouseUp={() => gameStateRef.current.keys.left = false} 
                    onMouseLeave={() => gameStateRef.current.keys.left = false}
                    onTouchStart={(e) => { e.preventDefault(); gameStateRef.current.keys.left = true; }} 
                    onTouchEnd={(e) => { e.preventDefault(); gameStateRef.current.keys.left = false; }}
                >
                    BRAKE
                </button>
                 <button 
                    className="w-24 h-24 rounded-full bg-black/40 border-2 border-white/10 active:bg-white/10 active:border-emerald-500/50 transition-all text-white font-black italic text-xl" 
                    onMouseDown={() => gameStateRef.current.keys.right = true} 
                    onMouseUp={() => gameStateRef.current.keys.right = false} 
                    onMouseLeave={() => gameStateRef.current.keys.right = false}
                    onTouchStart={(e) => { e.preventDefault(); gameStateRef.current.keys.right = true; }} 
                    onTouchEnd={(e) => { e.preventDefault(); gameStateRef.current.keys.right = false; }}
                >
                    GAS
                </button>
            </div>
          </>
      )}
      <canvas ref={canvasRef} className="w-full h-full" style={{ imageRendering: config.PIXELATED ? 'pixelated' : 'auto' }} />
    </div>
  );
};

export default Game;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { COLORS } from '../constants';
import { GameConfig, CarModel, MapConfig, GameMode, LevelConfig } from '../types';
import { createEngine, createCar, generateTerrainChunk, generateClouds, createWall, TerrainChunk, Cloud, Decoration } from '../utils/physics';
import { SoundManager } from '../utils/audio';
import DebugMenu from './DebugMenu';

const Matter = (window as any).Matter;

interface GameProps {
  mode: GameMode;
  levelConfig?: LevelConfig;
  onGameOver: (distance: number, coins: number) => void;
  onLevelComplete: (coins: number) => void;
  selectedCar: CarModel;
  selectedMap: MapConfig;
  config: GameConfig;
  onUpdateConfig: (key: keyof GameConfig, value: any) => void;
  onResetConfig: () => void;
  onExit: () => void;
  onRestart: () => void;
  isMenuBackground?: boolean;
  onReady?: () => void;
}

interface Particle {
    x: number; y: number; vx: number; vy: number;
    life: number; maxLife: number; active: boolean;
    type: 'dust' | 'spark' | 'explosion' | 'smoke';
}

const Game: React.FC<GameProps> = ({ mode, levelConfig, onGameOver, onLevelComplete, selectedCar, selectedMap, config, onUpdateConfig, onResetConfig, onExit, onRestart, isMenuBackground = false, onReady }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const requestRef = useRef<number | null>(null);
  const engineRef = useRef<any>(null);
  const carRef = useRef<any>(null);
  const soundManagerRef = useRef<SoundManager | null>(null);

  // Game Logic Refs
  const chunksRef = useRef<TerrainChunk[]>([]);
  const cloudsRef = useRef<Cloud[]>([]);
  const collectedCoinIdsRef = useRef<Set<number>>(new Set());
  const collectedFuelIdsRef = useRef<Set<number>>(new Set());
  const particlesRef = useRef<Particle[]>([]);
  const lastChunkDataRef = useRef({ endX: 0, endY: 200, globalIndex: 0, segmentsSinceFuel: 0 });

  const fuelRef = useRef(config.MAX_FUEL);
  const wheelGroundContacts = useRef(0);
  const isOutOfFuelRef = useRef(false);
  const gameStateRef = useRef({ distance: 0, coins: 0, isGameOver: false, keys: { left: false, right: false } });

  // Visual state
  const cameraZoomRef = useRef(1.0);
  const cameraPosRef = useRef({ x: 0, y: 0 });
  const [isPaused, setIsPaused] = useState(false);
  const pausedRef = useRef(false);
  const [notification, setNotification] = useState<{text: string, subText?: string, id: number} | null>(null);
  const patternsRef = useRef<{[key: string]: CanvasPattern | null}>({});
  const starsRef = useRef<{x: number, y: number, r: number, opacity: number}[]>([]);

  // FPS Logic
  const lastFpsTimeRef = useRef(0);
  const frameCountRef = useRef(0);
  const hudFpsRef = useRef<HTMLDivElement>(null);

  // HUD Refs
  const hudDistanceRef = useRef<HTMLDivElement>(null);
  const hudCoinsRef = useRef<HTMLDivElement>(null);
  const hudFuelBarRef = useRef<HTMLDivElement>(null);

  // Setup Stars for Moon
  useEffect(() => {
    if (selectedMap.backgroundType === 'moon') {
        const s = [];
        for(let i=0; i<150; i++) {
            s.push({ x: Math.random() * 2000, y: Math.random() * 1000 - 500, r: Math.random() * 2, opacity: Math.random() });
        }
        starsRef.current = s;
    } else {
        starsRef.current = [];
    }
  }, [selectedMap]);

  const addChunk = useCallback((startX: number) => {
    const { endY, globalIndex, segmentsSinceFuel } = lastChunkDataRef.current;
    const length = config.CHUNK_SIZE;
    const chunkId = Math.floor(startX / length);

    const newChunk = generateTerrainChunk(
        chunkId, startX, endY, globalIndex, length, false, config, selectedMap.backgroundType, segmentsSinceFuel,
        mode === 'LEVELS' && levelConfig ? levelConfig.distance : null
    );

    if (engineRef.current) Matter.World.add(engineRef.current.world, newChunk.composite);

    if (selectedMap.backgroundType === 'earth' || selectedMap.backgroundType === 'highway') {
        const newClouds = generateClouds(startX, length);
        cloudsRef.current = [...cloudsRef.current, ...newClouds];
    }

    lastChunkDataRef.current = {
        endX: startX + length,
        endY: newChunk.endY,
        globalIndex: newChunk.endGlobalIndex,
        segmentsSinceFuel: newChunk.nextSegmentsSinceFuel
    };

    chunksRef.current.push(newChunk);

    // Cleanup old chunks and clouds to prevent memory leak
    if (chunksRef.current.length > 5) {
        const oldChunk = chunksRef.current.shift();
        if (oldChunk && engineRef.current) {
             Matter.Composite.remove(engineRef.current.world, oldChunk.composite);
        }
    }
    if (cloudsRef.current.length > 50) {
        cloudsRef.current = cloudsRef.current.slice(cloudsRef.current.length - 40);
    }
  }, [config, selectedMap.backgroundType, mode, levelConfig]);

  const handleResize = useCallback(() => {
    if (canvasRef.current && containerRef.current) {
        const rw = containerRef.current.clientWidth * config.RESOLUTION;
        const rh = containerRef.current.clientHeight * config.RESOLUTION;
        canvasRef.current.width = rw;
        canvasRef.current.height = rh;
        patternsRef.current = {}; 
    }
  }, [config.RESOLUTION]);

  useEffect(() => {
    window.addEventListener('resize', handleResize);
    handleResize();
    return () => window.removeEventListener('resize', handleResize);
  }, [handleResize]);

  // Initialization Sequence
  useEffect(() => {
    if (!isMenuBackground) soundManagerRef.current = new SoundManager();
    const engine = createEngine(config);
    engineRef.current = engine;
    const car = createCar(200, -100, selectedCar, config); 
    carRef.current = car;
    Matter.World.add(engine.world, [car, createWall(-1000)]);

    // Reset loop state
    lastChunkDataRef.current = { endX: 0, endY: 200, globalIndex: 0, segmentsSinceFuel: 0 };
    chunksRef.current = [];
    cloudsRef.current = [];
    collectedCoinIdsRef.current = new Set();
    collectedFuelIdsRef.current = new Set();
    fuelRef.current = config.MAX_FUEL;
    isOutOfFuelRef.current = false;
    gameStateRef.current.isGameOver = false;
    gameStateRef.current.distance = 0;
    gameStateRef.current.coins = 0;
    pausedRef.current = false;
    setIsPaused(false);

    let currentGenX = 0;
    const buffer = isMenuBackground ? 4000 : config.INITIAL_BUFFER_DISTANCE;
    while (currentGenX < buffer) {
        addChunk(currentGenX);
        currentGenX += config.CHUNK_SIZE;
    }

    particlesRef.current = Array.from({ length: config.PARTICLE_POOL_SIZE }).map(() => ({
        x: 0, y: 0, vx: 0, vy: 0, life: 0, maxLife: 0, active: false, type: 'dust'
    }));

    Matter.Events.on(engine, 'collisionStart', (event: any) => {
        event.pairs.forEach((pair: any) => {
            const { bodyA, bodyB } = pair;
            const isWheel = (b: any) => b.label === 'wheelBack' || b.label === 'wheelFront';
            const isGround = (b: any) => b.label === 'ground' || b.label === 'obstacle';

            if ((isWheel(bodyA) && isGround(bodyB)) || (isWheel(bodyB) && isGround(bodyA))) {
                wheelGroundContacts.current++;
                const w = isWheel(bodyA) ? bodyA : bodyB;
                const speed = Matter.Vector.magnitude(w.velocity);
                if (speed > 5) spawnParticles(w.position.x, w.position.y + 15, 2, speed > 10 ? 'spark' : 'dust');
            }

            if ((bodyA.label === 'chassis' && bodyB.label === 'ground') || (bodyB.label === 'chassis' && bodyA.label === 'ground')) {
                if (isMenuBackground) return;
                const chassis = bodyA.label === 'chassis' ? bodyA : bodyB;
                if (Math.abs(chassis.angle) > Math.PI / 1.5) {
                    gameStateRef.current.isGameOver = true;
                    soundManagerRef.current?.stopContinuous();
                    onGameOver(gameStateRef.current.distance, gameStateRef.current.coins);
                }
            }

            let item = null;
            if (['chassis', 'wheelBack', 'wheelFront'].includes(bodyA.label) && ['coin', 'fuel', 'finishLine'].includes(bodyB.label)) item = bodyB;
            if (['chassis', 'wheelBack', 'wheelFront'].includes(bodyB.label) && ['coin', 'fuel', 'finishLine'].includes(bodyA.label)) item = bodyA;

            if (item && !isMenuBackground) {
                if (item.label === 'finishLine') {
                    gameStateRef.current.isGameOver = true;
                    onLevelComplete(gameStateRef.current.coins);
                } else if (!collectedCoinIdsRef.current.has(item.id) && !collectedFuelIdsRef.current.has(item.id)) {
                    if (item.label === 'coin') {
                        collectedCoinIdsRef.current.add(item.id);
                        gameStateRef.current.coins += config.COIN_VALUE;
                        soundManagerRef.current?.playCoinSound();
                        Matter.World.remove(engine.world, item);
                    } else if (item.label === 'fuel') {
                        collectedFuelIdsRef.current.add(item.id);
                        fuelRef.current = Math.min(config.MAX_FUEL, fuelRef.current + config.FUEL_CAN_VALUE);
                        isOutOfFuelRef.current = false;
                        setNotification({ text: "FUEL!", id: Date.now() });
                        setTimeout(() => setNotification(null), 1500);
                        Matter.World.remove(engine.world, item);
                    }
                }
            }
        });
    });

    Matter.Events.on(engine, 'collisionEnd', (event: any) => {
        event.pairs.forEach((pair: any) => {
            const isWheel = (b: any) => b.label === 'wheelBack' || b.label === 'wheelFront';
            const isGround = (b: any) => b.label === 'ground' || b.label === 'obstacle';
            if ((isWheel(pair.bodyA) && isGround(pair.bodyB)) || (isWheel(pair.bodyB) && isGround(pair.bodyA))) {
                wheelGroundContacts.current = Math.max(0, wheelGroundContacts.current - 1);
            }
        });
    });

    // Notify parent that we are ready to start playing
    if (onReady) onReady();

    requestRef.current = requestAnimationFrame(animate);
    return () => {
        if (requestRef.current) cancelAnimationFrame(requestRef.current);
        Matter.Engine.clear(engine);
        if (soundManagerRef.current) soundManagerRef.current.stopContinuous();
    };
  }, [addChunk, selectedCar, onGameOver, onLevelComplete, config, isMenuBackground, onReady]);

  const handleResume = useCallback(() => {
    pausedRef.current = false;
    setIsPaused(false);
  }, []);

  const spawnParticles = (x: number, y: number, count: number, type: 'dust' | 'spark' | 'explosion' | 'smoke') => {
      let spawned = 0;
      for (let p of particlesRef.current) {
          if (spawned >= count) break;
          if (!p.active) {
              p.active = true; p.x = x; p.y = y; p.type = type;
              p.maxLife = config.PARTICLE_LIFETIME; p.life = p.maxLife;
              if (type === 'smoke') {
                  p.vx = (Math.random() - 0.5) * 2 - 2; // Smoke blows back
                  p.vy = (Math.random() - 0.5) * 2;
                  p.maxLife = 60;
                  p.life = 60;
              } else {
                  p.vx = (Math.random() - 0.5) * 5; 
                  p.vy = (Math.random() - 0.5) * 5;
              }
              spawned++;
          }
      }
  };

  const getPattern = (ctx: CanvasRenderingContext2D, type: string, color1: string, color2: string) => {
      const key = `${type}-${color1}-${color2}`;
      if (patternsRef.current[key]) return patternsRef.current[key];
      const pCanvas = document.createElement('canvas');
      const pCtx = pCanvas.getContext('2d')!;
      pCanvas.width = 40; pCanvas.height = 40;
      if (type === 'ground') {
          // Noise texture
          pCtx.fillStyle = color1; pCtx.fillRect(0,0,40,40);
          pCtx.fillStyle = color2; 
          for(let i=0; i<30; i++) {
              pCtx.globalAlpha = 0.1 + Math.random() * 0.2;
              pCtx.beginPath(); 
              pCtx.arc(Math.random()*40, Math.random()*40, 1 + Math.random()*2, 0, Math.PI*2);
              pCtx.fill();
          }
      } else if (type === 'striped') {
          pCanvas.width = 20; pCtx.fillStyle = color1; pCtx.fillRect(0,0,20,40);
          pCtx.fillStyle = color2; pCtx.fillRect(0,0,10,40);
      } else if (type === 'checker') {
          pCanvas.width = 20; pCanvas.height = 20;
          pCtx.fillStyle = color1; pCtx.fillRect(0,0,20,20);
          pCtx.fillStyle = color2; pCtx.fillRect(0,0,10,10); pCtx.fillRect(10,10,10,10);
      } else if (type === 'dots') {
          pCanvas.width = 10; pCanvas.height = 10;
          pCtx.fillStyle = color1; pCtx.fillRect(0,0,10,10);
          pCtx.fillStyle = color2; pCtx.beginPath(); pCtx.arc(5,5,2,0,Math.PI*2); pCtx.fill();
      } else if (type === 'gradient') {
          const g = pCtx.createLinearGradient(0,0,0,40);
          g.addColorStop(0, color2);
          g.addColorStop(1, color1);
          pCtx.fillStyle = g;
          pCtx.fillRect(0,0,40,40);
      }
      const pattern = ctx.createPattern(pCanvas, 'repeat');
      patternsRef.current[key] = pattern;
      return pattern;
  };

  const drawChassisPath = (ctx: CanvasRenderingContext2D, car: CarModel, cw: number, ch: number, wr: number) => {
      ctx.beginPath();
      const halfW = cw / 2;
      const halfH = ch / 2;

      // Calculate wheel positions relative to center
      // Based on createCar logic: offset = -cw/2 + wr
      const rearWheelX = -halfW + wr;
      const frontWheelX = halfW - wr;
      const wellR = wr + 4; // Slight clearance for wheel well

      // -- UNDERCARRIAGE with Wheel Wells --
      // Start at Bottom-Left (before rear well)
      ctx.moveTo(-halfW, halfH); 

      // Rear Well
      ctx.arc(rearWheelX, halfH, wellR, Math.PI, 0); 

      // Front Well
      ctx.arc(frontWheelX, halfH, wellR, Math.PI, 0);

      // To Front Bumper Bottom
      ctx.lineTo(halfW, halfH);

      // -- UPPER BODY SHAPES --
      if (car.shape === 'coupe' || !car.shape) {
          ctx.lineTo(halfW * 1.1, 0); // Nose slope
          ctx.quadraticCurveTo(halfW * 0.8, -halfH * 0.7, halfW * 0.1, -halfH * 0.9); // Windshield
          ctx.lineTo(-halfW * 0.4, -halfH * 0.9); // Roof
          ctx.quadraticCurveTo(-halfW, -halfH * 0.9, -halfW, -halfH * 0.2); // Rear Slope
      } else if (car.shape === 'jeep') {
          ctx.lineTo(halfW * 1.1, halfH); // Front bumper vertical
          ctx.lineTo(halfW * 1.1, -halfH * 0.2); // Hood front
          ctx.lineTo(halfW * 0.6, -halfH * 0.2); // Hood top
          ctx.lineTo(halfW * 0.6, -halfH * 1.6); // Windshield
          ctx.lineTo(-halfW * 0.5, -halfH * 1.6); // Roof
          ctx.lineTo(-halfW * 0.5, -halfH * 0.5); // Bed front
          ctx.lineTo(-halfW * 0.9, -halfH * 0.5); // Bed top
      } else if (car.shape === 'racer') {
          ctx.lineTo(halfW * 1.5, halfH * 0.3); // Nose tip
          ctx.quadraticCurveTo(halfW * 1.0, -halfH * 0.3, halfW * 0.3, -halfH * 0.5); // Body slope
          ctx.lineTo(-halfW * 0.5, -halfH * 0.5); // Engine cover
          ctx.lineTo(-halfW * 1.2, -halfH * 0.3); // Spoiler mount
          ctx.lineTo(-halfW * 1.2, halfH * 0.2); // Rear
      } else if (car.shape === 'buggy') {
          ctx.lineTo(halfW * 0.9, halfH * 0.5); // Nose
          ctx.lineTo(halfW * 1.1, 0);
          ctx.lineTo(halfW * 0.9, 0); 
          ctx.lineTo(halfW * 0.4, -halfH * 1.4); // Rollcage Front
          ctx.lineTo(-halfW * 0.5, -halfH * 1.4); // Rollcage Top
          ctx.lineTo(-halfW * 0.7, 0); // Rollcage Rear
      } else if (car.shape === 'van') {
          ctx.lineTo(halfW * 1.1, halfH * 0.5);
          ctx.quadraticCurveTo(halfW * 1.1, -halfH * 1.2, halfW * 0.7, -halfH * 1.3); // Front curve
          ctx.lineTo(-halfW * 0.9, -halfH * 1.3); // Roof
          ctx.lineTo(-halfW * 0.9, halfH * 0.5); // Rear
      } else if (car.shape === 'supercar') {
          ctx.lineTo(halfW * 1.45, halfH * 0.5); // Nose
          ctx.quadraticCurveTo(halfW * 1.0, -halfH * 0.4, halfW * 0.1, -halfH * 0.6); // Hood
          ctx.lineTo(-halfW * 0.5, -halfH * 0.6); // Rear Deck
          ctx.lineTo(-halfW * 1.1, 0); 
          ctx.lineTo(-halfW * 1.1, halfH * 0.5);
      } else if (car.shape === 'bike') {
           ctx.lineTo(halfW * 0.3, 0);
           ctx.lineTo(halfW * 0.4, -halfH * 0.4); 
           ctx.lineTo(0, -halfH * 0.7); 
           ctx.lineTo(-halfW * 0.5, 0);
      }

      ctx.closePath();
  };

  const drawCarDetails = (ctx: CanvasRenderingContext2D, car: CarModel, cw: number, ch: number) => {
      const halfW = cw / 2;
      const halfH = ch / 2;

      // 1. Headlights (with glow)
      ctx.save();
      ctx.translate(halfW, 0);

      const grad = ctx.createLinearGradient(0, 0, 150, 0);
      grad.addColorStop(0, 'rgba(255, 255, 200, 0.4)');
      grad.addColorStop(1, 'rgba(255, 255, 200, 0)');
      ctx.fillStyle = grad;
      ctx.beginPath(); ctx.moveTo(0, -5); ctx.lineTo(150, -40); ctx.lineTo(150, 40); ctx.lineTo(0, 5); ctx.fill();

      ctx.fillStyle = '#fef08a';
      ctx.shadowColor = '#fef08a'; ctx.shadowBlur = 10;
      if (car.shape === 'jeep' || car.shape === 'van') {
           ctx.fillRect(halfW * 0.05, -15, 5, 20);
      } else if (car.shape === 'bike') {
           ctx.beginPath(); ctx.arc(halfW * 0.3, -10, 8, 0, Math.PI*2); ctx.fill();
      } else {
           ctx.beginPath(); ctx.ellipse(halfW * 0.15, 0, 4, 12, 0, 0, Math.PI*2); ctx.fill();
      }
      ctx.restore();

      // 2. Windows - Gradient glass
      const glassGrad = ctx.createLinearGradient(0, -ch, 0, 0);
      glassGrad.addColorStop(0, '#38bdf8');
      glassGrad.addColorStop(1, '#1e293b');
      ctx.fillStyle = glassGrad;
      ctx.strokeStyle = '#334155'; ctx.lineWidth = 1;

      if (car.shape === 'coupe') {
          ctx.beginPath();
          ctx.moveTo(-halfW * 0.3, -halfH * 0.75);
          ctx.lineTo(halfW * 0.1, -halfH * 0.75);
          ctx.lineTo(halfW * 0.5, -halfH * 0.1);
          ctx.lineTo(-halfW * 0.3, -halfH * 0.1);
          ctx.fill(); ctx.stroke();
      } else if (car.shape === 'supercar') {
          ctx.beginPath();
          ctx.moveTo(-halfW * 0.2, -halfH * 0.5);
          ctx.lineTo(halfW * 0.2, -halfH * 0.5);
          ctx.lineTo(halfW * 0.6, -halfH * 0.1);
          ctx.lineTo(-halfW * 0.4, -halfH * 0.1);
          ctx.fill(); ctx.stroke();
      } else if (car.shape === 'jeep') {
          ctx.fillRect(-halfW * 0.4, -halfH * 1.3, cw * 0.35, ch * 0.5); // Side
          ctx.fillRect(halfW * 0.1, -halfH * 1.3, cw * 0.35, ch * 0.5); // Front
      } else if (car.shape === 'van') {
          ctx.fillRect(-halfW * 0.8, -halfH * 1.1, cw * 0.35, ch * 0.5);
          ctx.fillRect(-halfW * 0.3, -halfH * 1.1, cw * 0.45, ch * 0.5);
      }

      // 3. Extra Details
      ctx.fillStyle = '#111';
      if (car.shape === 'racer' || car.shape === 'supercar') {
          // Spoiler
          ctx.fillStyle = car.bodyColor;
          ctx.beginPath();
          ctx.moveTo(-halfW * 1.1, -halfH * 0.2);
          ctx.lineTo(-halfW * 1.25, -halfH * 1.4);
          ctx.lineTo(-halfW * 0.7, -halfH * 1.4);
          ctx.lineTo(-halfW * 0.6, -halfH * 0.2);
          ctx.fill(); 
          ctx.stroke();
          // Wing
          ctx.fillStyle = '#111';
          ctx.fillRect(-halfW * 1.3, -halfH * 1.5, cw * 0.6, 6);
      } else if (car.shape === 'buggy') {
          ctx.strokeStyle = '#64748b';
          ctx.lineWidth = 3;
          ctx.beginPath();
          ctx.moveTo(-halfW * 0.7, 0); ctx.lineTo(halfW * 0.9, 0); 
          ctx.moveTo(-halfW * 0.5, -halfH * 1.4); ctx.lineTo(halfW * 0.4, -halfH * 1.4);
          ctx.lineTo(halfW * 0.9, 0);
          ctx.stroke();
      }

      // 4. Exhaust
      const exhaustX = -halfW * 1.0;
      const exhaustY = halfH * 0.3;
      ctx.fillStyle = '#444';
      if (car.shape !== 'bike') {
          ctx.fillRect(exhaustX - 8, exhaustY, 15, 8);
          ctx.fillStyle = '#000';
          ctx.beginPath(); ctx.arc(exhaustX - 8, exhaustY + 4, 3, 0, Math.PI*2); ctx.fill();
      }

      if (Math.random() > 0.7 && !isMenuBackground && Math.abs(carRef.current.bodies[0].velocity.x) > 1) {
          spawnParticles(
              carRef.current.bodies[0].position.x + exhaustX, 
              carRef.current.bodies[0].position.y + exhaustY + 4, 
              1, 'smoke'
          );
      }
  };

  const drawWheel = (ctx: CanvasRenderingContext2D, x: number, y: number, r: number, angle: number, color: string) => {
      ctx.save();
      ctx.translate(x, y);
      ctx.rotate(angle);

      // Tire
      ctx.beginPath(); ctx.arc(0, 0, r, 0, Math.PI * 2); 
      ctx.fillStyle = '#1c1917'; ctx.fill(); // Dark rubber

      // Detailed Tread
      ctx.strokeStyle = '#292524'; ctx.lineWidth = 4;
      ctx.setLineDash([5, 8]);
      ctx.beginPath(); ctx.arc(0,0, r-2, 0, Math.PI*2); ctx.stroke();
      ctx.setLineDash([]);

      // Rim
      const rimR = r * 0.65;
      ctx.beginPath(); ctx.arc(0, 0, rimR, 0, Math.PI * 2);
      ctx.fillStyle = color; ctx.fill();
      ctx.strokeStyle = '#444'; ctx.lineWidth = 2; ctx.stroke();

      // Spokes
      ctx.strokeStyle = '#000'; ctx.lineWidth = 3; ctx.lineCap = 'round';
      const spokes = 5;
      for (let i = 0; i < spokes; i++) {
          ctx.rotate((Math.PI * 2) / spokes);
          ctx.beginPath(); ctx.moveTo(0, 0); ctx.lineTo(0, rimR - 3); ctx.stroke();
      }

      // Center Hub
      ctx.beginPath(); ctx.arc(0, 0, r * 0.15, 0, Math.PI * 2);
      ctx.fillStyle = '#555'; ctx.fill();
      ctx.beginPath(); ctx.arc(0, 0, r * 0.08, 0, Math.PI * 2);
      ctx.fillStyle = '#222'; ctx.fill();

      ctx.restore();
  };

  const drawSuspension = (ctx: CanvasRenderingContext2D, chassisBody: any, wheelBody: any, offsetX: number, offsetY: number) => {
      const cAngle = chassisBody.angle;
      const worldOffsetX = offsetX * Math.cos(cAngle) - offsetY * Math.sin(cAngle);
      const worldOffsetY = offsetX * Math.sin(cAngle) + offsetY * Math.cos(cAngle);

      const p1 = { x: chassisBody.position.x + worldOffsetX, y: chassisBody.position.y + worldOffsetY };
      const p2 = { x: wheelBody.position.x, y: wheelBody.position.y };

      const dist = Math.hypot(p2.x - p1.x, p2.y - p1.y);
      const angle = Math.atan2(p2.y - p1.y, p2.x - p1.x);

      ctx.save();
      ctx.translate(p1.x, p1.y);
      ctx.rotate(angle);

      // Upper strut
      ctx.strokeStyle = '#444'; ctx.lineWidth = 6;
      ctx.beginPath(); ctx.moveTo(0, 0); ctx.lineTo(dist/2, 0); ctx.stroke();

      // Lower strut
      ctx.strokeStyle = '#999'; ctx.lineWidth = 4;
      ctx.beginPath(); ctx.moveTo(dist/2, 0); ctx.lineTo(dist, 0); ctx.stroke();

      // Coil
      ctx.strokeStyle = '#dc2626'; ctx.lineWidth = 2.5;
      ctx.beginPath();
      ctx.moveTo(0, 0);
      const zigs = 8;
      for(let i=0; i<=zigs; i++) {
          ctx.lineTo((dist / zigs) * i, i % 2 === 0 ? -5 : 5);
      }
      ctx.stroke();
      ctx.restore();
  };

  const drawCloud = (ctx: CanvasRenderingContext2D, cloud: Cloud) => {
      ctx.save();
      ctx.translate(cloud.x, cloud.y);
      ctx.scale(cloud.scale, cloud.scale);

      ctx.fillStyle = 'rgba(255,255,255,0.7)';

      ctx.beginPath();
      ctx.arc(0, 0, 30, 0, Math.PI * 2);
      ctx.arc(35, 5, 40, 0, Math.PI * 2);
      ctx.arc(-35, 5, 35, 0, Math.PI * 2);
      ctx.arc(15, -25, 30, 0, Math.PI * 2);
      ctx.arc(-15, -25, 30, 0, Math.PI * 2);

      ctx.fill();
      ctx.restore();
  };

  const drawTree = (ctx: CanvasRenderingContext2D, type: number, seed: number) => {
    // Trunk
    ctx.fillStyle = COLORS.treeTrunk;
    const trunkW = 12 + seed * 4;
    const trunkH = 40 + seed * 20;
    ctx.fillRect(-trunkW/2, -trunkH, trunkW, trunkH);

    // Leaves
    if (type === 6) { // Pine
        ctx.fillStyle = COLORS.treeLeafDark;
        ctx.beginPath();
        ctx.moveTo(-40, -trunkH + 10);
        ctx.lineTo(0, -trunkH - 100 - seed * 50);
        ctx.lineTo(40, -trunkH + 10);
        ctx.fill();

        ctx.fillStyle = COLORS.treeLeafLight;
        ctx.beginPath();
        ctx.moveTo(-30, -trunkH - 20);
        ctx.lineTo(0, -trunkH - 100 - seed * 50);
        ctx.lineTo(30, -trunkH - 20);
        ctx.fill();
    } else { // Round
        ctx.fillStyle = COLORS.treeLeafDark;
        ctx.beginPath();
        ctx.arc(0, -trunkH - 20, 40 + seed * 10, 0, Math.PI * 2);
        ctx.fill();

        ctx.fillStyle = COLORS.treeLeafLight;
        ctx.beginPath();
        ctx.arc(-10, -trunkH - 30, 30 + seed * 10, 0, Math.PI * 2);
        ctx.fill();
    }
  };

  const drawRock = (ctx: CanvasRenderingContext2D, seed: number) => {
      ctx.fillStyle = COLORS.boulder;
      ctx.beginPath();
      ctx.moveTo(-20 - seed * 10, 0);
      ctx.lineTo(-15 - seed * 5, -20 - seed * 15);
      ctx.lineTo(10 + seed * 5, -25 - seed * 10);
      ctx.lineTo(25 + seed * 10, 0);
      ctx.fill();

      // Detail
      ctx.fillStyle = COLORS.boulderDark;
      ctx.beginPath();
      ctx.moveTo(-10, -5);
      ctx.lineTo(0, -15);
      ctx.lineTo(10, -5);
      ctx.fill();
  };

  const drawBush = (ctx: CanvasRenderingContext2D, seed: number) => {
     ctx.fillStyle = COLORS.bushDark;
     ctx.beginPath();
     ctx.arc(-15, -10, 15 + seed * 5, 0, Math.PI * 2);
     ctx.arc(15, -10, 12 + seed * 5, 0, Math.PI * 2);
     ctx.arc(0, -20, 18 + seed * 5, 0, Math.PI * 2);
     ctx.fill();

     ctx.fillStyle = COLORS.bushLight;
     ctx.beginPath();
     ctx.arc(0, -20, 10 + seed * 3, 0, Math.PI * 2);
     ctx.fill();
  };

  const animate = useCallback(() => {
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d', { alpha: false });
    if (!canvas || !ctx || gameStateRef.current.isGameOver) {
        requestRef.current = requestAnimationFrame(animate);
        return;
    }

    if (!pausedRef.current) {
        Matter.Engine.update(engineRef.current, 1000 / 60);
        const chassis = carRef.current.bodies.find((b: any) => b.label === 'chassis');
        const wheelB = carRef.current.bodies.find((b: any) => b.label === 'wheelBack');
        const wheelF = carRef.current.bodies.find((b: any) => b.label === 'wheelFront');

        const { keys } = gameStateRef.current;
        const speedRatio = Matter.Vector.magnitude(chassis.velocity) / 25;
        const isGrounded = wheelGroundContacts.current > 0;

        if (!isMenuBackground) {
            soundManagerRef.current?.updateContinuous(speedRatio, isGrounded, keys.right && !isOutOfFuelRef.current);
            if (keys.right && !isOutOfFuelRef.current) {
                fuelRef.current -= config.FUEL_CONSUMPTION;
                if (fuelRef.current <= 0) {
                    fuelRef.current = 0; isOutOfFuelRef.current = true;
                    setNotification({ text: "OUT OF FUEL", id: Date.now() });
                    setTimeout(() => { if (!gameStateRef.current.isGameOver) onGameOver(gameStateRef.current.distance, gameStateRef.current.coins); }, 3000);
                }
                const power = selectedCar.acceleration;
                if (selectedCar.driveTrain !== 'FWD') Matter.Body.setAngularVelocity(wheelB, Math.min(wheelB.angularVelocity + power, selectedCar.speed));
                if (selectedCar.driveTrain !== 'RWD') Matter.Body.setAngularVelocity(wheelF, Math.min(wheelF.angularVelocity + power, selectedCar.speed));
                if (chassis.angularVelocity > -config.MAX_ROTATION_SPEED) Matter.Body.setAngularVelocity(chassis, chassis.angularVelocity - (isGrounded ? config.GROUND_ROTATION_SPEED : config.AIR_ROTATION_SPEED));
            } else if (keys.left) {
                 if (selectedCar.driveTrain !== 'FWD') Matter.Body.setAngularVelocity(wheelB, Math.max(wheelB.angularVelocity - 0.1, -selectedCar.speed/2));
                 if (selectedCar.driveTrain !== 'RWD') Matter.Body.setAngularVelocity(wheelF, Math.max(wheelF.angularVelocity - 0.1, -selectedCar.speed/2));
                 if (chassis.angularVelocity < config.MAX_ROTATION_SPEED) Matter.Body.setAngularVelocity(chassis, chassis.angularVelocity + (isGrounded ? config.GROUND_ROTATION_SPEED : config.AIR_ROTATION_SPEED));
            }
        } else {
            Matter.Body.setAngularVelocity(wheelB, 0.4); Matter.Body.setAngularVelocity(wheelF, 0.4);
            if (chassis.position.y > 500) Matter.Body.setPosition(chassis, { x: 200, y: -100 });
        }

        cameraPosRef.current = { x: chassis.position.x, y: chassis.position.y };
        if (chassis.position.x > lastChunkDataRef.current.endX - config.RENDER_DISTANCE) addChunk(lastChunkDataRef.current.endX);
        gameStateRef.current.distance = Math.max(0, Math.floor((chassis.position.x - 200) / 10));

        if (hudDistanceRef.current) hudDistanceRef.current.innerText = `${gameStateRef.current.distance}`;
        if (hudCoinsRef.current) hudCoinsRef.current.innerText = `${gameStateRef.current.coins}`;
        if (hudFuelBarRef.current) hudFuelBarRef.current.style.width = `${(fuelRef.current / config.MAX_FUEL) * 100}%`;
    }

    // --- RENDERING ---
    const zoom = cameraZoomRef.current;
    const vH = config.BASE_VIEWPORT_HEIGHT * zoom;
    const vW = (canvas.width / canvas.height) * vH; 
    const scale = canvas.height / vH;

    const camX = cameraPosRef.current.x - vW * 0.3;
    const camY = cameraPosRef.current.y - vH * 0.6;

    ctx.setTransform(scale, 0, 0, scale, -camX * scale, -camY * scale);

    // Sky
    const skyGrad = ctx.createLinearGradient(camX, camY, camX, camY + vH);
    skyGrad.addColorStop(0, selectedMap.skyColorStart); skyGrad.addColorStop(1, selectedMap.skyColorEnd);
    ctx.fillStyle = skyGrad; ctx.fillRect(camX, camY, vW, vH);

    // Sun/Moon Glow
    if (selectedMap.backgroundType !== 'moon') {
        const sunGrad = ctx.createRadialGradient(camX + vW - 100, camY + 100, 20, camX + vW - 100, camY + 100, 200);
        sunGrad.addColorStop(0, 'rgba(255, 255, 200, 0.6)');
        sunGrad.addColorStop(1, 'rgba(255, 255, 200, 0)');
        ctx.fillStyle = sunGrad; ctx.fillRect(camX, camY, vW, vH/2);
    }

    if (starsRef.current.length > 0) {
        ctx.fillStyle = 'white';
        starsRef.current.forEach(s => {
            const px = s.x + camX * 0.85; 
            if (px > camX && px < camX + vW) {
                ctx.globalAlpha = s.opacity; ctx.beginPath(); ctx.arc(px, s.y, s.r, 0, Math.PI*2); ctx.fill();
            }
        });
        ctx.globalAlpha = 1;
    }

    cloudsRef.current.forEach(c => {
        if (c.x > camX - 400 && c.x < camX + vW + 400) {
            drawCloud(ctx, c);
        }
    });

    const groundPat = getPattern(ctx, 'ground', selectedMap.groundColor, selectedMap.groundDarkColor);
    ctx.fillStyle = groundPat || selectedMap.groundColor;

    chunksRef.current.forEach(chunk => {
        if (chunk.endX < camX || chunk.pathData[0].x > camX + vW) return;

        ctx.beginPath(); ctx.moveTo(chunk.pathData[0].x, chunk.pathData[0].y);
        chunk.pathData.forEach(p => ctx.lineTo(p.x, p.y));
        ctx.lineTo(chunk.endX, chunk.endY + 1000); ctx.lineTo(chunk.pathData[0].x, chunk.pathData[0].y + 1000);
        ctx.fill(); 

        if (selectedMap.backgroundType === 'earth') {
             ctx.strokeStyle = COLORS.grassDetail; ctx.lineWidth = 10;
        } else if (selectedMap.backgroundType === 'moon') {
             ctx.strokeStyle = '#94a3b8'; ctx.lineWidth = 6;
        } else {
             ctx.strokeStyle = '#475569'; ctx.lineWidth = 8;
        }
        ctx.beginPath();
        chunk.pathData.forEach((p, i) => {
            if (i===0) ctx.moveTo(p.x, p.y);
            else ctx.lineTo(p.x, p.y);
        });
        ctx.stroke();

        chunk.decorations.forEach(d => {
            if (d.x < camX - 100 || d.x > camX + vW + 100) return;
            ctx.save(); ctx.translate(d.x, d.y); ctx.rotate(d.angle); ctx.scale(d.scale, d.scale);

            if (d.type === 5) { 
                ctx.fillStyle = 'white'; ctx.fillRect(0,-200,6,200); 
                ctx.fillStyle = '#ef4444'; ctx.beginPath(); ctx.moveTo(6,-200); ctx.lineTo(70,-175); ctx.lineTo(6,-150); ctx.fill();
            } else if (d.type === 3) { 
                ctx.fillStyle = COLORS.lampPost; ctx.fillRect(-2,-80,4,80); 
                ctx.fillStyle = COLORS.lampLight; ctx.beginPath(); ctx.arc(10,-80,6,0,Math.PI*2); ctx.fill();
                ctx.fillStyle = COLORS.lampGlow; ctx.beginPath(); ctx.arc(10,-80,20,0,Math.PI*2); ctx.fill();
            } else if (d.type === 4) { 
                ctx.fillStyle = '#78350f'; ctx.fillRect(-2,-20,4,20);
                ctx.fillRect(-20,-15,40,4);
            } else if (d.type === 6 || d.type === 7) { 
                drawTree(ctx, d.type, d.seed);
            } else if (d.type === 8) { 
                drawRock(ctx, d.seed);
            } else if (d.type === 9) { 
                drawBush(ctx, d.seed);
            } else if (selectedMap.backgroundType === 'earth') {
                 ctx.strokeStyle = COLORS.grassDetail; ctx.lineWidth = 2; 
                 ctx.beginPath(); 
                 ctx.moveTo(0,0); ctx.lineTo(-3, -8 - d.seed * 5);
                 ctx.moveTo(0,0); ctx.lineTo(3, -6 - d.seed * 5);
                 ctx.stroke();
            }
            ctx.restore();
        });

        chunk.coinBodies.forEach(b => {
            if (!collectedCoinIdsRef.current.has(b.id) && b.position.x > camX - 50 && b.position.x < camX + vW + 50) {
                ctx.save(); ctx.translate(b.position.x, b.position.y);
                const pulse = Math.sin(Date.now() / 200) * 0.1 + 1;
                ctx.scale(pulse, pulse);
                ctx.fillStyle = COLORS.coinOuter; ctx.beginPath(); ctx.arc(0,0,config.COIN_SIZE,0,Math.PI*2); ctx.fill();
                ctx.fillStyle = COLORS.coinInner; ctx.beginPath(); ctx.arc(0,0,config.COIN_SIZE*0.7,0,Math.PI*2); ctx.fill();
                ctx.fillStyle = '#fff'; ctx.font = 'bold 12px monospace'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle'; ctx.fillText('$', 0, 1);
                ctx.restore();
            }
        });

        chunk.fuelBodies.forEach(b => {
            if (!collectedFuelIdsRef.current.has(b.id) && b.position.x > camX - 50 && b.position.x < camX + vW + 50) {
                ctx.save(); ctx.translate(b.position.x, b.position.y);
                const pulse = Math.sin(Date.now() / 300) * 0.1 + 1;
                ctx.scale(pulse, pulse);
                ctx.fillStyle = COLORS.fuelCan; 
                ctx.fillRect(-10, -15, 20, 30);
                ctx.fillStyle = COLORS.fuelCanCap;
                ctx.fillRect(-6, -18, 12, 3);
                ctx.font = 'bold 10px sans-serif'; ctx.fillStyle = 'white'; ctx.fillText('FUEL', -10, 5);
                ctx.restore();
            }
        });
    });

    // --- CAR RENDER ---
    const chassis = carRef.current.bodies.find((b: any) => b.label === 'chassis');
    const wheelB = carRef.current.bodies.find((b: any) => b.label === 'wheelBack');
    const wheelF = carRef.current.bodies.find((b: any) => b.label === 'wheelFront');
    const cw = selectedCar.width || config.CAR_WIDTH; 
    const ch = selectedCar.height || config.CAR_HEIGHT;
    const wr = selectedCar.wheelSize || config.WHEEL_SIZE;

    // Draw Suspension (BEHIND everything)
    const wheelOffsetX = -cw / 2 + wr;
    const wheelOffsetY = ch / 2;
    drawSuspension(ctx, chassis, wheelB, wheelOffsetX, wheelOffsetY);
    drawSuspension(ctx, chassis, wheelF, -wheelOffsetX, wheelOffsetY);

    // Draw Wheels (BEHIND Chassis)
    [wheelB, wheelF].forEach(w => {
        drawWheel(ctx, w.position.x, w.position.y, wr, w.angle, selectedCar.wheelColor);
    });

    // Draw Chassis (ON TOP)
    ctx.save(); ctx.translate(chassis.position.x, chassis.position.y); ctx.rotate(chassis.angle);

    ctx.shadowColor = 'rgba(0,0,0,0.5)'; ctx.shadowBlur = 10;
    let bodyFill: string | CanvasPattern = selectedCar.bodyColor;
    if (selectedCar.texture !== 'plain') bodyFill = getPattern(ctx, selectedCar.texture, selectedCar.bodyColor, selectedCar.textureColor2) || bodyFill;

    if (selectedCar.imageUrl) {
        // ... (image logic from previous turn)
    }

    ctx.fillStyle = bodyFill;
    ctx.strokeStyle = 'rgba(0,0,0,0.6)'; ctx.lineWidth = 2;

    // Pass wheel radius to calculate arches
    drawChassisPath(ctx, selectedCar, cw, ch, wr);
    ctx.fill(); 
    ctx.shadowBlur = 0; 
    ctx.stroke();

    drawCarDetails(ctx, selectedCar, cw, ch);

    ctx.restore();

    particlesRef.current.forEach(p => {
        if (p.active) {
            ctx.fillStyle = p.type === 'spark' ? COLORS.particleSpark : 
                            p.type === 'smoke' ? COLORS.particleSmoke : COLORS.particleDust; 
            ctx.globalAlpha = p.life / p.maxLife;
            ctx.beginPath(); 
            if (p.type === 'smoke') {
                const r = 4 + (1 - p.life/p.maxLife) * 8;
                ctx.arc(p.x, p.y, r, 0, Math.PI*2);
            } else {
                ctx.arc(p.x, p.y, 2.5, 0, Math.PI*2); 
            }
            ctx.fill();
            p.x += p.vx; p.y += p.vy; 
            if (p.type !== 'smoke') p.vy += 0.2; 
            else { p.vx *= 0.95; p.vy -= 0.05; } 
            p.life--; if (p.life <= 0) p.active = false;
        }
    });
    ctx.globalAlpha = 1;

    const now = performance.now(); frameCountRef.current++;
    if (now - lastFpsTimeRef.current >= 500) {
        const fps = Math.round((frameCountRef.current * 1000) / (now - lastFpsTimeRef.current));
        if (hudFpsRef.current) hudFpsRef.current.innerText = `${fps} FPS`;
        lastFpsTimeRef.current = now; frameCountRef.current = 0;
    }

    requestRef.current = requestAnimationFrame(animate);
  }, [config, selectedCar, selectedMap, onGameOver, onLevelComplete, isMenuBackground]);

  return (
    <div ref={containerRef} className={`relative w-full h-full bg-slate-900 overflow-hidden select-none ${isMenuBackground ? 'opacity-40 pointer-events-none' : ''}`}>
      {!isMenuBackground && (
          <>
            <div className="absolute top-4 right-4 z-30 flex gap-2">
                <div ref={hudFpsRef} className="font-mono text-xs text-emerald-500 bg-black/60 px-2 py-1 rounded">60 FPS</div>
                <button onClick={() => { pausedRef.current = !pausedRef.current; setIsPaused(!isPaused); }} className="w-10 h-10 bg-black/60 text-white rounded flex items-center justify-center border border-white/20 hover:bg-white/10 active:scale-95 transition-all">
                    {isPaused ? "▶" : "⏸"}
                </button>
            </div>

            {isPaused && (
                <div className="absolute inset-0 z-40 flex flex-col items-center justify-center bg-black/80 backdrop-blur-md animate-fade-in">
                    <div className="p-8 bg-neutral-900/90 border border-neutral-700 rounded-2xl shadow-2xl flex flex-col items-center gap-6 min-w-[300px]">
                        <h2 className="text-4xl font-black italic text-white tracking-widest uppercase border-b-4 border-amber-500 pb-2 mb-2">
                            Paused
                        </h2>

                        <div className="flex flex-col gap-3 w-full">
                            <button 
                                onClick={handleResume}
                                className="w-full py-4 bg-emerald-600 hover:bg-emerald-500 text-white font-black italic uppercase tracking-wider rounded-lg shadow-lg hover:scale-[1.02] active:scale-95 transition-all flex items-center justify-center gap-2"
                            >
                                <span>▶</span> Resume
                            </button>

                            <button 
                                onClick={onRestart}
                                className="w-full py-4 bg-neutral-700 hover:bg-neutral-600 text-white font-bold uppercase tracking-wider rounded-lg shadow-lg hover:scale-[1.02] active:scale-95 transition-all flex items-center justify-center gap-2"
                            >
                                <span>↺</span> Restart
                            </button>

                            <button 
                                onClick={onExit}
                                className="w-full py-4 bg-red-900/50 border-2 border-red-900/50 hover:bg-red-900 hover:border-red-800 text-red-100 font-bold uppercase tracking-wider rounded-lg shadow-lg hover:scale-[1.02] active:scale-95 transition-all flex items-center justify-center gap-2"
                            >
                                <span>✕</span> Main Menu
                            </button>
                        </div>
                    </div>
                </div>
            )}

            <div className="absolute top-6 left-6 z-10 pointer-events-none flex flex-col gap-2">
                <div className="bg-black/60 px-4 py-2 rounded-xl border border-white/10 flex flex-col">
                    <span className="text-[10px] text-neutral-400 uppercase font-bold">Distance</span>
                    <span ref={hudDistanceRef} className="text-2xl font-mono font-bold text-white">0</span>
                </div>
                <div className="bg-black/60 px-4 py-2 rounded-xl border border-amber-500/20 flex gap-3 items-center">
                    <div className="w-6 h-6 rounded-full bg-amber-500 text-black flex items-center justify-center text-xs font-bold">$</div>
                    <span ref={hudCoinsRef} className="text-xl font-mono font-bold text-white">0</span>
                </div>
                <div className="w-48 h-1.5 bg-neutral-800 rounded-full mt-2 overflow-hidden border border-white/5">
                    <div ref={hudFuelBarRef} className="h-full bg-red-500 transition-all duration-200" style={{ width: '100%' }} />
                </div>
            </div>
            {notification && (
                <div className="absolute top-1/3 left-1/2 -translate-x-1/2 z-40 text-4xl font-black italic text-white animate-bounce drop-shadow-lg">{notification.text}</div>
            )}
            <div className="absolute bottom-10 left-10 right-10 z-30 flex justify-between">
                 <button 
                    className="w-24 h-24 rounded-full bg-black/40 border-2 border-white/10 active:bg-white/10 active:border-red-500/50 transition-all text-white font-black italic text-xl" 
                    onMouseDown={() => gameStateRef.current.keys.left = true} 
                    onMouseUp={() => gameStateRef.current.keys.left = false} 
                    onMouseLeave={() => gameStateRef.current.keys.left = false}
                    onTouchStart={(e) => { e.preventDefault(); gameStateRef.current.keys.left = true; }} 
                    onTouchEnd={(e) => { e.preventDefault(); gameStateRef.current.keys.left = false; }}
                >
                    BRAKE
                </button>
                 <button 
                    className="w-24 h-24 rounded-full bg-black/40 border-2 border-white/10 active:bg-white/10 active:border-emerald-500/50 transition-all text-white font-black italic text-xl" 
                    onMouseDown={() => gameStateRef.current.keys.right = true} 
                    onMouseUp={() => gameStateRef.current.keys.right = false} 
                    onMouseLeave={() => gameStateRef.current.keys.right = false}
                    onTouchStart={(e) => { e.preventDefault(); gameStateRef.current.keys.right = true; }} 
                    onTouchEnd={(e) => { e.preventDefault(); gameStateRef.current.keys.right = false; }}
                >
                    GAS
                </button>
            </div>
          </>
      )}
      <canvas ref={canvasRef} className="w-full h-full" style={{ imageRendering: config.PIXELATED ? 'pixelated' : 'auto' }} />
    </div>
  );
};

export default Game;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { COLORS } from '../constants';
import { GameConfig, CarModel, MapConfig, GameMode, LevelConfig } from '../types';
import { createEngine, createCar, generateTerrainChunk, generateClouds, createWall, TerrainChunk, Cloud, Decoration } from '../utils/physics';
import { SoundManager } from '../utils/audio';
import DebugMenu from './DebugMenu';

const Matter = (window as any).Matter;

interface GameProps {
  mode: GameMode;
  levelConfig?: LevelConfig;
  onGameOver: (distance: number, coins: number) => void;
  onLevelComplete: (coins: number) => void;
  selectedCar: CarModel;
  selectedMap: MapConfig;
  config: GameConfig;
  onUpdateConfig: (key: keyof GameConfig, value: any) => void;
  onResetConfig: () => void;
  onExit: () => void;
  onRestart: () => void;
  isMenuBackground?: boolean;
  onReady?: () => void;
}

interface Particle {
    x: number; y: number; vx: number; vy: number;
    life: number; maxLife: number; active: boolean;
    type: 'dust' | 'spark' | 'explosion' | 'smoke';
}

const Game: React.FC<GameProps> = ({ mode, levelConfig, onGameOver, onLevelComplete, selectedCar, selectedMap, config, onUpdateConfig, onResetConfig, onExit, onRestart, isMenuBackground = false, onReady }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const requestRef = useRef<number | null>(null);
  const engineRef = useRef<any>(null);
  const carRef = useRef<any>(null);
  const soundManagerRef = useRef<SoundManager | null>(null);

  // Game Logic Refs
  const chunksRef = useRef<TerrainChunk[]>([]);
  const cloudsRef = useRef<Cloud[]>([]);
  const collectedCoinIdsRef = useRef<Set<number>>(new Set());
  const collectedFuelIdsRef = useRef<Set<number>>(new Set());
  const particlesRef = useRef<Particle[]>([]);
  const lastChunkDataRef = useRef({ endX: 0, endY: 200, globalIndex: 0, segmentsSinceFuel: 0 });

  const fuelRef = useRef(config.MAX_FUEL);
  const wheelGroundContacts = useRef(0);
  const isOutOfFuelRef = useRef(false);
  const gameStateRef = useRef({ distance: 0, coins: 0, isGameOver: false, keys: { left: false, right: false } });

  // Visual state
  const cameraZoomRef = useRef(1.0);
  const cameraPosRef = useRef({ x: 0, y: 0 });

  // Pause & Settings State
  const [isPaused, setIsPaused] = useState(false);
  const pausedRef = useRef(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [pendingResolution, setPendingResolution] = useState(config.RESOLUTION);

  const [notification, setNotification] = useState<{text: string, subText?: string, id: number} | null>(null);
  const patternsRef = useRef<{[key: string]: CanvasPattern | null}>({});
  const starsRef = useRef<{x: number, y: number, r: number, opacity: number}[]>([]);

  // FPS Logic
  const lastFpsTimeRef = useRef(0);
  const frameCountRef = useRef(0);
  const hudFpsRef = useRef<HTMLDivElement>(null);

  // HUD Refs
  const hudDistanceRef = useRef<HTMLDivElement>(null);
  const hudCoinsRef = useRef<HTMLDivElement>(null);
  const hudFuelBarRef = useRef<HTMLDivElement>(null);

  // Setup Stars for Moon
  useEffect(() => {
    if (selectedMap.backgroundType === 'moon') {
        const s = [];
        for(let i=0; i<150; i++) {
            s.push({ x: Math.random() * 2000, y: Math.random() * 1000 - 500, r: Math.random() * 2, opacity: Math.random() });
        }
        starsRef.current = s;
    } else {
        starsRef.current = [];
    }
  }, [selectedMap]);

  const addChunk = useCallback((startX: number) => {
    const { endY, globalIndex, segmentsSinceFuel } = lastChunkDataRef.current;
    const length = config.CHUNK_SIZE;
    const chunkId = Math.floor(startX / length);

    const newChunk = generateTerrainChunk(
        chunkId, startX, endY, globalIndex, length, false, config, selectedMap.backgroundType, segmentsSinceFuel,
        mode === 'LEVELS' && levelConfig ? levelConfig.distance : null
    );

    if (engineRef.current) Matter.World.add(engineRef.current.world, newChunk.composite);

    if (selectedMap.backgroundType === 'earth' || selectedMap.backgroundType === 'highway') {
        const newClouds = generateClouds(startX, length);
        cloudsRef.current = [...cloudsRef.current, ...newClouds];
    }

    lastChunkDataRef.current = {
        endX: startX + length,
        endY: newChunk.endY,
        globalIndex: newChunk.endGlobalIndex,
        segmentsSinceFuel: newChunk.nextSegmentsSinceFuel
    };

    chunksRef.current.push(newChunk);

    // Cleanup old chunks and clouds to prevent memory leak
    if (chunksRef.current.length > 5) {
        const oldChunk = chunksRef.current.shift();
        if (oldChunk && engineRef.current) {
             Matter.Composite.remove(engineRef.current.world, oldChunk.composite);
        }
    }
    if (cloudsRef.current.length > 50) {
        cloudsRef.current = cloudsRef.current.slice(cloudsRef.current.length - 40);
    }
  }, [config, selectedMap.backgroundType, mode, levelConfig]);

  const handleResize = useCallback(() => {
    if (canvasRef.current && containerRef.current) {
        const container = containerRef.current;
        const cw = container.clientWidth;
        const ch = container.clientHeight;

        // Enforce 16:9 Aspect Ratio
        const targetRatio = 16 / 9;
        let w, h;

        if (cw / ch > targetRatio) {
            // Container is wider than 16:9, height is strict
            h = ch;
            w = ch * targetRatio;
        } else {
            // Container is taller than 16:9, width is strict
            w = cw;
            h = cw / targetRatio;
        }

        const canvas = canvasRef.current;
        // Set display size
        canvas.style.width = `${w}px`;
        canvas.style.height = `${h}px`;

        // Set internal render resolution
        canvas.width = w * config.RESOLUTION;
        canvas.height = h * config.RESOLUTION;

        patternsRef.current = {}; 
    }
  }, [config.RESOLUTION]);

  useEffect(() => {
    window.addEventListener('resize', handleResize);
    handleResize();
    return () => window.removeEventListener('resize', handleResize);
  }, [handleResize]);

  // Initialization Sequence
  useEffect(() => {
    if (!isMenuBackground) soundManagerRef.current = new SoundManager();
    const engine = createEngine(config);
    engineRef.current = engine;
    const car = createCar(200, -100, selectedCar, config); 
    carRef.current = car;
    Matter.World.add(engine.world, [car, createWall(-1000)]);

    // Reset loop state
    lastChunkDataRef.current = { endX: 0, endY: 200, globalIndex: 0, segmentsSinceFuel: 0 };
    chunksRef.current = [];
    cloudsRef.current = [];
    collectedCoinIdsRef.current = new Set();
    collectedFuelIdsRef.current = new Set();
    fuelRef.current = config.MAX_FUEL;
    isOutOfFuelRef.current = false;
    gameStateRef.current.isGameOver = false;
    gameStateRef.current.distance = 0;
    gameStateRef.current.coins = 0;
    pausedRef.current = false;
    setIsPaused(false);
    setIsSettingsOpen(false);

    let currentGenX = 0;
    const buffer = isMenuBackground ? 4000 : config.INITIAL_BUFFER_DISTANCE;
    while (currentGenX < buffer) {
        addChunk(currentGenX);
        currentGenX += config.CHUNK_SIZE;
    }

    particlesRef.current = Array.from({ length: config.PARTICLE_POOL_SIZE }).map(() => ({
        x: 0, y: 0, vx: 0, vy: 0, life: 0, maxLife: 0, active: false, type: 'dust'
    }));

    Matter.Events.on(engine, 'collisionStart', (event: any) => {
        event.pairs.forEach((pair: any) => {
            const { bodyA, bodyB } = pair;
            const isWheel = (b: any) => b.label === 'wheelBack' || b.label === 'wheelFront';
            const isGround = (b: any) => b.label === 'ground' || b.label === 'obstacle';

            if ((isWheel(bodyA) && isGround(bodyB)) || (isWheel(bodyB) && isGround(bodyA))) {
                wheelGroundContacts.current++;
                const w = isWheel(bodyA) ? bodyA : bodyB;
                const speed = Matter.Vector.magnitude(w.velocity);
                if (speed > 5) spawnParticles(w.position.x, w.position.y + 15, 2, speed > 10 ? 'spark' : 'dust');
            }

            if ((bodyA.label === 'chassis' && bodyB.label === 'ground') || (bodyB.label === 'chassis' && bodyA.label === 'ground')) {
                if (isMenuBackground) return;
                const chassis = bodyA.label === 'chassis' ? bodyA : bodyB;
                if (Math.abs(chassis.angle) > Math.PI / 1.5) {
                    gameStateRef.current.isGameOver = true;
                    soundManagerRef.current?.stopContinuous();
                    onGameOver(gameStateRef.current.distance, gameStateRef.current.coins);
                }
            }

            let item = null;
            if (['chassis', 'wheelBack', 'wheelFront'].includes(bodyA.label) && ['coin', 'fuel', 'finishLine'].includes(bodyB.label)) item = bodyB;
            if (['chassis', 'wheelBack', 'wheelFront'].includes(bodyB.label) && ['coin', 'fuel', 'finishLine'].includes(bodyA.label)) item = bodyA;

            if (item && !isMenuBackground) {
                if (item.label === 'finishLine') {
                    gameStateRef.current.isGameOver = true;
                    onLevelComplete(gameStateRef.current.coins);
                } else if (!collectedCoinIdsRef.current.has(item.id) && !collectedFuelIdsRef.current.has(item.id)) {
                    if (item.label === 'coin') {
                        collectedCoinIdsRef.current.add(item.id);
                        gameStateRef.current.coins += config.COIN_VALUE;
                        soundManagerRef.current?.playCoinSound();
                        Matter.World.remove(engine.world, item);
                    } else if (item.label === 'fuel') {
                        collectedFuelIdsRef.current.add(item.id);
                        fuelRef.current = Math.min(config.MAX_FUEL, fuelRef.current + config.FUEL_CAN_VALUE);
                        isOutOfFuelRef.current = false;
                        setNotification({ text: "FUEL!", id: Date.now() });
                        setTimeout(() => setNotification(null), 1500);
                        Matter.World.remove(engine.world, item);
                    }
                }
            }
        });
    });

    Matter.Events.on(engine, 'collisionEnd', (event: any) => {
        event.pairs.forEach((pair: any) => {
            const isWheel = (b: any) => b.label === 'wheelBack' || b.label === 'wheelFront';
            const isGround = (b: any) => b.label === 'ground' || b.label === 'obstacle';
            if ((isWheel(pair.bodyA) && isGround(pair.bodyB)) || (isWheel(pair.bodyB) && isGround(pair.bodyA))) {
                wheelGroundContacts.current = Math.max(0, wheelGroundContacts.current - 1);
            }
        });
    });

    // Notify parent that we are ready to start playing
    if (onReady) onReady();

    requestRef.current = requestAnimationFrame(animate);
    return () => {
        if (requestRef.current) cancelAnimationFrame(requestRef.current);
        Matter.Engine.clear(engine);
        if (soundManagerRef.current) soundManagerRef.current.stopContinuous();
    };
  }, [addChunk, selectedCar, onGameOver, onLevelComplete, config, isMenuBackground, onReady]);

  const handleResume = useCallback(() => {
    pausedRef.current = false;
    setIsPaused(false);
    setIsSettingsOpen(false);
  }, []);

  const spawnParticles = (x: number, y: number, count: number, type: 'dust' | 'spark' | 'explosion' | 'smoke') => {
      let spawned = 0;
      for (let p of particlesRef.current) {
          if (spawned >= count) break;
          if (!p.active) {
              p.active = true; p.x = x; p.y = y; p.type = type;
              p.maxLife = config.PARTICLE_LIFETIME; p.life = p.maxLife;
              if (type === 'smoke') {
                  p.vx = (Math.random() - 0.5) * 2 - 2; // Smoke blows back
                  p.vy = (Math.random() - 0.5) * 2;
                  p.maxLife = 60;
                  p.life = 60;
              } else {
                  p.vx = (Math.random() - 0.5) * 5; 
                  p.vy = (Math.random() - 0.5) * 5;
              }
              spawned++;
          }
      }
  };

  const getPattern = (ctx: CanvasRenderingContext2D, type: string, color1: string, color2: string) => {
      const key = `${type}-${color1}-${color2}`;
      if (patternsRef.current[key]) return patternsRef.current[key];
      const pCanvas = document.createElement('canvas');
      const pCtx = pCanvas.getContext('2d')!;
      pCanvas.width = 40; pCanvas.height = 40;
      if (type === 'ground') {
          // Noise texture
          pCtx.fillStyle = color1; pCtx.fillRect(0,0,40,40);
          pCtx.fillStyle = color2; 
          for(let i=0; i<30; i++) {
              pCtx.globalAlpha = 0.1 + Math.random() * 0.2;
              pCtx.beginPath(); 
              pCtx.arc(Math.random()*40, Math.random()*40, 1 + Math.random()*2, 0, Math.PI*2);
              pCtx.fill();
          }
      } else if (type === 'striped') {
          pCanvas.width = 20; pCtx.fillStyle = color1; pCtx.fillRect(0,0,20,40);
          pCtx.fillStyle = color2; pCtx.fillRect(0,0,10,40);
      } else if (type === 'checker') {
          pCanvas.width = 20; pCanvas.height = 20;
          pCtx.fillStyle = color1; pCtx.fillRect(0,0,20,20);
          pCtx.fillStyle = color2; pCtx.fillRect(0,0,10,10); pCtx.fillRect(10,10,10,10);
      } else if (type === 'dots') {
          pCanvas.width = 10; pCanvas.height = 10;
          pCtx.fillStyle = color1; pCtx.fillRect(0,0,10,10);
          pCtx.fillStyle = color2; pCtx.beginPath(); pCtx.arc(5,5,2,0,Math.PI*2); pCtx.fill();
      } else if (type === 'gradient') {
          const g = pCtx.createLinearGradient(0,0,0,40);
          g.addColorStop(0, color2);
          g.addColorStop(1, color1);
          pCtx.fillStyle = g;
          pCtx.fillRect(0,0,40,40);
      }
      const pattern = ctx.createPattern(pCanvas, 'repeat');
      patternsRef.current[key] = pattern;
      return pattern;
  };

  const drawChassisPath = (ctx: CanvasRenderingContext2D, car: CarModel, cw: number, ch: number, wr: number) => {
      ctx.beginPath();
      const halfW = cw / 2;
      const halfH = ch / 2;

      // Calculate wheel positions relative to center
      // Based on createCar logic: offset = -cw/2 + wr
      const rearWheelX = -halfW + wr;
      const frontWheelX = halfW - wr;
      const wellR = wr + 4; // Slight clearance for wheel well

      // -- UNDERCARRIAGE with Wheel Wells --
      // Start at Bottom-Left (before rear well)
      ctx.moveTo(-halfW, halfH); 

      // Rear Well
      ctx.arc(rearWheelX, halfH, wellR, Math.PI, 0); 

      // Front Well
      ctx.arc(frontWheelX, halfH, wellR, Math.PI, 0);

      // To Front Bumper Bottom
      ctx.lineTo(halfW, halfH);

      // -- UPPER BODY SHAPES --
      if (car.shape === 'coupe' || !car.shape) {
          ctx.lineTo(halfW * 1.1, 0); // Nose slope
          ctx.quadraticCurveTo(halfW * 0.8, -halfH * 0.7, halfW * 0.1, -halfH * 0.9); // Windshield
          ctx.lineTo(-halfW * 0.4, -halfH * 0.9); // Roof
          ctx.quadraticCurveTo(-halfW, -halfH * 0.9, -halfW, -halfH * 0.2); // Rear Slope
      } else if (car.shape === 'jeep') {
          ctx.lineTo(halfW * 1.1, halfH); // Front bumper vertical
          ctx.lineTo(halfW * 1.1, -halfH * 0.2); // Hood front
          ctx.lineTo(halfW * 0.6, -halfH * 0.2); // Hood top
          ctx.lineTo(halfW * 0.6, -halfH * 1.6); // Windshield
          ctx.lineTo(-halfW * 0.5, -halfH * 1.6); // Roof
          ctx.lineTo(-halfW * 0.5, -halfH * 0.5); // Bed front
          ctx.lineTo(-halfW * 0.9, -halfH * 0.5); // Bed top
      } else if (car.shape === 'racer') {
          ctx.lineTo(halfW * 1.5, halfH * 0.3); // Nose tip
          ctx.quadraticCurveTo(halfW * 1.0, -halfH * 0.3, halfW * 0.3, -halfH * 0.5); // Body slope
          ctx.lineTo(-halfW * 0.5, -halfH * 0.5); // Engine cover
          ctx.lineTo(-halfW * 1.2, -halfH * 0.3); // Spoiler mount
          ctx.lineTo(-halfW * 1.2, halfH * 0.2); // Rear
      } else if (car.shape === 'buggy') {
          ctx.lineTo(halfW * 0.9, halfH * 0.5); // Nose
          ctx.lineTo(halfW * 1.1, 0);
          ctx.lineTo(halfW * 0.9, 0); 
          ctx.lineTo(halfW * 0.4, -halfH * 1.4); // Rollcage Front
          ctx.lineTo(-halfW * 0.5, -halfH * 1.4); // Rollcage Top
          ctx.lineTo(-halfW * 0.7, 0); // Rollcage Rear
      } else if (car.shape === 'van') {
          ctx.lineTo(halfW * 1.1, halfH * 0.5);
          ctx.quadraticCurveTo(halfW * 1.1, -halfH * 1.2, halfW * 0.7, -halfH * 1.3); // Front curve
          ctx.lineTo(-halfW * 0.9, -halfH * 1.3); // Roof
          ctx.lineTo(-halfW * 0.9, halfH * 0.5); // Rear
      } else if (car.shape === 'supercar') {
          ctx.lineTo(halfW * 1.45, halfH * 0.5); // Nose
          ctx.quadraticCurveTo(halfW * 1.0, -halfH * 0.4, halfW * 0.1, -halfH * 0.6); // Hood
          ctx.lineTo(-halfW * 0.5, -halfH * 0.6); // Rear Deck
          ctx.lineTo(-halfW * 1.1, 0); 
          ctx.lineTo(-halfW * 1.1, halfH * 0.5);
      } else if (car.shape === 'bike') {
           ctx.lineTo(halfW * 0.3, 0);
           ctx.lineTo(halfW * 0.4, -halfH * 0.4); 
           ctx.lineTo(0, -halfH * 0.7); 
           ctx.lineTo(-halfW * 0.5, 0);
      }

      ctx.closePath();
  };

  const drawCarDetails = (ctx: CanvasRenderingContext2D, car: CarModel, cw: number, ch: number) => {
      const halfW = cw / 2;
      const halfH = ch / 2;

      // 1. Headlights (with glow)
      ctx.save();
      ctx.translate(halfW, 0);

      const grad = ctx.createLinearGradient(0, 0, 150, 0);
      grad.addColorStop(0, 'rgba(255, 255, 200, 0.4)');
      grad.addColorStop(1, 'rgba(255, 255, 200, 0)');
      ctx.fillStyle = grad;
      ctx.beginPath(); ctx.moveTo(0, -5); ctx.lineTo(150, -40); ctx.lineTo(150, 40); ctx.lineTo(0, 5); ctx.fill();

      ctx.fillStyle = '#fef08a';
      ctx.shadowColor = '#fef08a'; ctx.shadowBlur = 10;
      if (car.shape === 'jeep' || car.shape === 'van') {
           ctx.fillRect(halfW * 0.05, -15, 5, 20);
      } else if (car.shape === 'bike') {
           ctx.beginPath(); ctx.arc(halfW * 0.3, -10, 8, 0, Math.PI*2); ctx.fill();
      } else {
           ctx.beginPath(); ctx.ellipse(halfW * 0.15, 0, 4, 12, 0, 0, Math.PI*2); ctx.fill();
      }
      ctx.restore();

      // 2. Windows - Gradient glass
      const glassGrad = ctx.createLinearGradient(0, -ch, 0, 0);
      glassGrad.addColorStop(0, '#38bdf8');
      glassGrad.addColorStop(1, '#1e293b');
      ctx.fillStyle = glassGrad;
      ctx.strokeStyle = '#334155'; ctx.lineWidth = 1;

      if (car.shape === 'coupe') {
          ctx.beginPath();
          ctx.moveTo(-halfW * 0.3, -halfH * 0.75);
          ctx.lineTo(halfW * 0.1, -halfH * 0.75);
          ctx.lineTo(halfW * 0.5, -halfH * 0.1);
          ctx.lineTo(-halfW * 0.3, -halfH * 0.1);
          ctx.fill(); ctx.stroke();
      } else if (car.shape === 'supercar') {
          ctx.beginPath();
          ctx.moveTo(-halfW * 0.2, -halfH * 0.5);
          ctx.lineTo(halfW * 0.2, -halfH * 0.5);
          ctx.lineTo(halfW * 0.6, -halfH * 0.1);
          ctx.lineTo(-halfW * 0.4, -halfH * 0.1);
          ctx.fill(); ctx.stroke();
      } else if (car.shape === 'jeep') {
          ctx.fillRect(-halfW * 0.4, -halfH * 1.3, cw * 0.35, ch * 0.5); // Side
          ctx.fillRect(halfW * 0.1, -halfH * 1.3, cw * 0.35, ch * 0.5); // Front
      } else if (car.shape === 'van') {
          ctx.fillRect(-halfW * 0.8, -halfH * 1.1, cw * 0.35, ch * 0.5);
          ctx.fillRect(-halfW * 0.3, -halfH * 1.1, cw * 0.45, ch * 0.5);
      }

      // 3. Extra Details
      ctx.fillStyle = '#111';
      if (car.shape === 'racer' || car.shape === 'supercar') {
          // Spoiler
          ctx.fillStyle = car.bodyColor;
          ctx.beginPath();
          ctx.moveTo(-halfW * 1.1, -halfH * 0.2);
          ctx.lineTo(-halfW * 1.25, -halfH * 1.4);
          ctx.lineTo(-halfW * 0.7, -halfH * 1.4);
          ctx.lineTo(-halfW * 0.6, -halfH * 0.2);
          ctx.fill(); 
          ctx.stroke();
          // Wing
          ctx.fillStyle = '#111';
          ctx.fillRect(-halfW * 1.3, -halfH * 1.5, cw * 0.6, 6);
      } else if (car.shape === 'buggy') {
          ctx.strokeStyle = '#64748b';
          ctx.lineWidth = 3;
          ctx.beginPath();
          ctx.moveTo(-halfW * 0.7, 0); ctx.lineTo(halfW * 0.9, 0); 
          ctx.moveTo(-halfW * 0.5, -halfH * 1.4); ctx.lineTo(halfW * 0.4, -halfH * 1.4);
          ctx.lineTo(halfW * 0.9, 0);
          ctx.stroke();
      }

      // 4. Exhaust
      const exhaustX = -halfW * 1.0;
      const exhaustY = halfH * 0.3;
      ctx.fillStyle = '#444';
      if (car.shape !== 'bike') {
          ctx.fillRect(exhaustX - 8, exhaustY, 15, 8);
          ctx.fillStyle = '#000';
          ctx.beginPath(); ctx.arc(exhaustX - 8, exhaustY + 4, 3, 0, Math.PI*2); ctx.fill();
      }

      if (Math.random() > 0.7 && !isMenuBackground && Math.abs(carRef.current.bodies[0].velocity.x) > 1) {
          spawnParticles(
              carRef.current.bodies[0].position.x + exhaustX, 
              carRef.current.bodies[0].position.y + exhaustY + 4, 
              1, 'smoke'
          );
      }
  };

  const drawWheel = (ctx: CanvasRenderingContext2D, x: number, y: number, r: number, angle: number, color: string) => {
      ctx.save();
      ctx.translate(x, y);
      ctx.rotate(angle);

      // Tire
      ctx.beginPath(); ctx.arc(0, 0, r, 0, Math.PI * 2); 
      ctx.fillStyle = '#1c1917'; ctx.fill(); // Dark rubber

      // Detailed Tread
      ctx.strokeStyle = '#292524'; ctx.lineWidth = 4;
      ctx.setLineDash([5, 8]);
      ctx.beginPath(); ctx.arc(0,0, r-2, 0, Math.PI*2); ctx.stroke();
      ctx.setLineDash([]);

      // Rim
      const rimR = r * 0.65;
      ctx.beginPath(); ctx.arc(0, 0, rimR, 0, Math.PI * 2);
      ctx.fillStyle = color; ctx.fill();
      ctx.strokeStyle = '#444'; ctx.lineWidth = 2; ctx.stroke();

      // Spokes
      ctx.strokeStyle = '#000'; ctx.lineWidth = 3; ctx.lineCap = 'round';
      const spokes = 5;
      for (let i = 0; i < spokes; i++) {
          ctx.rotate((Math.PI * 2) / spokes);
          ctx.beginPath(); ctx.moveTo(0, 0); ctx.lineTo(0, rimR - 3); ctx.stroke();
      }

      // Center Hub
      ctx.beginPath(); ctx.arc(0, 0, r * 0.15, 0, Math.PI * 2);
      ctx.fillStyle = '#555'; ctx.fill();
      ctx.beginPath(); ctx.arc(0, 0, r * 0.08, 0, Math.PI * 2);
      ctx.fillStyle = '#222'; ctx.fill();

      ctx.restore();
  };

  const drawSuspension = (ctx: CanvasRenderingContext2D, chassisBody: any, wheelBody: any, offsetX: number, offsetY: number) => {
      const cAngle = chassisBody.angle;
      const worldOffsetX = offsetX * Math.cos(cAngle) - offsetY * Math.sin(cAngle);
      const worldOffsetY = offsetX * Math.sin(cAngle) + offsetY * Math.cos(cAngle);

      const p1 = { x: chassisBody.position.x + worldOffsetX, y: chassisBody.position.y + worldOffsetY };
      const p2 = { x: wheelBody.position.x, y: wheelBody.position.y };

      const dist = Math.hypot(p2.x - p1.x, p2.y - p1.y);
      const angle = Math.atan2(p2.y - p1.y, p2.x - p1.x);

      ctx.save();
      ctx.translate(p1.x, p1.y);
      ctx.rotate(angle);

      // Upper strut
      ctx.strokeStyle = '#444'; ctx.lineWidth = 6;
      ctx.beginPath(); ctx.moveTo(0, 0); ctx.lineTo(dist/2, 0); ctx.stroke();

      // Lower strut
      ctx.strokeStyle = '#999'; ctx.lineWidth = 4;
      ctx.beginPath(); ctx.moveTo(dist/2, 0); ctx.lineTo(dist, 0); ctx.stroke();

      // Coil
      ctx.strokeStyle = '#dc2626'; ctx.lineWidth = 2.5;
      ctx.beginPath();
      ctx.moveTo(0, 0);
      const zigs = 8;
      for(let i=0; i<=zigs; i++) {
          ctx.lineTo((dist / zigs) * i, i % 2 === 0 ? -5 : 5);
      }
      ctx.stroke();
      ctx.restore();
  };

  const drawCloud = (ctx: CanvasRenderingContext2D, cloud: Cloud) => {
      ctx.save();
      ctx.translate(cloud.x, cloud.y);
      ctx.scale(cloud.scale, cloud.scale);

      ctx.fillStyle = 'rgba(255,255,255,0.7)';

      ctx.beginPath();
      ctx.arc(0, 0, 30, 0, Math.PI * 2);
      ctx.arc(35, 5, 40, 0, Math.PI * 2);
      ctx.arc(-35, 5, 35, 0, Math.PI * 2);
      ctx.arc(15, -25, 30, 0, Math.PI * 2);
      ctx.arc(-15, -25, 30, 0, Math.PI * 2);

      ctx.fill();
      ctx.restore();
  };

  const drawTree = (ctx: CanvasRenderingContext2D, type: number, seed: number) => {
    // Trunk
    ctx.fillStyle = COLORS.treeTrunk;
    const trunkW = 12 + seed * 4;
    const trunkH = 40 + seed * 20;
    ctx.fillRect(-trunkW/2, -trunkH, trunkW, trunkH);

    // Leaves
    if (type === 6) { // Pine
        ctx.fillStyle = COLORS.treeLeafDark;
        ctx.beginPath();
        ctx.moveTo(-40, -trunkH + 10);
        ctx.lineTo(0, -trunkH - 100 - seed * 50);
        ctx.lineTo(40, -trunkH + 10);
        ctx.fill();

        ctx.fillStyle = COLORS.treeLeafLight;
        ctx.beginPath();
        ctx.moveTo(-30, -trunkH - 20);
        ctx.lineTo(0, -trunkH - 100 - seed * 50);
        ctx.lineTo(30, -trunkH - 20);
        ctx.fill();
    } else { // Round
        ctx.fillStyle = COLORS.treeLeafDark;
        ctx.beginPath();
        ctx.arc(0, -trunkH - 20, 40 + seed * 10, 0, Math.PI * 2);
        ctx.fill();

        ctx.fillStyle = COLORS.treeLeafLight;
        ctx.beginPath();
        ctx.arc(-10, -trunkH - 30, 30 + seed * 10, 0, Math.PI * 2);
        ctx.fill();
    }
  };

  const drawRock = (ctx: CanvasRenderingContext2D, seed: number) => {
      ctx.fillStyle = COLORS.boulder;
      ctx.beginPath();
      ctx.moveTo(-20 - seed * 10, 0);
      ctx.lineTo(-15 - seed * 5, -20 - seed * 15);
      ctx.lineTo(10 + seed * 5, -25 - seed * 10);
      ctx.lineTo(25 + seed * 10, 0);
      ctx.fill();

      // Detail
      ctx.fillStyle = COLORS.boulderDark;
      ctx.beginPath();
      ctx.moveTo(-10, -5);
      ctx.lineTo(0, -15);
      ctx.lineTo(10, -5);
      ctx.fill();
  };

  const drawBush = (ctx: CanvasRenderingContext2D, seed: number) => {
     ctx.fillStyle = COLORS.bushDark;
     ctx.beginPath();
     ctx.arc(-15, -10, 15 + seed * 5, 0, Math.PI * 2);
     ctx.arc(15, -10, 12 + seed * 5, 0, Math.PI * 2);
     ctx.arc(0, -20, 18 + seed * 5, 0, Math.PI * 2);
     ctx.fill();

     ctx.fillStyle = COLORS.bushLight;
     ctx.beginPath();
     ctx.arc(0, -20, 10 + seed * 3, 0, Math.PI * 2);
     ctx.fill();
  };

  const animate = useCallback(() => {
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d', { alpha: false });
    if (!canvas || !ctx || gameStateRef.current.isGameOver) {
        requestRef.current = requestAnimationFrame(animate);
        return;
    }

    if (!pausedRef.current) {
        Matter.Engine.update(engineRef.current, 1000 / 60);
        const chassis = carRef.current.bodies.find((b: any) => b.label === 'chassis');
        const wheelB = carRef.current.bodies.find((b: any) => b.label === 'wheelBack');
        const wheelF = carRef.current.bodies.find((b: any) => b.label === 'wheelFront');

        const { keys } = gameStateRef.current;
        const speedRatio = Matter.Vector.magnitude(chassis.velocity) / 25;
        const isGrounded = wheelGroundContacts.current > 0;

        if (!isMenuBackground) {
            soundManagerRef.current?.updateContinuous(speedRatio, isGrounded, keys.right && !isOutOfFuelRef.current);
            if (keys.right && !isOutOfFuelRef.current) {
                fuelRef.current -= config.FUEL_CONSUMPTION;
                if (fuelRef.current <= 0) {
                    fuelRef.current = 0; isOutOfFuelRef.current = true;
                    setNotification({ text: "OUT OF FUEL", id: Date.now() });
                    setTimeout(() => { if (!gameStateRef.current.isGameOver) onGameOver(gameStateRef.current.distance, gameStateRef.current.coins); }, 3000);
                }
                const power = selectedCar.acceleration;
                if (selectedCar.driveTrain !== 'FWD') Matter.Body.setAngularVelocity(wheelB, Math.min(wheelB.angularVelocity + power, selectedCar.speed));
                if (selectedCar.driveTrain !== 'RWD') Matter.Body.setAngularVelocity(wheelF, Math.min(wheelF.angularVelocity + power, selectedCar.speed));
                if (chassis.angularVelocity > -config.MAX_ROTATION_SPEED) Matter.Body.setAngularVelocity(chassis, chassis.angularVelocity - (isGrounded ? config.GROUND_ROTATION_SPEED : config.AIR_ROTATION_SPEED));
            } else if (keys.left) {
                 if (selectedCar.driveTrain !== 'FWD') Matter.Body.setAngularVelocity(wheelB, Math.max(wheelB.angularVelocity - 0.1, -selectedCar.speed/2));
                 if (selectedCar.driveTrain !== 'RWD') Matter.Body.setAngularVelocity(wheelF, Math.max(wheelF.angularVelocity - 0.1, -selectedCar.speed/2));
                 if (chassis.angularVelocity < config.MAX_ROTATION_SPEED) Matter.Body.setAngularVelocity(chassis, chassis.angularVelocity + (isGrounded ? config.GROUND_ROTATION_SPEED : config.AIR_ROTATION_SPEED));
            }
        } else {
            Matter.Body.setAngularVelocity(wheelB, 0.4); Matter.Body.setAngularVelocity(wheelF, 0.4);
            if (chassis.position.y > 500) Matter.Body.setPosition(chassis, { x: 200, y: -100 });
        }

        cameraPosRef.current = { x: chassis.position.x, y: chassis.position.y };
        if (chassis.position.x > lastChunkDataRef.current.endX - config.RENDER_DISTANCE) addChunk(lastChunkDataRef.current.endX);
        gameStateRef.current.distance = Math.max(0, Math.floor((chassis.position.x - 200) / 10));

        if (hudDistanceRef.current) hudDistanceRef.current.innerText = `${gameStateRef.current.distance}`;
        if (hudCoinsRef.current) hudCoinsRef.current.innerText = `${gameStateRef.current.coins}`;
        if (hudFuelBarRef.current) hudFuelBarRef.current.style.width = `${(fuelRef.current / config.MAX_FUEL) * 100}%`;
    }

    // --- RENDERING ---
    const zoom = cameraZoomRef.current;
    const vH = config.BASE_VIEWPORT_HEIGHT * zoom;
    const vW = (canvas.width / canvas.height) * vH; 
    const scale = canvas.height / vH;

    const camX = cameraPosRef.current.x - vW * 0.3;
    const camY = cameraPosRef.current.y - vH * 0.6;

    ctx.setTransform(scale, 0, 0, scale, -camX * scale, -camY * scale);

    // Sky
    const skyGrad = ctx.createLinearGradient(camX, camY, camX, camY + vH);
    skyGrad.addColorStop(0, selectedMap.skyColorStart); skyGrad.addColorStop(1, selectedMap.skyColorEnd);
    ctx.fillStyle = skyGrad; ctx.fillRect(camX, camY, vW, vH);

    // Sun/Moon Glow
    if (selectedMap.backgroundType !== 'moon') {
        const sunGrad = ctx.createRadialGradient(camX + vW - 100, camY + 100, 20, camX + vW - 100, camY + 100, 200);
        sunGrad.addColorStop(0, 'rgba(255, 255, 200, 0.6)');
        sunGrad.addColorStop(1, 'rgba(255, 255, 200, 0)');
        ctx.fillStyle = sunGrad; ctx.fillRect(camX, camY, vW, vH/2);
    }

    if (starsRef.current.length > 0) {
        ctx.fillStyle = 'white';
        starsRef.current.forEach(s => {
            const px = s.x + camX * 0.85; 
            if (px > camX && px < camX + vW) {
                ctx.globalAlpha = s.opacity; ctx.beginPath(); ctx.arc(px, s.y, s.r, 0, Math.PI*2); ctx.fill();
            }
        });
        ctx.globalAlpha = 1;
    }

    cloudsRef.current.forEach(c => {
        if (c.x > camX - 400 && c.x < camX + vW + 400) {
            drawCloud(ctx, c);
        }
    });

    const groundPat = getPattern(ctx, 'ground', selectedMap.groundColor, selectedMap.groundDarkColor);
    ctx.fillStyle = groundPat || selectedMap.groundColor;

    chunksRef.current.forEach(chunk => {
        if (chunk.endX < camX || chunk.pathData[0].x > camX + vW) return;

        ctx.beginPath(); ctx.moveTo(chunk.pathData[0].x, chunk.pathData[0].y);
        chunk.pathData.forEach(p => ctx.lineTo(p.x, p.y));
        ctx.lineTo(chunk.endX, chunk.endY + 1000); ctx.lineTo(chunk.pathData[0].x, chunk.pathData[0].y + 1000);
        ctx.fill(); 

        if (selectedMap.backgroundType === 'earth') {
             ctx.strokeStyle = COLORS.grassDetail; ctx.lineWidth = 10;
        } else if (selectedMap.backgroundType === 'moon') {
             ctx.strokeStyle = '#94a3b8'; ctx.lineWidth = 6;
        } else {
             ctx.strokeStyle = '#475569'; ctx.lineWidth = 8;
        }
        ctx.beginPath();
        chunk.pathData.forEach((p, i) => {
            if (i===0) ctx.moveTo(p.x, p.y);
            else ctx.lineTo(p.x, p.y);
        });
        ctx.stroke();

        chunk.decorations.forEach(d => {
            if (d.x < camX - 100 || d.x > camX + vW + 100) return;
            ctx.save(); ctx.translate(d.x, d.y); ctx.rotate(d.angle); ctx.scale(d.scale, d.scale);

            if (d.type === 5) { 
                ctx.fillStyle = 'white'; ctx.fillRect(0,-200,6,200); 
                ctx.fillStyle = '#ef4444'; ctx.beginPath(); ctx.moveTo(6,-200); ctx.lineTo(70,-175); ctx.lineTo(6,-150); ctx.fill();
            } else if (d.type === 3) { 
                ctx.fillStyle = COLORS.lampPost; ctx.fillRect(-2,-80,4,80); 
                ctx.fillStyle = COLORS.lampLight; ctx.beginPath(); ctx.arc(10,-80,6,0,Math.PI*2); ctx.fill();
                ctx.fillStyle = COLORS.lampGlow; ctx.beginPath(); ctx.arc(10,-80,20,0,Math.PI*2); ctx.fill();
            } else if (d.type === 4) { 
                ctx.fillStyle = '#78350f'; ctx.fillRect(-2,-20,4,20);
                ctx.fillRect(-20,-15,40,4);
            } else if (d.type === 6 || d.type === 7) { 
                drawTree(ctx, d.type, d.seed);
            } else if (d.type === 8) { 
                drawRock(ctx, d.seed);
            } else if (d.type === 9) { 
                drawBush(ctx, d.seed);
            } else if (selectedMap.backgroundType === 'earth') {
                 ctx.strokeStyle = COLORS.grassDetail; ctx.lineWidth = 2; 
                 ctx.beginPath(); 
                 ctx.moveTo(0,0); ctx.lineTo(-3, -8 - d.seed * 5);
                 ctx.moveTo(0,0); ctx.lineTo(3, -6 - d.seed * 5);
                 ctx.stroke();
            }
            ctx.restore();
        });

        chunk.coinBodies.forEach(b => {
            if (!collectedCoinIdsRef.current.has(b.id) && b.position.x > camX - 50 && b.position.x < camX + vW + 50) {
                ctx.save(); ctx.translate(b.position.x, b.position.y);
                const pulse = Math.sin(Date.now() / 200) * 0.1 + 1;
                ctx.scale(pulse, pulse);
                ctx.fillStyle = COLORS.coinOuter; ctx.beginPath(); ctx.arc(0,0,config.COIN_SIZE,0,Math.PI*2); ctx.fill();
                ctx.fillStyle = COLORS.coinInner; ctx.beginPath(); ctx.arc(0,0,config.COIN_SIZE*0.7,0,Math.PI*2); ctx.fill();
                ctx.fillStyle = '#fff'; ctx.font = 'bold 12px monospace'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle'; ctx.fillText('$', 0, 1);
                ctx.restore();
            }
        });

        chunk.fuelBodies.forEach(b => {
            if (!collectedFuelIdsRef.current.has(b.id) && b.position.x > camX - 50 && b.position.x < camX + vW + 50) {
                ctx.save(); ctx.translate(b.position.x, b.position.y);
                const pulse = Math.sin(Date.now() / 300) * 0.1 + 1;
                ctx.scale(pulse, pulse);
                ctx.fillStyle = COLORS.fuelCan; 
                ctx.fillRect(-10, -15, 20, 30);
                ctx.fillStyle = COLORS.fuelCanCap;
                ctx.fillRect(-6, -18, 12, 3);
                ctx.font = 'bold 10px sans-serif'; ctx.fillStyle = 'white'; ctx.fillText('FUEL', -10, 5);
                ctx.restore();
            }
        });
    });

    // --- CAR RENDER ---
    const chassis = carRef.current.bodies.find((b: any) => b.label === 'chassis');
    const wheelB = carRef.current.bodies.find((b: any) => b.label === 'wheelBack');
    const wheelF = carRef.current.bodies.find((b: any) => b.label === 'wheelFront');
    const cw = selectedCar.width || config.CAR_WIDTH; 
    const ch = selectedCar.height || config.CAR_HEIGHT;
    const wr = selectedCar.wheelSize || config.WHEEL_SIZE;

    // Draw Suspension (BEHIND everything)
    const wheelOffsetX = -cw / 2 + wr;
    const wheelOffsetY = ch / 2;
    drawSuspension(ctx, chassis, wheelB, wheelOffsetX, wheelOffsetY);
    drawSuspension(ctx, chassis, wheelF, -wheelOffsetX, wheelOffsetY);

    // Draw Wheels (BEHIND Chassis)
    [wheelB, wheelF].forEach(w => {
        drawWheel(ctx, w.position.x, w.position.y, wr, w.angle, selectedCar.wheelColor);
    });

    // Draw Chassis (ON TOP)
    ctx.save(); ctx.translate(chassis.position.x, chassis.position.y); ctx.rotate(chassis.angle);

    ctx.shadowColor = 'rgba(0,0,0,0.5)'; ctx.shadowBlur = 10;
    let bodyFill: string | CanvasPattern = selectedCar.bodyColor;
    if (selectedCar.texture !== 'plain') bodyFill = getPattern(ctx, selectedCar.texture, selectedCar.bodyColor, selectedCar.textureColor2) || bodyFill;

    if (selectedCar.imageUrl) {
        // ... (image logic from previous turn)
    }

    ctx.fillStyle = bodyFill;
    ctx.strokeStyle = 'rgba(0,0,0,0.6)'; ctx.lineWidth = 2;

    // Pass wheel radius to calculate arches
    drawChassisPath(ctx, selectedCar, cw, ch, wr);
    ctx.fill(); 
    ctx.shadowBlur = 0; 
    ctx.stroke();

    drawCarDetails(ctx, selectedCar, cw, ch);

    ctx.restore();

    particlesRef.current.forEach(p => {
        if (p.active) {
            ctx.fillStyle = p.type === 'spark' ? COLORS.particleSpark : 
                            p.type === 'smoke' ? COLORS.particleSmoke : COLORS.particleDust; 
            ctx.globalAlpha = p.life / p.maxLife;
            ctx.beginPath(); 
            if (p.type === 'smoke') {
                const r = 4 + (1 - p.life/p.maxLife) * 8;
                ctx.arc(p.x, p.y, r, 0, Math.PI*2);
            } else {
                ctx.arc(p.x, p.y, 2.5, 0, Math.PI*2); 
            }
            ctx.fill();
            p.x += p.vx; p.y += p.vy; 
            if (p.type !== 'smoke') p.vy += 0.2; 
            else { p.vx *= 0.95; p.vy -= 0.05; } 
            p.life--; if (p.life <= 0) p.active = false;
        }
    });
    ctx.globalAlpha = 1;

    const now = performance.now(); frameCountRef.current++;
    if (now - lastFpsTimeRef.current >= 500) {
        const fps = Math.round((frameCountRef.current * 1000) / (now - lastFpsTimeRef.current));
        if (hudFpsRef.current) hudFpsRef.current.innerText = `${fps} FPS`;
        lastFpsTimeRef.current = now; frameCountRef.current = 0;
    }

    requestRef.current = requestAnimationFrame(animate);
  }, [config, selectedCar, selectedMap, onGameOver, onLevelComplete, isMenuBackground]);

  return (
    <div ref={containerRef} className={`relative w-full h-full bg-slate-900 overflow-hidden select-none flex items-center justify-center ${isMenuBackground ? 'opacity-40 pointer-events-none' : ''}`}>
      {!isMenuBackground && (
          <>
            <div className="absolute top-4 right-4 z-30 flex gap-2">
                <div ref={hudFpsRef} className="font-mono text-xs text-emerald-500 bg-black/60 px-2 py-1 rounded">60 FPS</div>
                <button onClick={() => { pausedRef.current = !pausedRef.current; setIsPaused(!isPaused); }} className="w-10 h-10 bg-black/60 text-white rounded flex items-center justify-center border border-white/20 hover:bg-white/10 active:scale-95 transition-all">
                    {isPaused ? "▶" : "⏸"}
                </button>
            </div>

            {isPaused && (
                <div className="absolute inset-0 z-40 flex flex-col items-center justify-center bg-black/80 backdrop-blur-md animate-fade-in">
                    <div className="p-8 bg-neutral-900/90 border border-neutral-700 rounded-2xl shadow-2xl flex flex-col items-center gap-6 min-w-[300px]">

                        {!isSettingsOpen ? (
                          <>
                            <h2 className="text-4xl font-black italic text-white tracking-widest uppercase border-b-4 border-amber-500 pb-2 mb-2">
                                Paused
                            </h2>

                            <div className="flex flex-col gap-3 w-full">
                                <button 
                                    onClick={handleResume}
                                    className="w-full py-4 bg-emerald-600 hover:bg-emerald-500 text-white font-black italic uppercase tracking-wider rounded-lg shadow-lg hover:scale-[1.02] active:scale-95 transition-all flex items-center justify-center gap-2"
                                >
                                    <span>▶</span> Resume
                                </button>

                                <button 
                                    onClick={onRestart}
                                    className="w-full py-4 bg-neutral-700 hover:bg-neutral-600 text-white font-bold uppercase tracking-wider rounded-lg shadow-lg hover:scale-[1.02] active:scale-95 transition-all flex items-center justify-center gap-2"
                                >
                                    <span>↺</span> Restart
                                </button>

                                <button 
                                    onClick={() => { setIsSettingsOpen(true); setPendingResolution(config.RESOLUTION); }}
                                    className="w-full py-4 bg-neutral-800 border border-neutral-600 hover:bg-neutral-700 text-white font-bold uppercase tracking-wider rounded-lg shadow-lg hover:scale-[1.02] active:scale-95 transition-all flex items-center justify-center gap-2"
                                >
                                    <span>⚙</span> Settings
                                </button>

                                <button 
                                    onClick={onExit}
                                    className="w-full py-4 bg-red-900/50 border-2 border-red-900/50 hover:bg-red-900 hover:border-red-800 text-red-100 font-bold uppercase tracking-wider rounded-lg shadow-lg hover:scale-[1.02] active:scale-95 transition-all flex items-center justify-center gap-2"
                                >
                                    <span>✕</span> Main Menu
                                </button>
                            </div>
                          </>
                        ) : (
                          <>
                            <h2 className="text-3xl font-black italic text-white tracking-widest uppercase border-b-4 border-amber-500 pb-2 mb-2">
                                Settings
                            </h2>
                            <div className="w-full space-y-4">
                                <div>
                                    <div className="flex justify-between text-neutral-400 text-xs font-bold uppercase mb-2">
                                        <span>Resolution Scale</span>
                                        <span className="text-amber-500">{Math.round(pendingResolution * 100)}%</span>
                                    </div>
                                    <input 
                                        type="range" min="0.25" max="1.5" step="0.05" 
                                        value={pendingResolution} 
                                        onChange={(e) => setPendingResolution(parseFloat(e.target.value))}
                                        className="w-full h-2 bg-neutral-700 rounded-lg appearance-none cursor-pointer accent-amber-500 hover:accent-amber-400"
                                    />
                                    <p className="text-[10px] text-neutral-500 mt-1 text-center font-mono">Higher values improve crispness but reduce performance.</p>
                                </div>

                                <div className="flex gap-2 pt-2">
                                    <button 
                                        onClick={() => { onUpdateConfig('RESOLUTION', pendingResolution); setIsSettingsOpen(false); }}
                                        className="flex-1 py-3 bg-emerald-600 hover:bg-emerald-500 text-white font-bold uppercase rounded-lg shadow-lg"
                                    >
                                        Save
                                    </button>
                                    <button 
                                        onClick={() => setIsSettingsOpen(false)}
                                        className="flex-1 py-3 bg-neutral-700 hover:bg-neutral-600 text-white font-bold uppercase rounded-lg"
                                    >
                                        Cancel
                                    </button>
                                </div>
                            </div>
                          </>
                        )}
                    </div>
                </div>
            )}

            <div className="absolute top-6 left-6 z-10 pointer-events-none flex flex-col gap-2">
                <div className="bg-black/60 px-4 py-2 rounded-xl border border-white/10 flex flex-col">
                    <span className="text-[10px] text-neutral-400 uppercase font-bold">Distance</span>
                    <span ref={hudDistanceRef} className="text-2xl font-mono font-bold text-white">0</span>
                </div>
                <div className="bg-black/60 px-4 py-2 rounded-xl border border-amber-500/20 flex gap-3 items-center">
                    <div className="w-6 h-6 rounded-full bg-amber-500 text-black flex items-center justify-center text-xs font-bold">$</div>
                    <span ref={hudCoinsRef} className="text-xl font-mono font-bold text-white">0</span>
                </div>
                <div className="w-48 h-1.5 bg-neutral-800 rounded-full mt-2 overflow-hidden border border-white/5">
                    <div ref={hudFuelBarRef} className="h-full bg-red-500 transition-all duration-200" style={{ width: '100%' }} />
                </div>
            </div>
            {notification && (
                <div className="absolute top-1/3 left-1/2 -translate-x-1/2 z-40 text-4xl font-black italic text-white animate-bounce drop-shadow-lg">{notification.text}</div>
            )}
            <div className="absolute bottom-10 left-10 right-10 z-30 flex justify-between">
                 <button 
                    className="w-24 h-24 rounded-full bg-black/40 border-2 border-white/10 active:bg-white/10 active:border-red-500/50 transition-all text-white font-black italic text-xl" 
                    onMouseDown={() => gameStateRef.current.keys.left = true} 
                    onMouseUp={() => gameStateRef.current.keys.left = false} 
                    onMouseLeave={() => gameStateRef.current.keys.left = false}
                    onTouchStart={(e) => { e.preventDefault(); gameStateRef.current.keys.left = true; }} 
                    onTouchEnd={(e) => { e.preventDefault(); gameStateRef.current.keys.left = false; }}
                >
                    BRAKE
                </button>
                 <button 
                    className="w-24 h-24 rounded-full bg-black/40 border-2 border-white/10 active:bg-white/10 active:border-emerald-500/50 transition-all text-white font-black italic text-xl" 
                    onMouseDown={() => gameStateRef.current.keys.right = true} 
                    onMouseUp={() => gameStateRef.current.keys.right = false} 
                    onMouseLeave={() => gameStateRef.current.keys.right = false}
                    onTouchStart={(e) => { e.preventDefault(); gameStateRef.current.keys.right = true; }} 
                    onTouchEnd={(e) => { e.preventDefault(); gameStateRef.current.keys.right = false; }}
                >
                    GAS
                </button>
            </div>
          </>
      )}
      <canvas ref={canvasRef} className="shadow-2xl" style={{ imageRendering: config.PIXELATED ? 'pixelated' : 'auto' }} />
    </div>
  );
};

export default Game;

